// hackers 단어 데이터 (PDF 추출본)
const VOCAB_HACKERS = [{"day":1,"title":"백수탈출 (채용)","words":[{"word":"résumé","pos":"n.","meaning":"이력서","example":"Fax your résumé and cover letter to the above number.","exampleKor":"위 번호로 이력서와 자기소개서를 팩스로 보내주세요."},{"word":"opening","pos":"n.","meaning":"공석, 결원; 개장, 개시","example":"There are several job openings at the restaurant right now.","exampleKor":"현재 그 식당에는 일자리가 몇 개 있다."},{"word":"applicant","pos":"n.","meaning":"지원자, 신청자","example":"Applicants are required to submit a résumé.","exampleKor":"지원자들은 이력서를 제출해야 한다."},{"word":"requirement","pos":"n.","meaning":"필요조건, 요건","example":"A driver's license is a requirement of this job.","exampleKor":"운전 면허증은 이 직업의 필요조건이다."},{"word":"meet","pos":"v.","meaning":"(필요·요구 등을) 만족시키다","example":"Applicants must meet all the requirements for the job.","exampleKor":"지원자들은 그 직책의 모든 필요조건을 만족시켜야 한다."},{"word":"qualified","pos":"adj.","meaning":"자격 있는, 적격의","example":"People with master's degrees are qualified for the research position.","exampleKor":"석사 학위를 갖춘 사람들은 연구직에 자격이 있다."},{"word":"candidate","pos":"n.","meaning":"후보자, 지원자","example":"Five candidates will be selected for final interviews.","exampleKor":"5명의 후보자가 최종 면접을 위해 선발될 것이다."},{"word":"confidence","pos":"n.","meaning":"확신, 자신; 신임","example":"We have confidence that she can handle the position.","exampleKor":"우리는 그녀가 그 직책을 수행할 수 있다고 확신한다."},{"word":"highly","pos":"adv.","meaning":"매우, 대단히","example":"Mr. Monroe's experience makes him highly qualified for the job.","exampleKor":"Mr. Monroe의 경험이 그를 그 직업에 매우 자격 있게 한다."},{"word":"professional","pos":"adj./n.","meaning":"전문적인, 직업의; 전문가","example":"Jeff is known as a professional photographer.","exampleKor":"Jeff는 전문 사진가로 알려져 있다."},{"word":"interview","pos":"n./v.","meaning":"면접; 면접을 보다","example":"The interviews are being held in meeting room three.","exampleKor":"면접은 3번 회의실에서 이루어지고 있다."},{"word":"hire","pos":"v.","meaning":"고용하다","example":"The company expects to hire several new employees next month.","exampleKor":"회사는 다음 달에 신입사원 몇 명을 고용할 계획이다."},{"word":"training","pos":"n.","meaning":"교육, 훈련","example":"This company offers on-the-job training for new staff.","exampleKor":"이 회사는 신입 사원들을 위한 현장 교육을 제공한다."},{"word":"reference","pos":"n.","meaning":"추천서; 참고","example":"Philip asked his previous employer to write a reference letter for him.","exampleKor":"Philip은 그의 이전 상사에게 추천서를 써 달라고 부탁했다."},{"word":"position","pos":"n./v.","meaning":"일자리, 직책; 두다","example":"The advertised position provides health care and other benefits.","exampleKor":"광고된 일자리는 의료 서비스와 다른 혜택들을 제공한다."},{"word":"achievement","pos":"n.","meaning":"성취, 달성","example":"List all of your achievements from previous jobs on your résumé.","exampleKor":"이전 직장에서 이룬 모든 성취 사항들을 이력서에 기록하시오."},{"word":"impressed","pos":"adj.","meaning":"인상 깊게 생각하는, 감명을 받은","example":"The CEO was impressed by his assistant's organizing skills.","exampleKor":"그 최고 경영자는 비서의 정리 능력을 인상 깊게 생각했다."},{"word":"excellent","pos":"adj.","meaning":"훌륭한, 탁월한","example":"Because of her excellent managerial skills, Erin was hired for the job.","exampleKor":"그녀의 훌륭한 관리 능력 때문에, Erin은 그 일자리에 채용되었다."},{"word":"eligible","pos":"adj.","meaning":"자격이 있는, 적격의","example":"The part-time workers are also eligible for paid holidays.","exampleKor":"시간제 근로자들도 유급 휴가를 받을 자격이 있다."},{"word":"identify","pos":"v.","meaning":"알아보다, 확인하다","example":"Staff members wear uniforms so that they are easy for customers to identify.","exampleKor":"직원들은 손님들이 쉽게 알아볼 수 있도록 제복을 입는다."},{"word":"associate","pos":"v.","meaning":"관련시키다","example":"Two of the applicants were associated with a competitor.","exampleKor":"지원자 중 두 명은 경쟁사와 관련되어 있었다."},{"word":"condition","pos":"n.","meaning":"조건","example":"The conditions of employment are listed in the job opening notice.","exampleKor":"고용 조건들은 채용 공고문에 열거되어 있다."},{"word":"employment","pos":"n.","meaning":"고용","example":"The company announced employment opportunities in personnel department.","exampleKor":"회사는 인사 부서에 고용 기회가 있음을 발표했다."},{"word":"lack","pos":"v./n.","meaning":"~이 없다; 부족","example":"Carl lacked the ability to get along well with his coworkers.","exampleKor":"Carl은 동료들과 잘 지내는 능력이 없다."},{"word":"managerial","pos":"adj.","meaning":"관리의","example":"Mike is seeking a managerial position in the accounting field.","exampleKor":"Mike는 회계 분야에서 관리직 자리를 찾고 있다."},{"word":"diligent","pos":"adj.","meaning":"성실한","example":"Carmen is one of the most diligent workers in the company.","exampleKor":"Carmen은 회사에서 가장 성실한 직원 중 한 명이다."},{"word":"familiar","pos":"adj.","meaning":"익숙한, 친숙한","example":"Staff must review the handbook to become familiar with it.","exampleKor":"직원들은 익숙해지도록 안내서를 복습해야 한다."},{"word":"proficiency","pos":"n.","meaning":"숙달, 능숙","example":"Overseas workers need proof of proficiency in a second language.","exampleKor":"해외 근로자들은 외국어 숙달에 관한 증거 자료가 필요하다."},{"word":"prospective","pos":"adj.","meaning":"장래의, 미래의","example":"Prospective employees were asked to come in for a second interview.","exampleKor":"장래의 직원들은 2차 면접을 보러 오라고 요청받았다."},{"word":"appeal","pos":"v.","meaning":"관심을 끌다, 매력적이다","example":"The 10 percent pay increase appealed to the staff.","exampleKor":"10퍼센트 임금 인상은 직원들의 관심을 끌었다."},{"word":"specialize","pos":"v.","meaning":"~을 전공하다, 전문적으로 다루다","example":"Most of the programmers specialized in software design in college.","exampleKor":"대부분의 프로그래머는 대학에서 소프트웨어 디자인을 전공했다."},{"word":"apprehensive","pos":"adj.","meaning":"걱정하는, 염려하는","example":"Many people feel apprehensive before an important job interview.","exampleKor":"많은 사람들은 중요한 면접 전에 걱정한다."},{"word":"consultant","pos":"n.","meaning":"고문, 컨설턴트","example":"Emma currently works in London as an interior design consultant.","exampleKor":"Emma는 현재 런던에서 인테리어 디자인 고문으로 일하고 있다."},{"word":"entitle","pos":"v.","meaning":"자격을 주다","example":"Executives are entitled to additional benefits.","exampleKor":"임원들에게는 추가 혜택에 대한 자격이 주어진다."},{"word":"degree","pos":"n.","meaning":"학위","example":"A bachelor's degree in engineering is a requirement for this position.","exampleKor":"공학 학사 학위는 이 직책의 필요조건이다."},{"word":"payroll","pos":"n.","meaning":"임금 대장, 급료 명부","example":"Fifteen new employees were added to the payroll last month.","exampleKor":"15명의 신입 사원이 지난달 임금 대장에 추가되었다."},{"word":"recruit","pos":"v.","meaning":"(신입 사원 등을) 모집하다","example":"The firm recruits promising graduates on a yearly basis.","exampleKor":"그 회사는 장래가 촉망되는 졸업자들을 매년 모집한다."},{"word":"certification","pos":"n.","meaning":"증명서, 증명","example":"Obtaining accounting certification takes approximately a year.","exampleKor":"회계 자격증을 취득하는 데는 대략 1년이 걸린다."},{"word":"occupation","pos":"n.","meaning":"직업","example":"Journalism is an interesting and challenging occupation.","exampleKor":"보도직은 흥미로우면서도 도전적인 직업이다."},{"word":"wage","pos":"n.","meaning":"임금, 급료","example":"Workers with formal education may earn higher wages than those without.","exampleKor":"정식 교육을 받은 근로자들은 그렇지 않은 사람들보다 더 높은 임금을 받을 수 있다."}]},{"day":2,"title":"드레스코드 (규칙·법률)","words":[{"word":"attire","pos":"n.","meaning":"복장, 옷차림새","example":"Professional business attire is required of all staff giving presentations.","exampleKor":"발표를 하는 모든 직원들은 정장을 입어야 한다."},{"word":"code","pos":"n.","meaning":"규범, 관례; 암호","example":"Employees are expected to follow the dress code.","exampleKor":"직원들은 복장 규범에 따르도록 요구된다."},{"word":"concern","pos":"n./v.","meaning":"우려, 걱정; 문제, 일; ~을 걱정스럽게 하다; 영향을 미치다, 관련되다","example":"The board voiced concerns about safety at the meeting.","exampleKor":"이사회는 회의에서 안전에 대한 우려를 표명했다."},{"word":"policy","pos":"n.","meaning":"규정; 보험 증권","example":"The employee benefit policy will be expanded next year.","exampleKor":"직원 복지 규정은 내년에 확대될 것이다."},{"word":"comply","pos":"v.","meaning":"준수하다, 따르다","example":"Employees must comply with the regulations governing computer use.","exampleKor":"직원들은 컴퓨터 사용 관리 규정을 준수해야 한다."},{"word":"regulation","pos":"n.","meaning":"규정","example":"Regulations regarding lunch breaks were established.","exampleKor":"점심시간에 관한 규정이 세워졌다."},{"word":"exception","pos":"n.","meaning":"예외","example":"Management decided not to make any exceptions to the rules.","exampleKor":"경영진은 규칙에 어떤 예외도 두지 않기로 결정했다."},{"word":"adhere","pos":"v.","meaning":"지키다, 고수하다","example":"All staff should do their best to adhere to the company's policies.","exampleKor":"모든 직원들은 회사 규정을 지키기 위해 최선을 다해야 한다."},{"word":"severely","pos":"adv.","meaning":"엄격하게, 심하게","example":"Those who share company data with outside parties will be severely punished.","exampleKor":"회사 자료를 외부인과 공유하는 사람은 엄격히 처벌될 것이다."},{"word":"refrain","pos":"v.","meaning":"자제하다, 삼가다","example":"Guards should refrain from making personal calls during a shift.","exampleKor":"경비 요원들은 근무 시간 동안 개인적인 전화를 하는 것을 자제해야 한다."},{"word":"permission","pos":"n.","meaning":"허락, 허가","example":"The CEO gave managers permission to hold a weekend workshop.","exampleKor":"최고 경영자는 관리자들에게 주말 워크숍을 열도록 허락했다."},{"word":"access","pos":"n./v.","meaning":"이용 권한, 접근; 통로; ~에 접근하다, 도달하다","example":"Only authorized personnel may gain access to client files.","exampleKor":"오직 허가된 직원만 고객 파일 이용 권한을 얻을 수 있다."},{"word":"thoroughly","pos":"adv.","meaning":"철저하게; 완전히, 대단히","example":"Please read the user manual thoroughly before installing this software.","exampleKor":"이 소프트웨어를 설치하기 전에 사용자 설명서를 철저히 읽어 보시기 바랍니다."},{"word":"revise","pos":"v.","meaning":"(의견·계획을) 수정하다, 변경하다","example":"The office's policies regarding vacations have been revised.","exampleKor":"휴가와 관련된 사무실 규정이 수정되었다."},{"word":"approach","pos":"n./v.","meaning":"접근법, 처리 방법; 다가오다, 가까워지다","example":"The manager has a strict approach to enforcing office regulations.","exampleKor":"그 관리자는 사무실 규정을 시행하는 엄격한 접근법을 갖고 있다."},{"word":"approval","pos":"n.","meaning":"승인, 인가","example":"Please obtain the supervisor's approval before purchasing supplies.","exampleKor":"비품을 구매하기 전에 관리자의 승인을 받으세요."},{"word":"form","pos":"n./v.","meaning":"종류, 유형, 양식; ~을 만들다, 형성하다","example":"Visitors are required to present a form of identification to security guards.","exampleKor":"방문객들은 신분증 한 가지를 경비원에게 제시해야 한다."},{"word":"immediately","pos":"adv.","meaning":"즉시, 곧","example":"Effective immediately, taxes will be automatically deducted from each paycheck.","exampleKor":"규정이 즉시 발효되어, 세금이 매 급여에서 자동 공제될 것입니다."},{"word":"inspection","pos":"n.","meaning":"점검, 검사","example":"The facility inspection should be conducted at least once a month.","exampleKor":"시설 점검은 적어도 한 달에 한 번 진행되어야 한다."},{"word":"arrangement","pos":"n.","meaning":"준비, 마련, 주선","example":"The manager made arrangements for purchase of new machinery.","exampleKor":"그 관리자는 새 장비 구입을 준비했다."},{"word":"procedure","pos":"n.","meaning":"절차","example":"The procedure for patent applications is outlined on the APTO Web site.","exampleKor":"특허 신청 절차는 APTO 웹사이트에 요약되어 있다."},{"word":"negative","pos":"adj.","meaning":"부정적인, 비관적인","example":"The new vacation policy received negative feedback from the employees.","exampleKor":"새로운 휴가 정책은 직원들로부터 부정적인 의견을 받았다."},{"word":"mandate","pos":"v./n.","meaning":"명령하다, 지시하다; 권한, 지시, 명령","example":"The board of directors has mandated an increase for research funding.","exampleKor":"이사회는 연구 자금 지원을 늘리라고 명령했다."},{"word":"effect","pos":"n./v.","meaning":"(법률 등의) 효력, 효과, 영향; 결과로서 ~을 가져오다","example":"The incentive policy will be in effect starting next week.","exampleKor":"상여금 규정은 다음 주부터 효력이 있을 것이다."},{"word":"drastically","pos":"adv.","meaning":"심하게, 과감하게, 철저하게","example":"Fines for breaking rules have been drastically increased.","exampleKor":"규칙 위반에 대한 벌금이 심하게 인상되었다."},{"word":"according to","pos":"phr.","meaning":"~에 따라","example":"All transactions must be handled according to the guidelines.","exampleKor":"모든 거래는 지침에 따라 처리되어야 한다."},{"word":"enable","pos":"v.","meaning":"(무엇을) 가능하게 하다","example":"Jenny's promotion enabled her to participate in the board meeting.","exampleKor":"Jenny의 승진은 그녀가 이사회 회의에 참석하는 것을 가능하게 했다."},{"word":"standard","pos":"n.","meaning":"기준, 표준","example":"The company must make changes to the current safety standards.","exampleKor":"그 회사는 현행 안전 기준을 변경해야 한다."},{"word":"constant","pos":"adj.","meaning":"지속적인, 끊임없이 계속하는","example":"The store received constant inquiries about its new return policy.","exampleKor":"그 상점은 새로운 반품 규정에 대해 지속적인 문의를 받았다."},{"word":"act","pos":"n./v.","meaning":"법령, 결의서; 행위, 행동; 결정하다, 판결을 내리다; 행동하다","example":"The new act makes it easier to file personal income tax forms online.","exampleKor":"새로운 법령은 온라인으로 개인 소득세 신고서를 제출하는 것을 더 쉽게 만든다."},{"word":"compensation","pos":"n.","meaning":"보상금, 보상","example":"Employees will receive compensation based on their performance and evaluation.","exampleKor":"직원들은 그들의 실적과 평가를 바탕으로 보상금을 받을 것이다."},{"word":"ban","pos":"n./v.","meaning":"금지; 금지하다","example":"The government placed a ban on carrying a large volume of liquid on board a plane.","exampleKor":"정부는 기내에 많은 양의 액체를 반입하는 것을 금지했다."},{"word":"obligation","pos":"n.","meaning":"의무, 책임","example":"All researchers have an obligation to publish at least one paper every year.","exampleKor":"모든 연구원들은 매년 적어도 한 편의 논문을 게재할 의무가 있다."},{"word":"authorize","pos":"v.","meaning":"~을 인가하다, 권한을 부여하다","example":"Allocations of funds must be authorized by management.","exampleKor":"자금 할당은 경영진에 의해 인가되어야 한다."},{"word":"prohibit","pos":"v.","meaning":"금지하다","example":"The museum prohibits visitors from taking pictures.","exampleKor":"그 박물관은 방문객들의 사진 촬영을 금지한다."},{"word":"abolish","pos":"v.","meaning":"(제도·법률 등을) 폐지하다","example":"Congress decided to abolish taxes on imported fruit.","exampleKor":"의회는 수입 과일에 대한 세금을 폐지하기로 결정했다."},{"word":"enforce","pos":"v.","meaning":"(법률을) 시행하다, 집행하다","example":"All departments must enforce the no smoking policy.","exampleKor":"모든 부서가 금연 규정을 시행해야 한다."},{"word":"habit","pos":"n.","meaning":"습관, 버릇","example":"Setting goals should be a regular habit.","exampleKor":"목표 설정은 규칙적인 습관이 되어야 한다."},{"word":"legislation","pos":"n.","meaning":"법률, 법규","example":"The committee unanimously voted for the new export limitation legislation.","exampleKor":"위원회는 새로운 수출 제한 법률에 만장일치로 찬성표를 던졌다."},{"word":"restrict","pos":"v.","meaning":"한정하다, 제한하다","example":"Access is restricted to authorized personnel.","exampleKor":"출입은 허가된 직원에게로 한정됩니다. (관계자 외 출입금지)"}]},{"day":3,"title":"사무의 달인 (일반사무 (1))","words":[{"word":"accustomed","pos":"adj.","meaning":"익숙한","example":"All our employees are accustomed to using the new design software.","exampleKor":"모든 직원들은 새로운 디자인 소프트웨어를 사용하는 데 익숙하다."},{"word":"corporation","pos":"n.","meaning":"주식회사, 법인","example":"Delroy Lee heads a multinational telecommunications corporation based in Virginia.","exampleKor":"Delroy Lee는 버지니아 주에 본사가 있는 다국적 통신회사를 이끈다."},{"word":"demanding","pos":"adj.","meaning":"요구가 많은, 힘든","example":"Although Ms. Jenkins is a demanding supervisor, she has a reputation for being fair.","exampleKor":"비록 Ms. Jenkins는 요구가 많은 감독관이지만, 공정하다는 평판을 갖고 있다."},{"word":"colleague","pos":"n.","meaning":"(직업상의) 동료","example":"Regular social activities can improve cooperation among colleagues.","exampleKor":"정기적인 사교 활동은 동료들 간의 협력을 증진할 수 있다."},{"word":"division","pos":"n.","meaning":"부서","example":"The technician will transfer to the automobile division after training.","exampleKor":"그 기술자는 훈련 후에 자동차 부서로 이동하게 될 것이다."},{"word":"request","pos":"n./v.","meaning":"요청; 요청하다","example":"Factory tours are available upon request.","exampleKor":"공장 견학은 요청 시에 가능합니다."},{"word":"efficiently","pos":"adv.","meaning":"효율적으로","example":"The software helps employees work more efficiently.","exampleKor":"그 소프트웨어는 직원들이 보다 효율적으로 일할 수 있게 도와준다."},{"word":"manage","pos":"v.","meaning":"~을 경영하다; 가까스로 하다","example":"The boss decided Colleen could manage the new store.","exampleKor":"상사는 Colleen이 새 상점을 경영할 수 있다고 판단했다."},{"word":"submit","pos":"v.","meaning":"제출하다","example":"Applicants should submit a résumé to the personnel manager.","exampleKor":"지원자들은 인사 담당자에게 이력서를 제출해야 한다."},{"word":"directly","pos":"adv.","meaning":"곧바로","example":"All regional branches report directly to the head office in Washington.","exampleKor":"모든 지부들은 워싱턴에 있는 본사에 곧바로 보고한다."},{"word":"remind","pos":"v.","meaning":"~에게 상기시키다, 일깨우다","example":"Ms. Williams reminded Mr. Johnson of his lunch meeting.","exampleKor":"Ms. Williams는 Mr. Johnson에게 그의 점심 회의를 상기시켰다."},{"word":"instruct","pos":"v.","meaning":"지시하다, 가르치다","example":"The manager instructed the staff to read the conference materials beforehand.","exampleKor":"팀장은 직원들에게 회의 자료를 미리 읽으라고 지시했다."},{"word":"deadline","pos":"n.","meaning":"마감일, 마감 시간","example":"The team worked together closely and finished the project ahead of the deadline.","exampleKor":"그 팀은 긴밀하게 협력해서 마감일 전에 프로젝트를 끝냈다."},{"word":"sample","pos":"n./v.","meaning":"견본, 샘플, 표본; 시식하다, (견본으로 질을) 시험하다","example":"We need to prepare samples of our products for the fair.","exampleKor":"박람회를 위해 우리 제품의 견본을 준비할 필요가 있다."},{"word":"notify","pos":"v.","meaning":"~에게 통지하다, 알리다","example":"All staff applying for leave must notify their supervisors in writing.","exampleKor":"휴가를 신청하는 모든 직원들은 상관에게 서면으로 통지해야 한다."},{"word":"perform","pos":"v.","meaning":"(일·과제·의무 등을) 행하다, 실행하다","example":"All work on the assembly line stopped while equipment repairs were being performed.","exampleKor":"장비 수리가 실행되는 동안 조립 라인의 모든 작업이 중단되었다."},{"word":"monitor","pos":"v./n.","meaning":"감독하다, 감시하다, 검토하다; 화면, 모니터","example":"The new director will monitor progress on the project.","exampleKor":"신임 이사는 그 프로젝트의 진행을 감독할 것이다."},{"word":"deserve","pos":"v.","meaning":"~할 만하다, ~할 가치가 있다","example":"The person with the highest performance evaluation deserves the Employee of the Year Award.","exampleKor":"가장 높은 업무 수행 평가를 받은 사람이 올해의 직원상을 받을 만하다."},{"word":"assignment","pos":"n.","meaning":"일, 임무, 과제","example":"Walter took the assignment in India because he was promised a promotion there.","exampleKor":"Walter는 그곳에서의 승진을 약속받았기 때문에 인도에서의 일을 맡았다."},{"word":"entire","pos":"adj.","meaning":"전체의","example":"The entire team gathers every Monday morning to discuss plans for the week.","exampleKor":"팀 전체는 그 주의 계획을 논의하기 위해 매주 월요일 아침에 모인다."},{"word":"release","pos":"v./n.","meaning":"발표하다, 공개하다; 출시, 발매","example":"The company released its annual report.","exampleKor":"그 회사는 자사의 연간 보고서를 발표했다."},{"word":"extension","pos":"n.","meaning":"연장, 연기; (전화의) 내선","example":"The manager granted an extension of the deadline.","exampleKor":"그 관리자는 마감일 연기를 허락했다."},{"word":"electronically","pos":"adv.","meaning":"컴퓨터 통신망으로, 컴퓨터로","example":"It saves time and resources to send invoices electronically.","exampleKor":"송장을 컴퓨터 통신망으로 전송하는 것은 시간과 자원을 절약해 준다."},{"word":"attendance","pos":"n.","meaning":"출근, 출석","example":"Attendance records are taken into consideration when determining eligibility for promotion.","exampleKor":"출근 기록은 승진 자격을 결정할 때 고려된다."},{"word":"absolutely","pos":"adv.","meaning":"절대적으로, 완전히","example":"It is absolutely necessary that everyone on the board is in agreement with the plan.","exampleKor":"이사회의 모든 사람들이 그 계획에 동의하는 것이 절대적으로 필요하다."},{"word":"delegate","pos":"v./n.","meaning":"(권한 등을) 위임하다; 대표","example":"Managers must be skilled in delegating responsibilities to subordinates.","exampleKor":"관리자들은 부하 직원에게 업무를 위임하는 데 있어 노력해야 한다."},{"word":"attentively","pos":"adv.","meaning":"주의 깊게, 조심스럽게","example":"Stockholders listened attentively as executives explained the company strategy.","exampleKor":"주주들은 임원들이 회사 전략을 설명할 때 주의 깊게 경청했다."},{"word":"supervision","pos":"n.","meaning":"감독","example":"Close supervision ensures high quality.","exampleKor":"철저한 감독은 높은 품질을 보장한다."},{"word":"workshop","pos":"n.","meaning":"워크숍, 연수","example":"Mr. Kim was asked to speak at the workshop on Friday.","exampleKor":"Mr. Kim은 금요일 워크숍에서 강연해 달라는 요청을 받았다."},{"word":"draw","pos":"v.","meaning":"끌다, 끌어당기다","example":"The company's annual conference usually draws 800 employees from around the world.","exampleKor":"그 회사의 연례 총회는 보통 전 세계로부터 800명의 직원들을 끌어들인다."},{"word":"revision","pos":"n.","meaning":"수정, 개정","example":"The team manager will make revisions to the proposal.","exampleKor":"팀장이 계획안을 수정할 것이다."},{"word":"reluctantly","pos":"adv.","meaning":"마지못해, 꺼려하여","example":"Ms. Danvers reluctantly agreed to cut the advertising budget.","exampleKor":"Ms. Danvers는 광고 예산을 삭감하는 데 마지못해 동의했다."},{"word":"acquaint","pos":"v.","meaning":"~에게 숙지시키다, 잘 알게 하다","example":"The training program acquaints new employees with company procedures.","exampleKor":"그 교육 프로그램은 신입 사원들에게 회사 절차를 숙지시킨다."},{"word":"convey","pos":"v.","meaning":"(용건을) 전달하다","example":"The secretary urgently conveyed the message to the director.","exampleKor":"그 비서는 메시지를 이사에게 급히 전달했다."},{"word":"check","pos":"v./n.","meaning":"검사하다, 조사하다; 확인하다; 검사","example":"Please check your computer regularly for disk errors.","exampleKor":"디스크 오류 여부를 확인하기 위해 컴퓨터를 정기적으로 검사하십시오."},{"word":"headquarters","pos":"n.","meaning":"본부","example":"The company headquarters is located in London.","exampleKor":"회사 본부는 런던에 위치해 있다."},{"word":"file","pos":"v./n.","meaning":"(서류를) 정리하다, 철하다; (서류·신청·고소 등을) 정식으로 제기하다, 제출하다; 서류","example":"Old accounting documents are filed in the storage room.","exampleKor":"오래된 회계 서류는 창고에 정리되어 있다."},{"word":"oversee","pos":"v.","meaning":"감독하다","example":"Natalie will oversee the office relocation process.","exampleKor":"Natalie가 사무실 이전 과정을 감독할 것이다."},{"word":"involved","pos":"adj.","meaning":"관여하는, 관계된, 연루된","example":"Dr. Mair was deeply involved in the decision-making process.","exampleKor":"Dr. Mair가 의사 결정 과정에 깊이 관여했다."},{"word":"concentrate","pos":"v.","meaning":"집중하다, 집중시키다","example":"The sales team concentrated on developing new strategies.","exampleKor":"영업팀은 새로운 전략을 개발하는 데 집중했다."}]},{"day":4,"title":"업무 노하우 (일반사무 (2))","words":[{"word":"lax","pos":"adj.","meaning":"(행동 등이) 느슨한, 규율에 못 미치는","example":"As of late, the staff has been rather lax in turning in reports.","exampleKor":"최근에 직원들은 보고서를 제출하는 데 다소 느슨했다."},{"word":"procrastinate","pos":"v.","meaning":"미루다, 꾸물거리다","example":"Mr. Jones procrastinated with his fund request and missed the deadline.","exampleKor":"Mr. Jones는 자금 신청을 미루다가 마감일을 지키지 못했다."},{"word":"combined","pos":"adj.","meaning":"결합된, 합동의","example":"Retail Specialists employs professionals with a combined experience of 30 years in sales.","exampleKor":"Retail Specialists사는 영업 분야에서 종합 30년의 경력을 가진 전문가들을 고용한다."},{"word":"accomplish","pos":"v.","meaning":"성취하다","example":"Careful planning is essential for accomplishing goals.","exampleKor":"세심한 계획은 목표를 성취하는 데 필수적이다."},{"word":"voluntarily","pos":"adv.","meaning":"자발적으로","example":"He voluntarily took on the challenging assignment in order to gain experience.","exampleKor":"그는 경험을 쌓기 위해 힘든 업무를 자발적으로 맡았다."},{"word":"undertake","pos":"v.","meaning":"(일을) 떠맡다","example":"She had to undertake the task on short notice.","exampleKor":"그녀는 갑자기 업무를 떠맡아야만 했다."},{"word":"assume","pos":"v.","meaning":"(증거는 없으나) 사실이라고 생각하다; (책임·역할을) 맡다","example":"The management assumes employees are satisfied.","exampleKor":"경영진은 직원들이 만족하고 있다고 생각한다."},{"word":"occasionally","pos":"adv.","meaning":"가끔, 때때로","example":"Staff should occasionally take time to relax so they do not get tired.","exampleKor":"직원들은 지치지 않기 위해 가끔 휴식을 취하는 시간을 가져야 한다."},{"word":"employee","pos":"n.","meaning":"직원, 고용인","example":"There are only three employees working under Ms. Anderson.","exampleKor":"Ms. Anderson 밑에서 일하는 직원은 단 세 명뿐이다."},{"word":"assist","pos":"v.","meaning":"돕다, 조력하다","example":"A staff member assisted with preparations for the conference.","exampleKor":"한 직원이 회담 준비를 도왔다."},{"word":"satisfied","pos":"adj.","meaning":"만족하는, 만족스러워하는","example":"Not everyone was satisfied with changes to the overtime policy.","exampleKor":"초과 근무 정책 변경에 대해 모두가 만족하지는 않았다."},{"word":"manner","pos":"n.","meaning":"방식; 태도","example":"Sean was annoyed by the manner in which his boss gave him orders.","exampleKor":"Sean은 상사가 그에게 지시하는 방식에 불쾌해졌다."},{"word":"responsible","pos":"adj.","meaning":"책임이 있는, 책임져야 할","example":"Businesses are responsible for ensuring customer satisfaction.","exampleKor":"기업들은 고객 만족을 보장할 책임이 있다."},{"word":"conduct","pos":"v./n.","meaning":"(업무 등을) 수행하다; (업무의) 수행","example":"IJMR Ltd.'s technology department will conduct the research study.","exampleKor":"IJMR사의 기술 부서가 조사 연구를 할 것이다."},{"word":"adjust","pos":"v.","meaning":"적응하다","example":"The employees quickly adjusted to the new e-mail system.","exampleKor":"직원들은 새로운 이메일 시스템에 빠르게 적응했다."},{"word":"personnel","pos":"n.","meaning":"(집합적) 직원, 인원; 인사과","example":"We often use an agency to find reliable temporary personnel.","exampleKor":"우리는 믿을 만한 임시 직원을 구하기 위해 중개소를 자주 이용한다."},{"word":"agree","pos":"v.","meaning":"동의하다","example":"The team agreed on the recommendations of the advisor.","exampleKor":"그 팀은 고문의 권고에 동의했다."},{"word":"supervise","pos":"v.","meaning":"감독하다, 지도하다","example":"Ms. Wilson supervises the employees in sector B.","exampleKor":"Ms. Wilson은 B구역의 직원들을 감독한다."},{"word":"coworker","pos":"n.","meaning":"동료, 협력자","example":"Coworkers who live near each other often travel to work together.","exampleKor":"서로 가까이에 사는 동료들은 종종 함께 출근한다."},{"word":"direct","pos":"v.","meaning":"~에게 길을 안내하다, 가르쳐 주다","example":"The receptionist directs new employees to the auditorium where orientation will be held.","exampleKor":"접수원은 신입 직원들을 오리엔테이션이 열릴 강당으로 안내한다."},{"word":"confidential","pos":"adj.","meaning":"기밀의, 내밀한","example":"Internal documents must be kept confidential.","exampleKor":"내부 문서는 기밀로 유지되어야 한다."},{"word":"assign","pos":"v.","meaning":"배정하다, 할당하다","example":"The office manager assigned desks to the new recruits.","exampleKor":"사무실 관리자가 신입 사원들에게 책상을 배정해 주었다."},{"word":"leading","pos":"adj./n.","meaning":"선도적인, 일류의, 가장 중요한, 선두적인; 지도, 통솔","example":"Shepherd Inc. is a leading exporter in the wood furniture industry.","exampleKor":"Shepherd사는 목재 가구 업계의 선도적인 수출업체이다."},{"word":"formal","pos":"adj.","meaning":"격식을 갖춘","example":"The awards ceremony requires wearing formal business attire.","exampleKor":"시상식은 격식을 갖춘 정장을 착용하는 것을 요구한다."},{"word":"remove","pos":"v.","meaning":"해임하다, 제거하다","example":"The vice president was removed from his position because of a scandal.","exampleKor":"그 부사장은 스캔들 때문에 직위에서 해임되었다."},{"word":"collect","pos":"v.","meaning":"모으다, 수집하다","example":"The author collected management ideas from around the world for his book.","exampleKor":"그 작가는 그의 책을 위해 전 세계에서 경영 지식을 모았다."},{"word":"coordinate","pos":"v.","meaning":"조정하다","example":"The Chicago office coordinated the planning process.","exampleKor":"시카고 지사가 기획 과정을 조정했다."},{"word":"hardly","pos":"adv.","meaning":"거의 ~하지 않다","example":"She was hardly ever late for her shift.","exampleKor":"그녀는 좀처럼 교대 근무 시간에 늦지 않았다."},{"word":"abstract","pos":"adj.","meaning":"추상적인; 막연한","example":"Copland spent thousands of dollars on an abstract painting for the lobby.","exampleKor":"Copland사는 로비에 걸 추상화에 수천 달러를 썼다."},{"word":"directory","pos":"n.","meaning":"주소록","example":"The company directory shows where the marketing department is.","exampleKor":"회사 주소록은 마케팅 부서가 어디에 있는지 알려 준다."},{"word":"accountable","pos":"adj.","meaning":"책임이 있는","example":"All employees are accountable for the duties they have been assigned to complete.","exampleKor":"모든 직원들은 완료하도록 배정된 임무에 대한 책임이 있다."},{"word":"skillfully","pos":"adv.","meaning":"능숙하게, 솜씨 있게","example":"Brenda skillfully edited the report to fit on one page.","exampleKor":"Brenda는 보고서가 한 페이지에 들어갈 수 있도록 능숙하게 편집했다."},{"word":"exclusive","pos":"adj.","meaning":"독점적인; 배타적인","example":"Delegates with special passes have exclusive access to a tour of the facilities.","exampleKor":"특별 통행증을 가진 대표들은 시설 견학에 참가할 독점적인 권리를 갖는다."},{"word":"intention","pos":"n.","meaning":"의지, 의향","example":"She had every intention of attending the conference, but could not.","exampleKor":"그녀는 회의에 꼭 참석하려고 했지만, 그렇게 하지 못했다."},{"word":"transform","pos":"v.","meaning":"바꾸다, 변모시키다","example":"Computerization has transformed the way companies do business.","exampleKor":"전산화는 기업들이 사업하는 방식을 바꿨다."},{"word":"respectful","pos":"adj.","meaning":"정중한, 존중하는","example":"Sales clerks are reminded to be respectful to all clients.","exampleKor":"판매 사원들은 모든 고객에게 정중해야 함을 상기하기 바랍니다."},{"word":"duplicate","pos":"n.","meaning":"사본","example":"A duplicate of each contract is kept in the company records.","exampleKor":"각 계약서의 사본 한 부가 회사 문서로 보관될 것이다."},{"word":"contrary","pos":"n.","meaning":"반대","example":"Techworld is in financial trouble, despite claims to the contrary.","exampleKor":"Techworld사는 그렇지 않다는 주장에도 불구하고 재정난에 처해 있다."},{"word":"disturbing","pos":"adj.","meaning":"충격적인, 불안감을 주는, 방해하는","example":"Shareholders found reports of the CEO's incompetence disturbing.","exampleKor":"주주들은 그 최고 경영자의 무능함에 대한 보도가 충격적이라고 생각했다."},{"word":"engage","pos":"v.","meaning":"관여하다, 종사하다","example":"Each worker was engaged in at least two projects.","exampleKor":"각 직원이 최소 두 프로젝트에 관여했다."},{"word":"foster","pos":"v.","meaning":"촉진하다, 육성하다","example":"Staff dinners helped foster better work relations.","exampleKor":"직원 저녁 식사 모임은 보다 나은 업무 관계를 촉진하는 데 도움이 되었다."},{"word":"neutrality","pos":"n.","meaning":"중립성, 중립","example":"Managers must display complete neutrality in disagreements between employees.","exampleKor":"관리자들은 직원들 사이의 다툼에서 완벽한 중립성을 보여야 한다."},{"word":"widely","pos":"adv.","meaning":"널리","example":"Ben Hurley is a widely admired business leader.","exampleKor":"Ben Hurley는 널리 존경받는 재계 리더이다."},{"word":"externally","pos":"adv.","meaning":"외부에서, 외부적으로","example":"Most of the company's marketing is handled externally through contractors.","exampleKor":"대부분의 회사 마케팅은 도급업자들을 통해 외부에서 처리된다."}]},{"day":5,"title":"비밀병기 (일반사무 (3))","words":[{"word":"sophisticated","pos":"adj.","meaning":"(기계가) 정교한, 복잡한; 세련된","example":"A sophisticated surveillance system was installed.","exampleKor":"정교한 보안 시스템이 설치되었다."},{"word":"timely","pos":"adj.","meaning":"시기적절한, 때를 맞춘","example":"The report was completed in a timely manner.","exampleKor":"그 보고서는 때맞춰 완성되었다."},{"word":"realistically","pos":"adv.","meaning":"현실적으로","example":"We cannot realistically expect to have the presentation ready on time.","exampleKor":"현실적으로 발표가 제때 준비되는 것을 기대하기 어렵다."},{"word":"promptly","pos":"adv.","meaning":"즉시; 정각에","example":"It is company policy to respond promptly to all inquiries.","exampleKor":"모든 문의에 즉시 답변하는 것이 회사의 방침이다."},{"word":"accessible","pos":"adj.","meaning":"출입할 수 있는; 이용할 수 있는","example":"The 18th floor is only accessible to executive staff.","exampleKor":"18층은 오직 경영진만 출입할 수 있습니다."},{"word":"implement","pos":"v.","meaning":"실시하다, 실행하다","example":"Board members voted to implement an innovative marketing campaign.","exampleKor":"이사회 위원들은 혁신적인 마케팅 캠페인을 실시하기로 표결했다."},{"word":"feedback","pos":"n.","meaning":"의견, 반응","example":"Feedback from colleagues can be of great assistance.","exampleKor":"동료들의 의견은 큰 도움이 될 수 있다."},{"word":"outstanding","pos":"adj.","meaning":"우수한; (부채 등이) 미지불된","example":"The director presented an outstanding business plan.","exampleKor":"그 이사는 우수한 사업 계획을 발표했다."},{"word":"inform","pos":"v.","meaning":"~에게 알리다","example":"Please inform the director that the meeting has been canceled.","exampleKor":"이사님께 회의가 취소되었다고 알려 주세요."},{"word":"replacement","pos":"n.","meaning":"교체; 후임자","example":"We need a replacement for this broken laptop.","exampleKor":"이 고장 난 노트북 컴퓨터의 교체가 필요하다."},{"word":"announcement","pos":"n.","meaning":"공고, 발표","example":"Mr. Dane posted an announcement about the general meeting.","exampleKor":"Mr. Dane은 총회에 대한 공고를 게시했다."},{"word":"department","pos":"n.","meaning":"(조직·기구의) 부서","example":"Report payroll problems to the finance department.","exampleKor":"급여 문제는 재무 부서에 신고하십시오."},{"word":"permanently","pos":"adv.","meaning":"영구적으로, 불변으로","example":"The computer files have been permanently deleted and cannot be retrieved.","exampleKor":"그 컴퓨터 파일들은 영구적으로 삭제되었고 복구될 수 없다."},{"word":"fulfill","pos":"v.","meaning":"(조건을) 만족시키다, (약속·의무 등을) 지키다, 이행하다","example":"The final product design fulfilled the terms of the contract.","exampleKor":"최종 제품 디자인은 계약 조건들을 만족시켰다."},{"word":"outline","pos":"n./v.","meaning":"개요; 설명하다, 약술하다","example":"Begin making the report by arranging the main ideas in an outline.","exampleKor":"주요 방안들을 개요로 정리함으로써 보고서 작성을 시작하십시오."},{"word":"explain","pos":"v.","meaning":"설명하다","example":"The manager explained the new regulations to everyone in the department.","exampleKor":"그 부장은 부서의 모든 사람들에게 새로운 규정을 설명했다."},{"word":"contain","pos":"v.","meaning":"포함하다","example":"The filing cabinet contains copies of all our invoices.","exampleKor":"그 서류 정리 캐비닛은 모든 송장의 사본을 포함한다."},{"word":"compile","pos":"v.","meaning":"(자료 등을) 편집하다; 모으다","example":"The assistant compiled a list of tablet computer manufacturers.","exampleKor":"그 비서는 태블릿 컴퓨터 제조사 목록을 편집했다."},{"word":"subsequent","pos":"adj.","meaning":"차후의, 그 다음의","example":"Some employees received separation pay subsequent to the company's closing.","exampleKor":"몇몇 직원들은 회사의 폐업 이후에 퇴직 수당을 받았다."},{"word":"overview","pos":"n.","meaning":"개요, 개관","example":"Scott gave an overview of the topic before the presentation.","exampleKor":"Scott은 발표 전에 주제의 개요를 설명했다."},{"word":"provider","pos":"n.","meaning":"공급자, 제공자","example":"There are numerous Internet and cable providers in the city.","exampleKor":"도시에는 수많은 인터넷과 케이블 방송 공급업체가 있다."},{"word":"matter","pos":"n.","meaning":"문제, 일","example":"Please deal with personal matters outside the office.","exampleKor":"개인적인 문제는 사무실 밖에서 처리하시기 바랍니다."},{"word":"expertise","pos":"n.","meaning":"전문 지식, 전문 기술","example":"This kind of project falls outside the firm's area of expertise.","exampleKor":"이런 종류의 프로젝트는 회사의 전문 분야 밖에 해당한다."},{"word":"demonstrate","pos":"v.","meaning":"증명하다; (모형·실험 등으로) 설명하다","example":"Sales figures demonstrate that the advertising campaign was successful.","exampleKor":"매출 수치는 광고 캠페인이 성공적이었음을 증명한다."},{"word":"remainder","pos":"n.","meaning":"나머지","example":"Audits will continue throughout the remainder of the month.","exampleKor":"이달의 나머지 기간 내내 회계 감사가 계속될 것이다."},{"word":"essential","pos":"adj.","meaning":"필수적인, 극히 중요한, 본질적인","example":"Perseverance is essential to success in business.","exampleKor":"인내는 사업의 성공에 있어 필수적이다."},{"word":"divide","pos":"v.","meaning":"분배하다, 나누다","example":"Required overtime will be divided equally among employees.","exampleKor":"필요한 초과 근무 시간은 직원들 간에 공평하게 분배될 것이다."},{"word":"major","pos":"adj.","meaning":"주요한, 중대한","example":"A major figure in publishing, Ms. Yarrow is highly influential.","exampleKor":"출판업계의 주요 인사인 Ms. Yarrow는 매우 영향력이 크다."},{"word":"compliance","pos":"n.","meaning":"(명령·법규에의) 준수","example":"Government officials will inspect the plant's compliance with safety guidelines.","exampleKor":"정부 관리들이 공장의 안전 규정 준수 여부를 검사할 것이다."},{"word":"clarify","pos":"v.","meaning":"명확하게 하다","example":"The notice clarified some details of the vacation policy modifications.","exampleKor":"그 공고는 휴가 정책 변경의 일부 세부 사항을 명확하게 했다."},{"word":"face","pos":"v.","meaning":"(문제 등에) 직면하다; 향하다, 마주보다","example":"Businesses are faced with the challenge of foreign competition.","exampleKor":"기업들은 외국 경쟁사들의 도전에 직면해 있다."},{"word":"follow","pos":"v.","meaning":"~을 따라가다; 주시하다; (분명히) 이해하다","example":"The guests followed the guide into the exhibition hall.","exampleKor":"방문객들은 안내원을 따라 전시회장으로 들어갔다."},{"word":"aspect","pos":"n.","meaning":"관점, 국면","example":"Every aspect of the problem must be taken into consideration.","exampleKor":"그 문제의 모든 관점이 고려되어야 한다."},{"word":"apparently","pos":"adv.","meaning":"보기에 ~한 듯한, 외관상으로는","example":"Apparently, Mr. Jones was not invited to this meeting.","exampleKor":"Mr. Jones는 이 회의에 초대받지 못한 듯하다."},{"word":"aware","pos":"adj.","meaning":"알고 있는, 인식하고 있는","example":"Workers should be made aware of safety procedures.","exampleKor":"근로자들이 안전 절차를 알고 있게 해야 한다."},{"word":"extended","pos":"adj.","meaning":"(기간 등을) 연장한, 장기간에 걸친","example":"The accounting department works extended hours on the first week of every month.","exampleKor":"회계 부서는 매달 첫 주에 연장 근무한다."},{"word":"accidentally","pos":"adv.","meaning":"뜻하지 않게, 우연히","example":"Alison accidentally made some errors in the financial statements.","exampleKor":"Alison은 재무제표 작성 시 뜻하지 않게 실수를 범했다."},{"word":"advisable","pos":"adj.","meaning":"바람직한, 합당한","example":"It is advisable to update computer equipment regularly.","exampleKor":"컴퓨터 장비를 정기적으로 업데이트하는 것이 바람직하다."},{"word":"concerned","pos":"adj.","meaning":"염려하는, 걱정하는; 관련된","example":"Management is concerned about security.","exampleKor":"경영진은 보안에 대해 염려하고 있다."},{"word":"speak","pos":"v.","meaning":"이야기하다","example":"Mr. Brooke spoke to his clients about a new venture.","exampleKor":"Mr. Brooke은 자신의 고객들에게 신규 사업에 관해 이야기했다."}]},{"day":6,"title":"쉴 휴(休) (여가·공동체)","words":[{"word":"rest","pos":"v./n.","meaning":"쉬다, 휴식을 취하다; 휴식, 나머지","example":"Hikers can rest on the bench halfway up the hill.","exampleKor":"도보 여행자들은 언덕 중턱의 벤치에서 쉴 수 있다."},{"word":"exhibition","pos":"n.","meaning":"전시회","example":"The gallery hosted an exhibition of urban scenic photographs.","exampleKor":"그 화랑은 도시 풍경 사진 전시회를 주최했다."},{"word":"celebrity","pos":"n.","meaning":"유명 인사, 명사","example":"Many celebrities attended the city's summer park festival.","exampleKor":"많은 유명 인사들이 그 도시의 여름 공원 축제에 참석했다."},{"word":"live","pos":"adj.","meaning":"(라디오·TV가) 생방송인","example":"Finnegan's café hosts a live music performance every Saturday.","exampleKor":"Finnegan's 카페는 매주 토요일마다 라이브 음악 공연을 주최한다."},{"word":"improvise","pos":"v.","meaning":"(연주·연설 등을) 즉흥적으로 하다, 즉석에서 만들다","example":"The performers improvised a jazz melody.","exampleKor":"연주자들은 재즈 멜로디를 즉흥적으로 연주했다."},{"word":"popular","pos":"adj.","meaning":"인기 있는","example":"Broadway musicals are so popular that they frequently go on tour.","exampleKor":"브로드웨이 뮤지컬은 정말 인기가 많아서 순회공연을 자주 떠난다."},{"word":"donation","pos":"n.","meaning":"기증, 기부","example":"The library is accepting donations of children's books.","exampleKor":"도서관에서는 아동 도서를 기증받고 있습니다."},{"word":"alumni","pos":"n.","meaning":"동창생들, 졸업생들","example":"St. John's University alumni were invited to the graduation ceremony.","exampleKor":"St. John's 대학교 동창생들이 졸업식에 초대되었다."},{"word":"present","pos":"v./adj.","meaning":"제시하다; 현재의, 참석한","example":"Please present valid tickets at the door.","exampleKor":"유효한 표를 입구에서 제시해 주십시오."},{"word":"admission","pos":"n.","meaning":"입장","example":"Those wishing to visit the exhibit will be charged an extra admission fee.","exampleKor":"전시회 관람을 원하는 분들에게는 추가 입장료가 부과될 것입니다."},{"word":"banquet","pos":"n.","meaning":"연회, 만찬","example":"The hotel has facilities for large-scale wedding banquets.","exampleKor":"그 호텔은 대규모 피로연을 위한 시설을 가지고 있다."},{"word":"anniversary","pos":"n.","meaning":"기념일","example":"The couple celebrated their 50th anniversary with a party.","exampleKor":"그 부부는 그들의 50번째 기념일을 파티로 축하했다."},{"word":"required","pos":"adj.","meaning":"필수의, 의무적인","example":"Proper swimming attire is required when using the hotel pool.","exampleKor":"호텔 수영장을 이용할 시에는 적절한 수영 복장이 필수다."},{"word":"succeed","pos":"v.","meaning":"성공하다; 뒤를 잇다","example":"Peggy succeeded in convincing her family to visit Hawaii.","exampleKor":"Peggy는 그녀의 가족이 하와이를 방문하도록 설득하는 데 성공했다."},{"word":"collection","pos":"n.","meaning":"소장품, 수집물; 징수, 수금","example":"The museum has a unique collection of stamps.","exampleKor":"그 박물관은 독특한 우표 소장품을 보유하고 있다."},{"word":"fund-raising","pos":"n.","meaning":"모금","example":"Auctions are a popular form of fund-raising.","exampleKor":"경매는 모금의 인기 있는 형태이다."},{"word":"resume","pos":"v.","meaning":"재개하다, 다시 시작하다","example":"The play will resume after a short intermission.","exampleKor":"그 연극은 짧은 휴식 시간 후에 재개할 것이다."},{"word":"issue","pos":"n.","meaning":"(출판물의) 제 ~호; 문제, 쟁점","example":"Jack's cake recipe was in the April issue of Baker Monthly.","exampleKor":"Baker Monthly지의 4월호에 Jack의 케이크 조리법이 실렸다."},{"word":"subscription","pos":"n.","meaning":"(정기 발행물의) 구독","example":"I would like to get a subscription to the Weekly Herald.","exampleKor":"Weekly Herald지를 구독하고 싶습니다."},{"word":"appear","pos":"v.","meaning":"나타나다, 출현하다","example":"The novelist appeared at the bookstore to sign autographs.","exampleKor":"그 소설가는 사인회를 하기 위해 서점에 나타났다."},{"word":"accompany","pos":"v.","meaning":"동행하다; 동반하다","example":"Mary accompanied her grandmother to the mall.","exampleKor":"Mary는 쇼핑몰까지 그녀의 할머니와 동행했다."},{"word":"edition","pos":"n.","meaning":"(간행물의) 판","example":"A revised edition of the economics book will be published soon.","exampleKor":"그 경제학 서적의 개정판이 곧 출간될 것이다."},{"word":"specifically","pos":"adv.","meaning":"명확하게, 분명히; 특히, 특별히","example":"The package terms specifically stated that guests would stay at a hotel.","exampleKor":"그 패키지 여행 조건은 손님들이 호텔에 머물 것임을 명확하게 언급했다."},{"word":"anonymous","pos":"adj.","meaning":"익명의, 이름을 모르는","example":"The charity received $6,000 from an anonymous donor.","exampleKor":"그 자선 단체는 익명의 기부자로부터 6천 달러를 받았다."},{"word":"commit","pos":"v.","meaning":"헌신하다, 전념하다","example":"The store is committed to providing excellent customer service.","exampleKor":"그 가게는 훌륭한 고객 서비스를 제공하는 데 헌신한다."},{"word":"informative","pos":"adj.","meaning":"유익한, 정보를 주는","example":"The documentary was informative and interesting.","exampleKor":"그 다큐멘터리는 유익하고도 흥미로웠다."},{"word":"audience","pos":"n.","meaning":"청중, 관중","example":"The audience applauded the singer enthusiastically.","exampleKor":"청중은 그 가수에게 열광적으로 갈채를 보냈다."},{"word":"author","pos":"n.","meaning":"작가, 저자","example":"All of the author's short stories are popular.","exampleKor":"그 작가의 모든 단편 소설들은 인기가 있다."},{"word":"note","pos":"v./n.","meaning":"주목하다; 특별히 언급하다; 메모","example":"Please note the intricate details of the architecture.","exampleKor":"그 건축물의 복잡한 세부 양식에 주목해 주십시오."},{"word":"antique","pos":"n.","meaning":"골동품","example":"Antiques are popular for home decor.","exampleKor":"골동품은 실내 장식용품으로 인기 있다."},{"word":"manuscript","pos":"n.","meaning":"원고","example":"The author is working on several manuscripts.","exampleKor":"그 작가는 몇 편의 원고를 작업 중이다."},{"word":"beneficial","pos":"adj.","meaning":"유익한, 이로운","example":"The organization's work is beneficial to the community.","exampleKor":"그 단체의 활동은 지역 사회에 이익이 된다."},{"word":"upcoming","pos":"adj.","meaning":"곧 있을, 다가오는","example":"A reporter spoke to a candidate for the upcoming election.","exampleKor":"리포터는 곧 있을 선거의 한 후보자에게 말을 걸었다."},{"word":"lend","pos":"v.","meaning":"빌려주다","example":"The library lends a variety of audio-visual materials.","exampleKor":"그 도서관은 다양한 시청각 자료를 빌려 준다."},{"word":"current","pos":"adj.","meaning":"현재의; 현행의, 통용되는","example":"Current subscribers to the magazine will receive a free supplement.","exampleKor":"그 잡지의 현 구독자들은 무료 부록을 받을 것이다."},{"word":"local","pos":"adj.","meaning":"지방의, 고장의","example":"The tournament will be held at the local high school.","exampleKor":"그 토너먼트는 지역 고등학교에서 열릴 것이다."},{"word":"variety","pos":"n.","meaning":"다양성, 변화; 종류, 품종","example":"The newsstand sells a variety of magazines and newspapers.","exampleKor":"신문 가판대는 다양한 잡지와 신문을 판다."},{"word":"advocate","pos":"n./v.","meaning":"옹호자; 옹호하다","example":"The writer is an advocate of public education.","exampleKor":"그 작가는 공교육 옹호자이다."},{"word":"contributor","pos":"n.","meaning":"기고가, 공헌자","example":"The doctor is a regular contributor to the medical journal.","exampleKor":"그 의사는 그 의학 학술지의 정기 기고가이다."},{"word":"defy","pos":"v.","meaning":"저항하다; (설명·묘사 등이) 거의 불가능하다","example":"The documentary series defies conventional wisdom about fitness.","exampleKor":"그 다큐멘터리 시리즈는 건강에 대한 사회적인 통념에 저항한다."},{"word":"fascinating","pos":"adj.","meaning":"매혹적인, 황홀한","example":"Many fascinating pieces of art were on display.","exampleKor":"매혹적인 많은 미술 작품들이 전시되어 있었다."},{"word":"showing","pos":"n.","meaning":"(영화·연극의) 상영; 전시","example":"We attended the premiere showing of the Rita Garner movie.","exampleKor":"우리는 Rita Garner의 영화 시사회에 참석했다."}]},{"day":7,"title":"마케팅 전략 (마케팅 (1))","words":[{"word":"survey","pos":"n./v.","meaning":"설문 조사; (설문) 조사하다","example":"Customer surveys help to improve product quality.","exampleKor":"고객 설문 조사는 제품의 품질을 향상시키는 데 도움이 된다."},{"word":"analysis","pos":"n.","meaning":"분석","example":"The latest market analysis shows an increase in used car purchases.","exampleKor":"최근의 시장 분석은 중고차 구매의 증가를 보여 준다."},{"word":"respondent","pos":"n.","meaning":"응답자","example":"Almost all survey respondents rated the product highly.","exampleKor":"거의 모든 설문 응답자가 제품을 높이 평가했다."},{"word":"monopoly","pos":"n.","meaning":"(상품의) 독점, 전매","example":"Panatronic has a virtual monopoly on the manufacture of digital recorders.","exampleKor":"Panatronic사는 사실상 디지털 녹음기 제조 독점권을 가지고 있다."},{"word":"competition","pos":"n.","meaning":"경쟁","example":"Competition in the game software market has increased.","exampleKor":"게임 소프트웨어 시장에서의 경쟁이 증가했다."},{"word":"consistently","pos":"adv.","meaning":"항상, 일관되게","example":"The factory has consistently provided the highest grade products.","exampleKor":"그 공장은 항상 최상급 제품을 공급해 왔다."},{"word":"demand","pos":"n./v.","meaning":"수요; 요구하다","example":"The company could not meet the increased demand for mobile devices.","exampleKor":"그 회사는 늘어난 휴대 기기 수요를 충족시킬 수 없었다."},{"word":"do one's utmost","pos":"phr.","meaning":"전력을 다하다","example":"Sun Manufacturing does its utmost to ensure the quality of its products.","exampleKor":"Sun Manufacturing사는 제품의 품질을 보장하기 위해 전력을 다한다."},{"word":"expand","pos":"v.","meaning":"확장하다, 확대하다","example":"Brahe Optics has expanded its marketing and sales division.","exampleKor":"Brahe Optics사는 마케팅 영업 부서를 확장했다."},{"word":"advanced","pos":"adj.","meaning":"고급의; 진보한, 앞선","example":"Modern cell phones are very advanced compared to those from a decade ago.","exampleKor":"요즘 휴대 전화는 10년 전의 것에 비해 매우 고급이다."},{"word":"postpone","pos":"v.","meaning":"연기하다, 뒤로 미루다","example":"Organizers postponed the conference on management strategies because of bad weather.","exampleKor":"주최 측은 악천후 때문에 경영 전략에 관한 회의를 연기했다."},{"word":"additional","pos":"adj.","meaning":"추가의, 부가적인","example":"Several investors decided to purchase additional stocks.","exampleKor":"몇몇 투자자들은 추가 주식을 매입하기로 결정했다."},{"word":"appreciate","pos":"v.","meaning":"고맙게 생각하다; 높이 평가하다; 감상하다","example":"Benson Co. appreciates your continued business.","exampleKor":"Benson사는 귀하의 지속적인 거래를 고맙게 생각합니다."},{"word":"demonstration","pos":"n.","meaning":"설명; 드러냄, 시연","example":"The salesclerk offered to provide a demonstration on how to use the photocopier.","exampleKor":"그 판매원은 복사기 사용법에 대한 설명을 제공하겠다고 나섰다."},{"word":"buy","pos":"v.","meaning":"사다, 구입하다","example":"The acquisitions department buys all of the office equipment.","exampleKor":"구매부에서 모든 사무실 비품을 산다."},{"word":"examine","pos":"v.","meaning":"조사하다","example":"Research and Development will examine food consumption trends in foreign markets.","exampleKor":"연구 개발 부서는 해외 시장에서의 식품 소비 경향을 조사할 것이다."},{"word":"effective","pos":"adj.","meaning":"효과적인; (법률 등이) 발효되는, 시행되는","example":"An effective advertising campaign is one that people remember for a long time.","exampleKor":"효과적인 광고 캠페인은 사람들이 오랫동안 기억하는 것이다."},{"word":"like","pos":"v./prep.","meaning":"좋아하다; ~와 같이, ~처럼","example":"Consumers like products that look high-end but are less expensive.","exampleKor":"소비자들은 최고급으로 보이지만 덜 비싼 제품을 좋아한다."},{"word":"especially","pos":"adv.","meaning":"특히","example":"Manufacturers of large vehicles are facing an especially difficult year for sales.","exampleKor":"대형 차량 제조업체들은 판매에 있어 특히 힘든 한 해를 맞고 있다."},{"word":"closely","pos":"adv.","meaning":"면밀히, 엄밀히","example":"Marketing departments monitor the latest trends closely.","exampleKor":"마케팅 부서는 최신 경향을 면밀히 관찰한다."},{"word":"reserve","pos":"v.","meaning":"예약하다, 지정하다; 보존하다","example":"The secretary will reserve hotel rooms for anyone going to the convention.","exampleKor":"비서가 대회에 참석하는 사람들을 위해 호텔 방을 예약할 것이다."},{"word":"cooperate","pos":"v.","meaning":"협력하다, 협동하다","example":"The two companies cooperated on developing the promotional campaign for the new spring collection.","exampleKor":"두 회사는 새로운 봄 컬렉션 홍보 캠페인을 개발하는 것에 대해 협력했다."},{"word":"very","pos":"adv.","meaning":"매우, 대단히, 아주","example":"The survey was very effective at identifying the target market.","exampleKor":"그 설문 조사는 표적 시장을 찾는 데 매우 효과적이었다."},{"word":"consecutive","pos":"adj.","meaning":"연속적인","example":"The Barkley Company achieved high sales growth for the third consecutive year.","exampleKor":"Barkley사는 3년 연속으로 고매출 성장을 달성했다."},{"word":"expectation","pos":"n.","meaning":"예상, 기대","example":"The expectation is that costs will be cut.","exampleKor":"비용이 감소될 것으로 예상된다."},{"word":"publicize","pos":"v.","meaning":"공표하다; 광고하다, 선전하다","example":"New regulations are publicized on the government Web site.","exampleKor":"새로운 규정들은 정부 웹사이트에 공표된다."},{"word":"raise","pos":"v./n.","meaning":"높이다, 올리다; (의문을) 제기하다; 임금 인상","example":"We used mass-mailing methods to raise awareness of our brand.","exampleKor":"우리는 자사 브랜드에 대한 인식을 높이기 위해 대량 메일 발송법을 이용했다."},{"word":"extremely","pos":"adv.","meaning":"극도로, 대단히","example":"Internet service providers struggle to survive in today's extremely competitive market.","exampleKor":"인터넷 서비스 사업자들은 오늘날의 극도로 경쟁적인 시장에서 살아남기 위해 분투한다."},{"word":"affect","pos":"v.","meaning":"~에 영향을 미치다, 불리하게 작용하다","example":"The frozen-food industry can affect the canned goods market.","exampleKor":"냉동식품 산업이 통조림 시장에 영향을 미칠 수 있다."},{"word":"target","pos":"n./v.","meaning":"목표; 목표로 삼다","example":"Sales for this quarter are right on target.","exampleKor":"이번 분기 매출은 정확히 목표에 이르렀다."},{"word":"campaign","pos":"n.","meaning":"운동, 캠페인","example":"The mayor's election campaign focused on his strong record in office.","exampleKor":"그 시장의 선거 운동은 재직 중 그의 눈부신 업적에 초점을 맞추었다."},{"word":"probable","pos":"adj.","meaning":"개연성이 높은, 유망한","example":"One of the probable causes for low sales was the lack of promotion.","exampleKor":"낮은 매출의 개연성 높은 원인 중 하나는 홍보의 부족이었다."},{"word":"focus","pos":"v./n.","meaning":"집중시키다, 집중하다; 초점","example":"Management decided to focus resources on expanding its business.","exampleKor":"경영진은 사업을 확장하는 데 자원을 집중하기로 결정했다."},{"word":"seasonal","pos":"adj.","meaning":"계절의, 계절적인","example":"The sugarcane industry is vulnerable to seasonal variations.","exampleKor":"사탕수수 산업은 계절에 따른 차이에 민감하다."},{"word":"impact","pos":"n.","meaning":"영향, 충격","example":"Price fluctuations had a major impact on the market.","exampleKor":"물가 변동은 시장에 큰 영향을 주었다."},{"word":"comparison","pos":"n.","meaning":"비교","example":"Online advertising is cheaper in comparison with television.","exampleKor":"온라인 광고는 텔레비전 광고와 비교해 볼 때 더 저렴하다."},{"word":"gap","pos":"n.","meaning":"격차","example":"Severe deficits can occur when there is a huge gap between exports and imports.","exampleKor":"수출과 수입 간에 큰 격차가 있을 때 극심한 적자가 발생할 수 있다."},{"word":"mounting","pos":"adj.","meaning":"증가하는, 오르는","example":"There is mounting pressure from management to increase productivity.","exampleKor":"경영진으로부터 생산성을 증대하라는 압박이 증가하고 있다."},{"word":"reflective","pos":"adj.","meaning":"반영하는","example":"Shrinking profits are reflective of the current state of the company.","exampleKor":"줄어드는 수익이 회사의 현재 상태를 반영한다."}]},{"day":8,"title":"글로벌 마케팅 (마케팅 (2))","words":[{"word":"advertisement","pos":"n.","meaning":"광고","example":"Sales have been propelled by the new advertisement.","exampleKor":"판매가 새 광고에 의해 촉진되었다."},{"word":"marginal","pos":"adj.","meaning":"약간의; 주변의","example":"Customers showed only marginal interest in the new tablet computer.","exampleKor":"소비자들은 신상 태블릿 컴퓨터에 약간의 관심만을 보였을 뿐이다."},{"word":"customer","pos":"n.","meaning":"고객","example":"Telephone representatives should make the needs of customers their priority.","exampleKor":"전화 상담원들은 고객의 요구를 그들의 우선 사항으로 삼아야 한다."},{"word":"influence","pos":"v./n.","meaning":"~에 영향을 주다; 영향","example":"Demand for housing directly influences the cost of homes.","exampleKor":"주택에 대한 수요는 주택 가격에 직접적으로 영향을 준다."},{"word":"instantly","pos":"adv.","meaning":"즉각적으로, 즉시","example":"The brand logo should be instantly recognizable.","exampleKor":"브랜드 로고는 즉각적으로 알아볼 수 있어야 한다."},{"word":"creative","pos":"adj.","meaning":"창조적인, 독창적인","example":"Mr. Beaumont came up with a creative idea.","exampleKor":"Mr. Beaumont는 창조적인 아이디어를 생각해냈다."},{"word":"aggressively","pos":"adv.","meaning":"적극적으로","example":"The best sales representatives aggressively seek out potential clients.","exampleKor":"최고의 영업 사원들은 적극적으로 잠재 고객을 찾아 나선다."},{"word":"aim","pos":"v./n.","meaning":"~을 겨누다; 목표, 목적","example":"Sport Apparel developed athletic gear aimed at teenagers.","exampleKor":"Sport Apparel사는 10대를 겨냥한 운동 기구를 개발했다."},{"word":"strategy","pos":"n.","meaning":"전략","example":"Management's strategy for expansion has been successful.","exampleKor":"경영진의 확장 전략은 성공적이었다."},{"word":"indicate","pos":"v.","meaning":"보여주다, 나타내다","example":"Studies indicate that consumers prefer attractively packaged products.","exampleKor":"그 연구는 소비자들이 보기 좋게 포장된 상품을 선호한다는 것을 보여준다."},{"word":"attract","pos":"v.","meaning":"끌다, 유인하다","example":"The automaker is making an effort to attract younger buyers.","exampleKor":"그 자동차 회사는 더 젊은 구매자들을 끌기 위해 노력하고 있다."},{"word":"experience","pos":"n./v.","meaning":"경험, 체험; 체험하다, 경험하다","example":"All of the invited guests had a pleasant experience at the store opening.","exampleKor":"초대된 손님들 모두가 그 가게의 개장식에서 즐거운 경험을 했다."},{"word":"analyze","pos":"v.","meaning":"분석하다, 분석적으로 검토하다","example":"Researchers were asked to analyze the survey data.","exampleKor":"연구원들은 설문 조사 자료를 분석하라고 요청받았다."},{"word":"introduce","pos":"v.","meaning":"(신제품을) 발표하다, 소개하다","example":"ElectroLife introduced a new line of vacuum cleaners.","exampleKor":"ElectroLife사는 새로운 진공청소기 제품을 발표했다."},{"word":"advise","pos":"v.","meaning":"조언해 주다, 충고하다","example":"Coburn Law Firm advises clients on intellectual property matters.","exampleKor":"Coburn 법률 회사는 고객들에게 지적 재산권 문제에 대해 조언해 준다."},{"word":"subscribe","pos":"v.","meaning":"구독하다","example":"Subscribing to the monthly fashion magazine costs only $40 a year.","exampleKor":"그 월간 패션 잡지를 구독하는 것은 일 년에 단 40달러밖에 들지 않는다."},{"word":"absence","pos":"n.","meaning":"부재; 결근, 결석","example":"The absence of competition will help product sales.","exampleKor":"경쟁의 부재는 제품 판매에 도움이 될 것이다."},{"word":"means","pos":"n.","meaning":"방법, 수단","example":"Direct surveys are one means of gathering consumer feedback.","exampleKor":"직접 조사는 소비자 의견을 모으는 한 가지 방법이다."},{"word":"prefer","pos":"v.","meaning":"(다른 것보다) ~을 더 좋아하다, 선호하다","example":"Customers prefer Luster Shampoo to any other competing brand.","exampleKor":"고객들은 다른 어떤 경쟁 상표보다 Luster 샴푸를 더 좋아한다."},{"word":"advantage","pos":"n.","meaning":"이점, 강점","example":"One advantage of consumer testing is the development of marketing insight.","exampleKor":"소비자 테스트의 한 가지 이점은 마케팅 식견을 기를 수 있다는 점이다."},{"word":"forward","pos":"adv./v.","meaning":"앞으로; (물건·정보를) 보내다","example":"Our company's research program has moved forward substantially.","exampleKor":"우리 회사의 연구 프로그램이 상당히 진척되었다."},{"word":"contemporary","pos":"adj.","meaning":"동시대의; 현대의, 당대의","example":"Advertising messages change over time to reflect contemporary attitudes.","exampleKor":"광고 메시지는 동시대의 사고방식을 반영하기 위해 시간이 지남에 따라 변화한다."},{"word":"discussion","pos":"n.","meaning":"토론, 토의","example":"A discussion was held to decide how to promote the product.","exampleKor":"그 제품을 어떻게 홍보할지 결정하기 위해 토론이 열렸다."},{"word":"initial","pos":"adj.","meaning":"처음의, 최초의","example":"Initial findings show that customers are satisfied with the service.","exampleKor":"처음의 조사 결과는 고객들이 그 서비스에 만족한다는 것을 보여준다."},{"word":"steadily","pos":"adv.","meaning":"착실하게; 꾸준히","example":"Ron steadily answered investors' questions about his business idea.","exampleKor":"Ron은 그의 사업 계획에 대한 투자자들의 질문에 착실하게 대답했다."},{"word":"necessarily","pos":"adv.","meaning":"반드시","example":"Increased production does not necessarily lead to greater revenues.","exampleKor":"생산 증가가 반드시 수입 증가로 이어지는 것은 아니다."},{"word":"resolve","pos":"v.","meaning":"(문제 등을) 해결하다","example":"The new facial cream promises to resolve 90 percent of common skin problems.","exampleKor":"새로운 얼굴 마사지 크림은 흔한 피부 문제들의 90퍼센트를 해결하는 것을 보증한다."},{"word":"detect","pos":"v.","meaning":"간파하다, 탐지하다","example":"Only a few people detected any actual differences between the two models.","exampleKor":"오직 몇몇 사람들만이 두 모델 간의 실질적인 차이점 모두를 간파했다."},{"word":"intensify","pos":"v.","meaning":"강화하다, 증대하다, 강렬하게 만들다","example":"The movie studio intensified its promotional activities to draw in a wider audience.","exampleKor":"그 영화 제작사는 더 폭넓은 관중을 끌기 위해 홍보 활동을 강화했다."},{"word":"favorably","pos":"adv.","meaning":"호의적으로; 순조롭게","example":"The product demonstration was favorably received by consumers.","exampleKor":"제품 시연이 소비자들에게 호의적으로 받아들여졌다."},{"word":"cover","pos":"v.","meaning":"포함하다; 지불하다; 덮다","example":"The rental deposit covers the cost of repairing damage to the equipment.","exampleKor":"대여 보증금은 장비 손상을 수리하는 것에 대한 비용을 포함한다."},{"word":"less","pos":"adj.","meaning":"보다 적은, 덜한","example":"Less competition among insurance companies led to higher premiums.","exampleKor":"보험사 간의 보다 적은 경쟁이 보험료 증가로 이어졌다."},{"word":"majority","pos":"n.","meaning":"대부분, 대다수","example":"The majority of registered clients pay their dues regularly.","exampleKor":"등록된 고객의 대부분이 정기적으로 요금을 지불한다."},{"word":"adopt","pos":"v.","meaning":"채택하다","example":"Plenty of research must be done before adopting a particular marketing strategy.","exampleKor":"특정 마케팅 전략을 채택하기 전에 많은 조사가 이루어져야 한다."},{"word":"largely","pos":"adv.","meaning":"주로, 대부분","example":"Public reaction to the charity foundation was largely positive.","exampleKor":"자선 재단에 대한 대중의 반응은 주로 긍정적이었다."},{"word":"disregard","pos":"v.","meaning":"소홀히 하다, 무시하다","example":"The company should not disregard customers' opinions if it wants to improve the service quality.","exampleKor":"회사는 서비스 질을 향상시키고 싶다면 고객들의 의견을 소홀히 하지 말아야 한다."},{"word":"effort","pos":"n.","meaning":"노력","example":"TV commercials were run in an effort to broaden consumer awareness of new brands.","exampleKor":"새 브랜드에 대한 소비자 인지도를 넓히려는 노력으로 텔레비전 광고가 방송되었다."},{"word":"incentive","pos":"n.","meaning":"혜택, 장려금","example":"Financial incentives such as coupons may encourage purchases.","exampleKor":"쿠폰 같은 금전적 혜택이 구매를 촉진시킬 수 있다."},{"word":"need","pos":"n./v.","meaning":"필요; 요구, 욕구; ~할 필요가 있다","example":"The company is in need of an untapped market.","exampleKor":"그 회사는 미개척 시장을 필요로 하고 있다."},{"word":"mastermind","pos":"n.","meaning":"(계획 등의) 입안자, 지도자","example":"Mr. Dane is the mastermind behind the innovative design.","exampleKor":"Mr. Dane은 그 혁신적인 디자인의 입안자이다."}]},{"day":9,"title":"경제 살리기 (경제)","words":[{"word":"stagnant","pos":"adj.","meaning":"침체된, 불경기의","example":"Profits are down this year as sales have been stagnant.","exampleKor":"판매가 침체되면서 올해 수익이 감소했다."},{"word":"dramatically","pos":"adv.","meaning":"극적으로","example":"Interest rates climbed dramatically.","exampleKor":"금리가 극적으로 상승했다."},{"word":"brisk","pos":"adj.","meaning":"활발한, 호황의","example":"A brisk market is developing in online shopping.","exampleKor":"온라인 쇼핑 분야에서 활발한 시장이 형성되고 있다."},{"word":"unstable","pos":"adj.","meaning":"불안정한, 변하기 쉬운","example":"Gas prices have been unstable in recent years.","exampleKor":"휘발유 가격이 최근 몇 년간 불안정했다."},{"word":"rapidly","pos":"adv.","meaning":"급속히, 빨리","example":"Energy demand increased rapidly.","exampleKor":"에너지 수요가 급속히 증가했다."},{"word":"soar","pos":"v.","meaning":"(물가 등이) 폭등하다, 높이 치솟다","example":"Interest rates have soared due to inflation.","exampleKor":"인플레이션으로 금리가 폭등했다."},{"word":"assert","pos":"v.","meaning":"단언하다, 주장하다","example":"The report asserts that corporate growth will continue.","exampleKor":"그 보고서는 기업 성장이 계속될 것이라 단언한다."},{"word":"boost","pos":"v.","meaning":"(경기를) 부양시키다, 상승시키다","example":"The real estate industry has helped boost the economy.","exampleKor":"부동산 산업이 경기를 부양시키는 데 도움이 되었다."},{"word":"analyst","pos":"n.","meaning":"분석가","example":"Analysts recommend buying stock in energy companies.","exampleKor":"분석가들은 에너지 회사들의 주식을 사는 것을 추천한다."},{"word":"potential","pos":"adj./n.","meaning":"잠재적인; 가능성","example":"Potential earnings from the trade deal could reach billions of dollars.","exampleKor":"그 무역 거래에서 나올 잠재적인 수익은 수십억 달러에 이를 수 있다."},{"word":"pleased","pos":"adj.","meaning":"만족해하는, 기쁜","example":"Investors are pleased with the market's performance.","exampleKor":"투자자들은 시장 성과에 만족해한다."},{"word":"remain","pos":"v.","meaning":"계속 ~한 상태이다; 아직 ~해야 하다","example":"The cost of living will remain stable over the next decade.","exampleKor":"생활비는 향후 10년 동안 계속 안정적인 상태일 것이다."},{"word":"limited","pos":"adj.","meaning":"제한된, 한정된","example":"The island nation has limited natural resources.","exampleKor":"그 섬나라는 제한된 천연자원을 가지고 있다."},{"word":"costly","pos":"adj.","meaning":"비용이 많이 드는, 손실이 큰","example":"Starting a business is costly.","exampleKor":"사업을 시작하는 것은 비용이 많이 든다."},{"word":"particular","pos":"adj.","meaning":"특정한","example":"Import taxes are higher for particular products that are luxury goods.","exampleKor":"수입세는 사치품인 특정 제품에 대해 더 높다."},{"word":"drastic","pos":"adj.","meaning":"과감한; 급격한","example":"Resolving the financial crisis will require drastic action.","exampleKor":"금융 위기를 해결하는 것은 과감한 조치를 필요로 할 것이다."},{"word":"evenly","pos":"adv.","meaning":"고르게, 균등하게","example":"Economic wealth is not evenly distributed.","exampleKor":"경제적인 부는 고르게 분배되지 않는다."},{"word":"evidence","pos":"n.","meaning":"증거","example":"The latest employment data shows evidence that the economy is improving.","exampleKor":"최신 취업 자료는 경제가 개선되고 있다는 증거를 보여 준다."},{"word":"prospect","pos":"n.","meaning":"전망, 예상","example":"Bolton Industries is facing the prospect of having to reduce its workforce.","exampleKor":"Bolton Industries사는 직원을 줄여야 한다는 전망에 직면하고 있다."},{"word":"lead","pos":"v.","meaning":"이끌다, 지휘하다; (어떤 결과에) 이르다","example":"Ms. Vasquez helped lead the company to success.","exampleKor":"Ms. Vasquez는 회사를 성공으로 이끄는 데 도움을 주었다."},{"word":"fall","pos":"v.","meaning":"(값·가치가) 하락하다","example":"The rate of unemployment has fallen steadily this quarter.","exampleKor":"실업률이 이번 분기에 꾸준히 하락했다."},{"word":"period","pos":"n.","meaning":"기간, 시기","example":"For a period of three years, the company underwent rapid expansion.","exampleKor":"3년의 기간 동안, 그 회사는 빠른 확장을 겪었다."},{"word":"indicator","pos":"n.","meaning":"지표, 지수","example":"Current economic indicators show rising growth in mining.","exampleKor":"현재의 경제 지표는 광업 분야의 성장 증대를 보여 준다."},{"word":"industry","pos":"n.","meaning":"산업","example":"Jobs in the newspaper industry are declining rapidly.","exampleKor":"신문 산업에서의 일자리가 급속히 감소하고 있다."},{"word":"likely","pos":"adj.","meaning":"~할 것 같은","example":"The new CEO is likely to confront major challenges.","exampleKor":"새로 부임한 최고 경영자는 큰 난제들에 직면할 것 같다."},{"word":"boom","pos":"n.","meaning":"붐, 호황","example":"Land developers are taking advantage of the housing boom.","exampleKor":"주택 개발업자들은 주택 시장의 붐을 이용하고 있다."},{"word":"director","pos":"n.","meaning":"임원, 책임자","example":"The company directors are discussing a new business strategy.","exampleKor":"회사의 임원들이 새로운 사업 전략을 논의하고 있다."},{"word":"substitute","pos":"n./v.","meaning":"대용품; 대신하다","example":"Corn syrup is used as a substitute for sugar in many food products.","exampleKor":"옥수수 시럽은 많은 식품에서 설탕의 대용품으로 사용된다."},{"word":"consequence","pos":"n.","meaning":"결과","example":"Profits grew as a consequence of increased business.","exampleKor":"늘어난 거래의 결과로 이윤이 증가했다."},{"word":"fairly","pos":"adv.","meaning":"상당히, 꽤","example":"Concerns over the bankruptcy are fairly widespread.","exampleKor":"파산에 대한 우려가 상당히 널리 퍼져 있다."},{"word":"economical","pos":"adj.","meaning":"경제적인, 절약되는","example":"Companies are searching for economical ways to utilize energy.","exampleKor":"기업들은 경제적인 에너지 사용법을 모색하고 있다."},{"word":"thrive","pos":"v.","meaning":"번영하다, 성공하다","example":"The delivery service industry is thriving.","exampleKor":"배송 산업이 번영하고 있다."},{"word":"implication","pos":"n.","meaning":"영향, 밀접한 관계","example":"The Supreme Court ruling has implications for small businesses.","exampleKor":"대법원 판결은 소규모 사업체들에 영향을 미친다."},{"word":"wane","pos":"n.","meaning":"감소, 쇠퇴","example":"Consumer spending is on the wane.","exampleKor":"소비자 지출이 감소하고 있다."},{"word":"prosperity","pos":"n.","meaning":"번영","example":"Strong economic growth is a prerequisite for national prosperity.","exampleKor":"안정적인 경제 성장은 국가 번영의 필요 요건이다."},{"word":"depression","pos":"n.","meaning":"불황","example":"The entire industry is going through an economic depression.","exampleKor":"산업 전체가 경제 불황을 겪고 있다."},{"word":"dwindle","pos":"v.","meaning":"줄어들다, 감소되다","example":"The company's profits dwindled in the 1990s.","exampleKor":"회사의 이윤이 1990년대에 줄어들었다."},{"word":"impede","pos":"v.","meaning":"저해하다, 방해하다","example":"Natural calamities in the summer will impede national growth.","exampleKor":"여름에 발생한 자연재해가 국가 성장을 저해할 것이다."},{"word":"promising","pos":"adj.","meaning":"유망한, 전망이 좋은","example":"Many people find promising careers in health and technology.","exampleKor":"많은 사람들이 의료 및 기술 분야에서 유망한 직업을 찾는다."},{"word":"adversity","pos":"n.","meaning":"역경, 불운","example":"In spite of the adversity he faced, Mike managed to find a job.","exampleKor":"그가 직면한 역경에도 불구하고, Mike는 직업을 구했다."}]},{"day":10,"title":"쇼핑의 고수 (쇼핑)","words":[{"word":"purchase","pos":"v./n.","meaning":"구매하다; 구매","example":"The customer purchased a laptop computer.","exampleKor":"그 고객은 노트북 컴퓨터를 구매했다."},{"word":"price","pos":"n.","meaning":"가격","example":"The new color printer has a retail price of only $150.99.","exampleKor":"새 컬러 프린터는 소매가로 겨우 150.99달러밖에 안 된다."},{"word":"affordable","pos":"adj.","meaning":"(가격이) 알맞은, 감당할 수 있는","example":"Toyama launched an affordable mid-range sedan.","exampleKor":"Toyama사가 알맞은 가격의 중형 세단을 출시했다."},{"word":"exactly","pos":"adv.","meaning":"정확히","example":"The sales representatives help customers decide exactly what style fits them best.","exampleKor":"영업 사원들은 고객들이 정확히 어떤 스타일이 자신에게 가장 잘 맞는지 결정하는 데 도움을 준다."},{"word":"installment","pos":"n.","meaning":"할부","example":"The shop allows buyers to pay for furniture in monthly installments.","exampleKor":"그 상점은 구매자가 가구 값을 매달 할부로 지불하는 것을 허용한다."},{"word":"notice","pos":"n.","meaning":"통지, 공고","example":"The prices listed in the catalog are effective until further notice.","exampleKor":"카탈로그에 명시된 가격은 추후 통지가 있을 때까지 유효합니다."},{"word":"charge","pos":"n./v.","meaning":"요금, 청구 금액; 책임, 의무; ~을 청구하다, (외상으로) 달아놓다","example":"The price includes shipping and handling charges.","exampleKor":"그 가격은 운송 및 취급 요금을 포함한다."},{"word":"experienced","pos":"adj.","meaning":"경험이 있는, 노련한, 능숙한","example":"Bill is the most experienced salesperson in the store.","exampleKor":"Bill은 그 상점에서 가장 경험이 많은 판매원이다."},{"word":"instruction","pos":"n.","meaning":"설명, 지시","example":"The receipt gives instructions for returning or exchanging items.","exampleKor":"영수증은 제품의 반품이나 교환에 대한 설명을 제시한다."},{"word":"expert","pos":"n./adj.","meaning":"전문가; 전문가의, 전문적인","example":"A personal shopper is an expert at finding bargains for customers.","exampleKor":"물품 구매 상담원은 고객들을 위해 싼 물건을 찾는 데 있어 전문가이다."},{"word":"warranty","pos":"n.","meaning":"(품질 등의) 보증, 보증서","example":"The computer is under warranty for two years.","exampleKor":"그 컴퓨터는 보증 기간이 2년입니다."},{"word":"refund","pos":"n.","meaning":"환불, 환불금","example":"Buyers can get a full refund for a defective product.","exampleKor":"구매자들은 결함이 있는 제품에 대해 전액 환불을 받을 수 있습니다."},{"word":"subscriber","pos":"n.","meaning":"가입자, 구독자","example":"The Web site now has millions of subscribers.","exampleKor":"그 웹사이트는 이제 수백만 명의 가입자가 있다."},{"word":"delivery","pos":"n.","meaning":"배달","example":"We guarantee delivery within three days.","exampleKor":"저희는 3일 이내 배달을 보장합니다."},{"word":"receipt","pos":"n.","meaning":"영수증","example":"The original receipt is required for all refunds.","exampleKor":"원본 영수증은 모든 환불에 요구된다."},{"word":"carefully","pos":"adv.","meaning":"주의 깊게, 신중히","example":"Please follow the installation directions carefully.","exampleKor":"설치 설명서를 주의 깊게 따라 하십시오."},{"word":"offer","pos":"v./n.","meaning":"제공하다; 제공, 오퍼","example":"Z-Mart offers $25 gift cards to customers signing up for membership.","exampleKor":"Z-Mart는 회원 등록을 하는 고객들에게 25달러 상품권을 제공한다."},{"word":"benefit","pos":"n./v.","meaning":"혜택, 이익; 혜택을 보다, 이익을 얻다","example":"The Shoppers' Club offers many benefits to its members.","exampleKor":"Shoppers' Club은 회원들에게 많은 혜택을 제공한다."},{"word":"exclusively","pos":"adv.","meaning":"오로지, 독점적으로","example":"A 10 percent discount is available exclusively to Premium Club members.","exampleKor":"10퍼센트 할인은 오로지 Premium Club 회원들만 이용할 수 있다."},{"word":"description","pos":"n.","meaning":"(제품 등의) 설명, 해설","example":"Call customer service for a more extensive description of any of the equipment.","exampleKor":"어떤 종류의 장비에 관해서든 더 많은 설명을 원하시면 고객 서비스 센터로 전화하세요."},{"word":"relatively","pos":"adv.","meaning":"상대적으로","example":"McCoy's has a relatively lenient return policy compared to similar stores.","exampleKor":"McCoy's사는 유사한 가게들에 비해 상대적으로 관대한 반품 규정을 갖고 있다."},{"word":"preparation","pos":"n.","meaning":"준비, 대비","example":"Preparations are under way for the department store's grand opening.","exampleKor":"백화점 대개장을 위한 준비가 진행 중이다."},{"word":"spare","pos":"v./adj.","meaning":"아끼다, 할애하다; 예비의, 여분의","example":"The shopping mall spared no expense on the 10th anniversary promotion.","exampleKor":"그 쇼핑몰은 10주년 홍보에 비용을 아끼지 않았다."},{"word":"area","pos":"n.","meaning":"지역, 구역","example":"There are excellent retail stores in this area.","exampleKor":"이 지역에는 훌륭한 소매점들이 있다."},{"word":"clearance","pos":"n.","meaning":"정리, 없애기; 허가","example":"There is usually a clearance sale for winter clothes in March.","exampleKor":"겨울옷 재고 정리 할인 판매는 보통 3월에 있다."},{"word":"alter","pos":"v.","meaning":"(성질·형상을) 고치다, 바꾸다","example":"The customer asked that the length of his pants be altered.","exampleKor":"그 고객은 바지 기장을 고쳐 달라고 요청했다."},{"word":"apply","pos":"v.","meaning":"적용하다; 지원하다","example":"The cashier applied the discount to all the items.","exampleKor":"그 계산원은 모든 품목에 할인을 적용했다."},{"word":"mutually","pos":"adv.","meaning":"서로, 상호 간에","example":"The couple and dealer reached a mutually agreeable price for the car.","exampleKor":"그 부부와 판매원은 서로 동의할 수 있는 차 가격에 도달했다."},{"word":"method","pos":"n.","meaning":"방식, 방법","example":"In recent years, debit cards have become a popular method of payment.","exampleKor":"최근 몇 년 사이에, 직불카드는 인기 있는 지불 방식이 되었다."},{"word":"acceptable","pos":"adj.","meaning":"용인되는, 받아들일 수 있는; 훌륭한, 만족스러운","example":"Jenson Fashions sells clothes that are acceptable as business attire.","exampleKor":"Jenson Fashions사는 비즈니스 정장으로 용인되는 옷을 판매한다."},{"word":"desire","pos":"n./v.","meaning":"욕구, 갈망; 원하다, 바라다","example":"Effective advertising can create a desire in consumers to buy goods they do not need.","exampleKor":"효과적인 광고는 소비자들에게 그들이 필요로 하지 않는 상품을 사려는 욕구를 불러일으킬 수 있다."},{"word":"redeemable","pos":"adj.","meaning":"(현금·상품과) 교환할 수 있는, 환급할 수 있는","example":"Store gift vouchers are redeemable at any branch.","exampleKor":"상점 상품권은 어느 지점에서나 교환할 수 있습니다."},{"word":"officially","pos":"adv.","meaning":"공식적으로","example":"The online store will officially open next month.","exampleKor":"온라인 상점은 다음 달에 공식적으로 개점할 것이다."},{"word":"consumption","pos":"n.","meaning":"소비(량), 소모","example":"Consumption of high-end products like home theaters has increased recently.","exampleKor":"홈시어터와 같은 고급 제품의 소비가 최근 증가했다."},{"word":"qualify","pos":"v.","meaning":"~의 자격을 얻다","example":"Clients need a regular income to qualify for credit cards.","exampleKor":"고객들이 신용 카드를 발급받을 자격을 얻으려면 정기적인 수입이 필요하다."},{"word":"fabric","pos":"n.","meaning":"섬유, 천","example":"The manufacturer's garments are made of natural fabric only.","exampleKor":"그 제조업체의 의류는 오직 천연 섬유로만 만들어진다."},{"word":"auction","pos":"n.","meaning":"경매","example":"A number of antique pieces will be sold at the auction.","exampleKor":"많은 골동품들이 경매에서 판매될 것이다."},{"word":"authentic","pos":"adj.","meaning":"진정한, 진짜의, 진품의","example":"The new restaurant downtown serves authentic Spanish cuisine.","exampleKor":"시내에 새로 생긴 식당은 진정한 스페인 요리를 제공한다."},{"word":"valid","pos":"adj.","meaning":"유효한","example":"A valid receipt must be presented.","exampleKor":"유효한 영수증을 제시해야 합니다."},{"word":"vendor","pos":"n.","meaning":"노점상, 가판대; 판매업체","example":"The street is filled with vendors during the weekly market.","exampleKor":"그 거리는 매주 시장이 서는 동안 노점상으로 가득 찬다."}]},{"day":11,"title":"신제품 출시 (제품개발)","words":[{"word":"research","pos":"n.","meaning":"연구, 조사","example":"The company started a research program into developing GPS technology.","exampleKor":"그 회사는 위치 파악 시스템(GPS) 기술을 개발하는 연구 프로그램을 시작했다."},{"word":"devise","pos":"v.","meaning":"고안하다, 발명하다","example":"The firm devised a more efficient network system.","exampleKor":"그 회사는 보다 효율적인 네트워크 시스템을 고안했다."},{"word":"revolutionary","pos":"adj.","meaning":"혁명적인","example":"The car's revolutionary new engine surpasses those of the competition.","exampleKor":"그 차의 혁명적인 새 엔진은 경쟁사의 것들을 능가한다."},{"word":"innovative","pos":"adj.","meaning":"혁신적인","example":"Simpson & Associates provides clients with innovative solutions to their needs.","exampleKor":"Simpson & Associates사는 고객들의 필요에 맞는 혁신적인 해결책을 제공한다."},{"word":"feature","pos":"n./v.","meaning":"특징, 특색; 특징으로 삼다, 특별히 포함하다","example":"The latest dryer has several new features.","exampleKor":"최신 건조기는 몇 가지 새로운 특징을 갖고 있다."},{"word":"inspiration","pos":"n.","meaning":"영감","example":"The new fashion designer draws her inspiration from traditional attire.","exampleKor":"새 패션 디자이너는 전통 의상에서 영감을 얻는다."},{"word":"sufficiently","pos":"adv.","meaning":"충분히","example":"The containers are sufficiently strong to resist breakage.","exampleKor":"그 그릇들은 파손을 견딜 만큼 충분히 강하다."},{"word":"patent","pos":"n.","meaning":"특허, 특허권, 특허품","example":"The lawyers submitted the paperwork for a patent application.","exampleKor":"변호사들이 특허 신청을 위한 서류를 제출했다."},{"word":"envision","pos":"v.","meaning":"(장래의 일 등을) 계획하다, 상상하다","example":"Management envisions its latest product being sold in stores across the country.","exampleKor":"경영진은 자사의 최신 제품이 전국에 있는 상점에서 판매되는 것을 계획한다."},{"word":"extend","pos":"v.","meaning":"연장하다; (기간을) 늘리다; (감사의 뜻을) 말하다, 베풀다","example":"A switch for adjusting brightness extends from the back of the lamp.","exampleKor":"밝기를 조절하는 스위치는 램프 뒷면으로부터 연장된다."},{"word":"following","pos":"prep./adj.","meaning":"~ 후에; 다음의, 다음에 오는","example":"The software was launched following months of research.","exampleKor":"그 소프트웨어는 몇 달간의 연구 후에 출시되었다."},{"word":"intend","pos":"v.","meaning":"~할 작정이다; 의도하다","example":"Beauford Incorporated intends to release its new appliances this fall.","exampleKor":"Beauford사는 올 가을에 새로운 가전제품을 출시할 작정이다."},{"word":"grant","pos":"v./n.","meaning":"(인정하여 정식으로) 수여하다, 주다; (연구비·장학금 등의) 보조금","example":"The patent for the handheld computer was granted on April 27.","exampleKor":"휴대용 컴퓨터에 대한 특허는 4월 27일에 수여되었다."},{"word":"allow","pos":"v.","meaning":"~하게 하다, ~을 허락하다","example":"The program's new feature allows users to conduct advanced searches.","exampleKor":"그 프로그램의 새로운 기능은 사용자들이 고급 검색을 할 수 있게 한다."},{"word":"inspect","pos":"v.","meaning":"~을 검사하다, 조사하다","example":"The head researcher inspects all equipments and chemicals in the laboratory daily to ensure safety.","exampleKor":"수석 연구원은 안전을 보장하기 위해 연구실의 모든 장비와 화학 약품을 매일 검사한다."},{"word":"improve","pos":"v.","meaning":"향상시키다, 개선하다","example":"A variety of incentives can improve staff productivity.","exampleKor":"다양한 장려금은 직원 생산성을 향상시킬 수 있다."},{"word":"increasingly","pos":"adv.","meaning":"점점, 더욱더","example":"Technology is becoming an increasingly important factor in the nation's economy.","exampleKor":"과학 기술은 국가 경제에서 점점 중요한 요소가 되고 있다."},{"word":"invest","pos":"v.","meaning":"투자하다, 운용하다","example":"Lamont Manufacturing invested millions of dollars in improving its assembly line.","exampleKor":"Lamont Manufacturing사는 조립 라인을 개선하는 데 수백만 달러를 투자했다."},{"word":"various","pos":"adj.","meaning":"여러 가지의, 가지각색의","example":"This car has various features not included in older models.","exampleKor":"이 자동차는 구형 모델에 포함되지 않았던 여러 가지 기능을 가지고 있다."},{"word":"upgrade","pos":"n./v.","meaning":"업그레이드, 개량형; 업그레이드하다, 개선하다","example":"Special customers are eligible for one free computer upgrade.","exampleKor":"특별 고객들은 한 번의 컴퓨터 무료 업그레이드를 받을 자격이 있다."},{"word":"manual","pos":"n.","meaning":"설명서, 안내서","example":"Rachel is writing the product manual for the new air conditioner.","exampleKor":"Rachel은 새로운 에어컨에 대한 제품 설명서를 작성하고 있다."},{"word":"explore","pos":"v.","meaning":"조사하다, 탐구하다","example":"Clients seeking company information can explore our Web site.","exampleKor":"회사 정보를 찾고자 하는 고객들은 우리 웹사이트를 조사할 수 있다."},{"word":"response","pos":"n.","meaning":"응답, 대답","example":"Those testing the new microwave are asked to submit written responses to some questions.","exampleKor":"새 전자레인지를 시험하는 사람들은 몇 가지 질문에 대해 서면으로 된 응답을 제출하라고 요청받는다."},{"word":"appearance","pos":"n.","meaning":"외관, 외모","example":"The design team completely modernized the product's appearance.","exampleKor":"디자인팀은 그 제품의 외관을 완전히 현대화했다."},{"word":"successful","pos":"adj.","meaning":"성공적인, 성공한","example":"The floor lamps are the company's most successful product.","exampleKor":"전기스탠드는 그 회사의 가장 성공적인 제품이다."},{"word":"hold","pos":"v.","meaning":"~을 수용하다, ~을 담다; (회의 등을) 개최하다, 열다","example":"The washing machine holds up to three kilograms of laundry.","exampleKor":"그 세탁기는 최대 3킬로그램의 세탁물을 수용한다."},{"word":"advance","pos":"n.","meaning":"진보, 전진","example":"The product development team researches advances in computer technology.","exampleKor":"제품 개발팀은 컴퓨터 기술의 진보에 대해 조사한다."},{"word":"reliable","pos":"adj.","meaning":"믿을 만한, 신뢰할 수 있는","example":"Tests indicate that Branco's products are reliable and efficient.","exampleKor":"실험은 Branco사의 제품이 믿을 만하고 효율적임을 보여 준다."},{"word":"quality","pos":"n.","meaning":"품질, 질","example":"The quality control division inspects samples of all items.","exampleKor":"품질 관리 부서는 모든 물품의 견본을 검사한다."},{"word":"domestic","pos":"adj.","meaning":"국내의, 국산의","example":"Slow sales in the domestic market forced companies to expand overseas.","exampleKor":"국내 시장에서의 부진한 매출은 기업들이 해외로 확장하게 했다."},{"word":"development","pos":"n.","meaning":"개발; 발전","example":"The project is in the final stage of development.","exampleKor":"그 프로젝트는 개발 마지막 단계에 있다."},{"word":"availability","pos":"n.","meaning":"(입수) 가능성, 유효성, 유용성","example":"Availability of product depends on market demand and supply.","exampleKor":"제품의 입수 가능성은 시장의 수요와 공급에 달려 있다."},{"word":"update","pos":"n./v.","meaning":"갱신, 개정; 갱신하다, 최신의 것으로 하다","example":"The Web site update includes information on the latest hair styling appliances.","exampleKor":"웹사이트 갱신은 최신 미용 기기에 대한 정보를 포함한다."},{"word":"accurate","pos":"adj.","meaning":"정확한","example":"The new accounting software is accurate and precise.","exampleKor":"새로운 회계 소프트웨어는 정확하고 정밀하다."},{"word":"complicated","pos":"adj.","meaning":"복잡한","example":"Project delays often create a complicated situation for the public relations department.","exampleKor":"프로젝트의 지연은 종종 홍보부에 복잡한 상황을 불러일으킨다."},{"word":"accomplished","pos":"adj.","meaning":"숙련된, 노련한","example":"The accomplished chemist has been hired to develop a flexible battery.","exampleKor":"숙련된 화학자가 잘 구부러지는 건전지를 개발하도록 고용되었다."},{"word":"inquiry","pos":"n.","meaning":"문의, 질문","example":"Please call our customer representatives for service inquiries.","exampleKor":"서비스 문의를 하시려면 저희 고객 상담원에게 전화하십시오."},{"word":"indication","pos":"n.","meaning":"징후, 조짐","example":"Uneven printing is an indication of a technical fault.","exampleKor":"고르지 못한 인쇄는 기술적 결함의 징후이다."},{"word":"manufacturer","pos":"n.","meaning":"제조 회사, 제조업자","example":"The manufacturer guarantees all its products for up to one year.","exampleKor":"그 제조 회사는 최대 1년 동안 모든 자사 제품에 대해 품질 보증을 해 준다."},{"word":"compatible","pos":"adj.","meaning":"호환되는, 양립할 수 있는","example":"The remote control is compatible with all models.","exampleKor":"그 리모컨은 모든 모델과 호환된다."},{"word":"superior","pos":"adj.","meaning":"우수한, 상급의","example":"The company's latest television is superior to those on the market today.","exampleKor":"그 회사의 최신 텔레비전은 현재 시중에 나와 있는 제품들보다 우수하다."},{"word":"absolute","pos":"adj.","meaning":"완전한, 완전무결한","example":"The latest technology keeps production costs to an absolute minimum.","exampleKor":"최신 과학 기술은 생산비를 완전 최소로 유지해 준다."},{"word":"broaden","pos":"v.","meaning":"넓히다","example":"The new CEO is broadening the scope of the company's research.","exampleKor":"신임 최고 경영자는 회사의 연구 범위를 넓히고 있다."},{"word":"corrosion","pos":"n.","meaning":"부식","example":"This steel roof is designed to be resistant to corrosion from the weather.","exampleKor":"이 강철 지붕은 날씨로 인한 부식에 저항력이 있도록 만들어졌다."},{"word":"remotely","pos":"adv.","meaning":"원격으로, 멀리서","example":"Researchers are allowed to work remotely for up to two days per week.","exampleKor":"연구원들은 일주일에 최대 이틀까지 원격으로 근무하는 것이 허용된다."}]},{"day":12,"title":"공장 자동화 (생산)","words":[{"word":"equipment","pos":"n.","meaning":"장비, 설비","example":"The company uses special equipment to load large crates onto freight trucks.","exampleKor":"그 회사는 큰 상자를 화물 트럭에 싣기 위해 특수 장비를 사용한다."},{"word":"automate","pos":"v.","meaning":"자동화하다","example":"The production plant will be fully automated by next year.","exampleKor":"그 생산 공장은 내년까지 완전히 자동화될 것이다."},{"word":"specification","pos":"n.","meaning":"명세서, 설명서, 사양","example":"The quality control team checks if all items meet product specifications.","exampleKor":"품질 관리팀은 모든 물품이 제품 명세서와 일치하는지를 확인한다."},{"word":"properly","pos":"adv.","meaning":"제대로, 정확하게","example":"Machinery must be well-maintained to operate properly.","exampleKor":"기계가 제대로 작동하려면 잘 관리되어야 한다."},{"word":"safety","pos":"n.","meaning":"안전","example":"Factory supervisors prioritize safety over speed.","exampleKor":"공장 관리자들은 속도보다 안전을 중시한다."},{"word":"precaution","pos":"n.","meaning":"예방 조치, 예방책","example":"After the accident, the company introduced stricter safety precautions.","exampleKor":"사고 후, 그 회사는 보다 엄격한 안전 예방 조치를 도입했다."},{"word":"operate","pos":"v.","meaning":"(기계 등이) 작동하다, 움직이다","example":"The assembly line operates round the clock.","exampleKor":"그 조립 라인은 24시간 내내 작동한다."},{"word":"processing","pos":"n.","meaning":"가공, 처리","example":"Food processing requires a clean environment.","exampleKor":"식품 가공은 청결한 환경을 필요로 한다."},{"word":"capacity","pos":"n.","meaning":"용량, 수용력; 역할","example":"The warehouse's capacity will double after the construction.","exampleKor":"공사 후 창고의 용량은 두 배로 증가할 것이다."},{"word":"assemble","pos":"v.","meaning":"(부품·기계 등을) 조립하다; (사람을) 모으다","example":"Components are manufactured abroad and assembled domestically.","exampleKor":"부품은 해외에서 제조되어 국내에서 조립된다."},{"word":"utilize","pos":"v.","meaning":"이용하다, 활용하다","example":"The technicians utilized computer technology to improve processes.","exampleKor":"기술자들은 공정을 개선하기 위해 컴퓨터 기술을 이용했다."},{"word":"place","pos":"v.","meaning":"~을 -한 상태에 두다; (지시·주문·신청 등을) 하다","example":"The factory supervisor has placed production operations on standby.","exampleKor":"공장 관리자는 생산 작업을 대기 상태로 두었다."},{"word":"fill","pos":"v.","meaning":"~을 채우다; (주문대로) 이행하다","example":"An attendant filled the car's tank with gas.","exampleKor":"한 직원이 자동차 연료 탱크를 휘발유로 채웠다."},{"word":"manufacturing","pos":"adj.","meaning":"제조(업)의","example":"The manufacturing process in the automotive industry has changed with computer advances.","exampleKor":"자동차 업계의 제조 공정은 컴퓨터의 발전과 함께 바뀌어 왔다."},{"word":"renovate","pos":"v.","meaning":"(낡은 건물·가구 등을) 개조하다, 수리하다, 보수하다","example":"The packaging area was renovated to use the space more effectively.","exampleKor":"포장 구역은 공간을 더 효과적으로 사용하기 위해 개조되었다."},{"word":"decision","pos":"n.","meaning":"결정, 판단","example":"The CEO's decision was to release the computer in February.","exampleKor":"그 최고 경영자의 결정은 2월에 컴퓨터를 출시하는 것이었다."},{"word":"material","pos":"n.","meaning":"재료, 물질","example":"The designers selected the material because of its durability.","exampleKor":"디자이너들은 내구성 때문에 그 재료를 선택했다."},{"word":"success","pos":"n.","meaning":"성공, 성과","example":"The company owes its success to strict quality control.","exampleKor":"그 회사는 엄격한 품질 관리 덕분에 성공한 것이다."},{"word":"attribute","pos":"v.","meaning":"(원인을) ~의 덕분으로 돌리다","example":"Management has attributed last year's gains to increased development.","exampleKor":"경영진은 작년의 성과를 늘어난 개발 덕분으로 돌렸다."},{"word":"efficiency","pos":"n.","meaning":"효율, 능률","example":"The consultant suggested measures to improve energy efficiency.","exampleKor":"그 고문은 에너지 효율을 개선하는 방안을 제안했다."},{"word":"limit","pos":"n.","meaning":"한계, 제한","example":"There is a limit to the amount of merchandise the factory can make in a day.","exampleKor":"그 공장이 하루에 생산할 수 있는 제품 수량에는 한계가 있다."},{"word":"tailored","pos":"adj.","meaning":"맞춤의, 주문에 따라 맞춘","example":"This equipment can be tailored to the company's production needs.","exampleKor":"이 장비는 업체의 생산 수요에 맞출 수 있다."},{"word":"component","pos":"n.","meaning":"부품, (구성) 요소","example":"The store returned the defective components to the manufacturer.","exampleKor":"그 상점은 결함이 있는 부품을 제조업체에 반환했다."},{"word":"capable","pos":"adj.","meaning":"~을 할 수 있는, ~할 능력이 있는","example":"Ferrum Corporation is capable of processing all kinds of metals.","exampleKor":"Ferrum사는 모든 종류의 금속을 가공할 수 있다."},{"word":"economize","pos":"v.","meaning":"절약하다, 아끼다","example":"Hybrid cars are becoming popular because they economize on fuel.","exampleKor":"하이브리드 차들은 연료를 절약하기 때문에 인기를 끌고 있다."},{"word":"flexible","pos":"adj.","meaning":"융통성 있는; 유연한, 잘 구부러지는","example":"Management is more flexible about granting vacations when business is slow.","exampleKor":"경영진은 회사가 바쁘지 않을 때 휴가를 승인하는 것에 대해 더 융통성 있다."},{"word":"comparable","pos":"adj.","meaning":"필적하는, 비교되는","example":"The car's quality standards are comparable to the industry average.","exampleKor":"그 차의 품질 규격은 업계 평균에 필적한다."},{"word":"produce","pos":"v.","meaning":"생산하다","example":"The new machinery produces 1,000 units per hour.","exampleKor":"새 기계는 시간당 천개의 제품을 생산한다."},{"word":"respectively","pos":"adv.","meaning":"각각, 따로","example":"The camera and tablet computer cost $225 and $350 respectively.","exampleKor":"카메라와 태블릿 컴퓨터는 각각 225달러와 350달러이다."},{"word":"device","pos":"n.","meaning":"장치","example":"The new device was tested for possible defects.","exampleKor":"새 장치는 결함이 있는지 검사되었다."},{"word":"trim","pos":"v.","meaning":"(깎아) 다듬다, 없애다; 삭감하다","example":"This mechanism trims the plastic packaging to make it smaller.","exampleKor":"이 기계 장치는 플라스틱 포장지를 다듬어서 더 작게 만든다."},{"word":"launch","pos":"v.","meaning":"(신제품을) 출시하다","example":"Computer programmers fix technical malfunctions before launching any software.","exampleKor":"컴퓨터 프로그래머들은 어떤 소프트웨어든 출시하기 전 기술적 결함을 수리한다."},{"word":"separately","pos":"adv.","meaning":"개별적으로, 따로따로","example":"The cushioning pads are made separately as each shoe is slightly different.","exampleKor":"각각의 신발이 약간씩 다르기 때문에 쿠션 깔개는 개별적으로 제작된다."},{"word":"expiration","pos":"n.","meaning":"(기간·임기 등의) 만료, 만기","example":"The expiration date is printed on the top of the milk carton.","exampleKor":"유효 기간은 우유 팩 상단에 인쇄되어 있다."},{"word":"maneuver","pos":"v.","meaning":"이동시키다, 움직이다","example":"Assembly line workers maneuvered the machinery into place.","exampleKor":"조립 라인 노동자들은 기계를 제자리로 이동시켰다."},{"word":"coming","pos":"adj.","meaning":"다가오는","example":"Factory output will double in the coming year.","exampleKor":"공장 생산량이 다가오는 해에는 두 배가 될 것이다."},{"word":"damaged","pos":"adj.","meaning":"손상된, 손해를 입은","example":"The conveyor belts were damaged from excessive use.","exampleKor":"과도한 사용으로 컨베이어 벨트가 손상되었다."},{"word":"prevent","pos":"v.","meaning":"~을 막다, ~을 예방하다","example":"Employees are expected to observe safety guidelines to prevent accidents.","exampleKor":"직원들은 사고를 막기 위해 안전 지침을 따라야 한다."},{"word":"power","pos":"n.","meaning":"전력, 전기","example":"The plant was closed for half a business day due to a power outage.","exampleKor":"그 공장은 정전으로 인해 반나절 간 휴업했다."},{"word":"chemical","pos":"n.","meaning":"화학 제품","example":"Protective gear is needed when working with dangerous chemicals.","exampleKor":"위험한 화학 제품을 가지고 작업할 때는 보호 장비가 필요하다."},{"word":"minimize","pos":"v.","meaning":"최소화하다, 축소하다","example":"To minimize employees' workload, the company upgraded its software.","exampleKor":"직원들의 업무량을 최소화하기 위해, 그 회사는 소프트웨어를 업그레이드했다."}]},{"day":13,"title":"고객은 왕 (고객서비스)","words":[{"word":"complaint","pos":"n.","meaning":"불평","example":"Customers can register complaints at the customer service center or online.","exampleKor":"고객들은 고객 서비스 센터나 온라인으로 불평을 신고할 수 있습니다."},{"word":"deal","pos":"v./n.","meaning":"처리하다; 거래하다; 분배하다; 거래","example":"The problem will be dealt with immediately.","exampleKor":"그 문제는 즉시 처리될 것이다."},{"word":"argumentative","pos":"adj.","meaning":"논쟁적인, 논쟁을 좋아하는","example":"Service personnel must avoid becoming argumentative with upset customers.","exampleKor":"서비스 직원들은 화난 손님들과 논쟁하는 것을 피해야 한다."},{"word":"appropriately","pos":"adv.","meaning":"적절하게","example":"Telephone representatives should know how to handle customer complaints appropriately.","exampleKor":"전화 상담원들은 고객의 불만을 적절하게 처리하는 법을 알아야 한다."},{"word":"respond","pos":"v.","meaning":"응답하다","example":"Sales staff should respond promptly to questions from customers.","exampleKor":"판매 사원들은 고객의 질문에 지체 없이 응답해야 한다."},{"word":"infuriate","pos":"v.","meaning":"화나게 하다, 격분시키다","example":"The attendant's incompetence infuriated the customer.","exampleKor":"그 안내원의 무능함은 고객을 화나게 했다."},{"word":"courteous","pos":"adj.","meaning":"예의 바른","example":"All inquiries must be handled in a courteous manner.","exampleKor":"모든 문의는 예의 바른 태도로 처리되어야 한다."},{"word":"satisfaction","pos":"n.","meaning":"만족","example":"We hope our assistance was to your satisfaction.","exampleKor":"저희 도움에 여러분께서 만족하셨기를 바랍니다."},{"word":"inconvenience","pos":"n./v.","meaning":"불편; ~에게 불편을 느끼게 하다","example":"We apologize for the inconvenience during construction.","exampleKor":"공사 중 불편을 드려 죄송합니다."},{"word":"complete","pos":"v./adj.","meaning":"완료하다, 완성하다; 완료된, 완성된","example":"The paperwork must be completed within one month.","exampleKor":"그 서류 작업은 한 달 안에 완료되어야 한다."},{"word":"specific","pos":"adj.","meaning":"구체적인, 명확한","example":"When seeking help online, clients must be very specific in describing problems.","exampleKor":"고객들은 온라인으로 도움을 요청할 때, 문제를 설명하는 데 있어 아주 구체적이어야 한다."},{"word":"return","pos":"v.","meaning":"반환하다, 반송하다; 돌아오다, 돌아가다","example":"Merchandise can be returned at the counter.","exampleKor":"상품은 계산대에서 반환하실 수 있습니다."},{"word":"replace","pos":"v.","meaning":"~을 교체하다, 대체하다","example":"The mechanic replaced the generator's motor with a new one.","exampleKor":"정비사가 발전기의 모터를 새것으로 교체했다."},{"word":"presentation","pos":"n.","meaning":"발표","example":"Melissa gave the employees a presentation about handling difficult clients.","exampleKor":"Melissa는 직원들에게 까다로운 고객들을 다루는 방법에 대해 발표했다."},{"word":"evaluation","pos":"n.","meaning":"평가","example":"Please fill out the evaluation form.","exampleKor":"평가서를 작성해 주십시오."},{"word":"confident","pos":"adj.","meaning":"확신하는, 자신 있는","example":"The manager is confident that Ms. Brown will be an excellent team leader.","exampleKor":"그 관리자는 Ms. Brown이 훌륭한 팀 리더가 될 것이라고 확신한다."},{"word":"cause","pos":"v./n.","meaning":"~을 야기하다, ~의 원인이 되다; 원인","example":"The defect in the lamp was caused by improper wiring.","exampleKor":"전등의 결함은 잘못된 배선에 의해 야기되었다."},{"word":"commentary","pos":"n.","meaning":"해설, 설명","example":"Richard added commentary to the service training film.","exampleKor":"Richard는 서비스 교육 영상에 해설을 덧붙였다."},{"word":"notification","pos":"n.","meaning":"통지","example":"We require written notification of any order cancellations.","exampleKor":"저희는 모든 주문 취소에 대한 서면 통지를 요구합니다."},{"word":"apologize","pos":"v.","meaning":"사과하다","example":"We apologize for the late delivery service.","exampleKor":"늦은 배송 서비스에 대해 사과 드립니다."},{"word":"interact","pos":"v.","meaning":"소통하다, 교류하다; 상호 작용을 하다","example":"When interacting with shoppers, clerks should deal with them in a pleasant manner.","exampleKor":"쇼핑객들과 소통할 때, 점원들은 유쾌한 태도로 그들을 대해야 한다."},{"word":"certain","pos":"adj.","meaning":"확신하는, 확실한; 특정한","example":"Sharon was not certain where she had bought the blouse.","exampleKor":"Sharon은 그 블라우스를 어디서 샀는지 확신하지 못했다."},{"word":"commitment","pos":"n.","meaning":"헌신, 전념","example":"Brand Bank has a longstanding commitment to providing excellent client assistance.","exampleKor":"Brand 은행은 뛰어난 고객 지원을 제공하는 데 오랫동안 헌신해 왔다."},{"word":"applaud","pos":"v.","meaning":"~에게 박수를 보내다; 칭찬하다","example":"The staff applauded management's decision to increase overtime pay.","exampleKor":"직원들은 초과 근무 수당을 인상하기로 한 경영진의 결정에 박수를 보냈다."},{"word":"biography","pos":"n.","meaning":"약력, 전기","example":"A short biography on the guest speaker was included in the program.","exampleKor":"초청 연사의 간단한 약력이 진행표에 포함되어 있었다."},{"word":"critical","pos":"adj.","meaning":"비판적인; 중요한; 위기의","example":"Many customers were critical of the new services.","exampleKor":"많은 고객들이 새로운 서비스에 대해 비판적이었다."},{"word":"depend on","pos":"phr.","meaning":"~에 달려 있다, ~에게 의존하다","example":"The success of a restaurant depends on the quality of the food and the customer service.","exampleKor":"식당의 성공은 음식과 고객 서비스의 질에 달려 있다."},{"word":"combine","pos":"v.","meaning":"결합시키다","example":"The store sometimes allows customers to combine two special offers.","exampleKor":"그 가게는 가끔 고객들이 두 가지의 특가 혜택을 결합시키는 것을 허용한다."},{"word":"priority","pos":"n.","meaning":"우선권, 우선 사항","example":"Priority for the service will be provided according to a first come, first served basis.","exampleKor":"그 서비스에 대한 우선권은 선착순으로 제공될 것이다."},{"word":"observe","pos":"v.","meaning":"관찰하다, 주시하다; (규칙 등을) 준수하다, 지키다","example":"The technicians observed a demonstration about repairing phones.","exampleKor":"기술자들은 전화기 수리에 대한 시연을 관찰했다."},{"word":"defective","pos":"adj.","meaning":"결함이 있는","example":"The buyer requested a refund for the defective hair dryer.","exampleKor":"그 구매자는 결함이 있는 헤어드라이어에 대해 환불을 요청했다."},{"word":"reflect","pos":"v.","meaning":"반영하다, 나타내다","example":"Kimdale Corporation's statement of purpose reflects its commitment to quality.","exampleKor":"Kimdale사의 강령은 품질에 대한 회사의 헌신을 반영한다."},{"word":"attitude","pos":"n.","meaning":"태도, 마음가짐","example":"Salespeople with a positive attitude tend to sell more products.","exampleKor":"긍정적인 태도를 가진 판매원들이 더 많은 제품을 파는 경향이 있다."},{"word":"disappoint","pos":"v.","meaning":"실망시키다","example":"The poor terms of the computer warranty disappointed many buyers.","exampleKor":"그 컴퓨터 보증서의 부실한 조항이 많은 구매자를 실망시켰다."},{"word":"inquire","pos":"v.","meaning":"문의하다, 질문하다","example":"Several people called in to inquire about the store's latest promotions.","exampleKor":"여러 사람이 상점의 최신 판촉 상품에 대해 문의하려고 전화했다."},{"word":"insert","pos":"v.","meaning":"삽입하다","example":"Please read all the instructions before inserting the CD into your computer.","exampleKor":"CD를 컴퓨터에 삽입하기 전에 설명서를 모두 읽어 보시기 바랍니다."},{"word":"disclose","pos":"v.","meaning":"공개하다, 드러내다","example":"Customers will be asked to disclose some personal details when ordering online.","exampleKor":"고객들은 온라인으로 주문 시 몇몇 개인 정보를 공개할 것을 요청받을 것이다."},{"word":"guarantee","pos":"v./n.","meaning":"보장하다; 보장","example":"Customer satisfaction is guaranteed.","exampleKor":"고객 만족이 보장됩니다."},{"word":"politely","pos":"adv.","meaning":"공손하게, 예의 바르게","example":"Store personnel must always speak to customers politely.","exampleKor":"상점 직원은 고객에게 항상 공손하게 말해야 한다."},{"word":"seriously","pos":"adv.","meaning":"진지하게","example":"The manager takes customer feedback very seriously.","exampleKor":"그 관리자는 고객의 의견을 아주 진지하게 받아들인다."}]},{"day":14,"title":"출장의 목적 (여행·공항)","words":[{"word":"international","pos":"adj.","meaning":"국제적인","example":"Passengers for international flights check in at counter three.","exampleKor":"국제선 승객들은 3번 카운터에서 탑승 수속을 한다."},{"word":"attraction","pos":"n.","meaning":"관광 명소","example":"This bus takes visitors to the city's best tourist attractions.","exampleKor":"이 버스는 방문객들을 도시 최고의 관광 명소로 데려간다."},{"word":"itinerary","pos":"n.","meaning":"여행 일정","example":"The itinerary includes a visit to Boston.","exampleKor":"여행 일정에는 보스턴 방문이 포함되어 있다."},{"word":"exotic","pos":"adj.","meaning":"이국적인, 매혹적인","example":"Our Web site contains information on numerous exotic vacation spots.","exampleKor":"저희 웹사이트에는 많은 이국적 휴양지들에 대한 정보가 담겨 있습니다."},{"word":"diverse","pos":"adj.","meaning":"다양한","example":"A diverse selection of tours is available for London.","exampleKor":"런던에서는 다양한 관광을 이용할 수 있다."},{"word":"superb","pos":"adj.","meaning":"최고의, 뛰어난","example":"The service at the hotel was superb.","exampleKor":"그 호텔의 서비스는 최고였다."},{"word":"baggage","pos":"n.","meaning":"수화물","example":"Stow baggage under the seat in front of you.","exampleKor":"수화물은 앞 좌석 밑에 보관하십시오."},{"word":"destination","pos":"n.","meaning":"목적지","example":"Travel agents can provide information about a travel destination.","exampleKor":"여행사 직원들은 여행 목적지에 대한 정보를 제공해 줄 수 있다."},{"word":"missing","pos":"adj.","meaning":"분실된, 없어진","example":"The missing luggage will be sent to the hotel when it is found.","exampleKor":"분실된 짐은 발견 시 호텔로 보내질 것입니다."},{"word":"locate","pos":"v.","meaning":"(~의 위치를) 찾아내다; ~을 위치시키다","example":"Airline staff have tried to locate the lost luggage.","exampleKor":"항공사 직원들은 잃어버린 짐을 찾으려 노력했다."},{"word":"approximately","pos":"adv.","meaning":"대략","example":"A nonstop flight takes approximately 13 hours.","exampleKor":"직항은 대략 13시간이 걸린다."},{"word":"duty","pos":"n.","meaning":"관세, 세금; 직무, 의무","example":"Passengers must pay duty on goods worth more than $500.","exampleKor":"승객들은 500달러 이상의 물품에 대해 관세를 지불해야 한다."},{"word":"process","pos":"n./v.","meaning":"과정; 처리하다","example":"The entire airline ticketing process can be done online.","exampleKor":"모든 항공권 예약 과정은 온라인으로 처리될 수 있다."},{"word":"board","pos":"v./n.","meaning":"탑승하다; 이사회","example":"Business class passengers were invited to board the plane first.","exampleKor":"비즈니스석 승객들이 먼저 비행기에 탑승하도록 권유받았다."},{"word":"comfortable","pos":"adj.","meaning":"편안한","example":"The beds in this hotel are very comfortable.","exampleKor":"이 호텔의 침대들은 아주 편안하다."},{"word":"declare","pos":"v.","meaning":"(세관에서) 신고하다","example":"Goods subject to import fees must be declared.","exampleKor":"수입세를 적용받는 물품들은 반드시 신고해야 합니다."},{"word":"specify","pos":"v.","meaning":"명시하다","example":"Travelers can specify on the form which cities they would like to visit.","exampleKor":"여행객들은 어느 도시를 방문하고 싶은지 양식에 명시할 수 있다."},{"word":"depart","pos":"v.","meaning":"출발하다","example":"Flight QF302 to Sydney departs from London Heathrow airport at 10:45 P.M.","exampleKor":"시드니행 QF302편은 오후 10시 45분에 런던 Heathrow 공항에서 출발합니다."},{"word":"emergency","pos":"n.","meaning":"비상시, 비상사태","example":"In case of emergency, oxygen masks will automatically drop from above.","exampleKor":"비상시에는 산소마스크가 위에서 자동으로 떨어질 것입니다."},{"word":"passenger","pos":"n.","meaning":"승객","example":"Passengers boarding the cruise ship were welcomed by the captain.","exampleKor":"크루즈 선박에 탑승한 승객들은 선장의 환영을 받았다."},{"word":"outgoing","pos":"adj.","meaning":"(장소를) 출발하는, 떠나는; (지위를) 떠나는","example":"Outgoing trains leave from platforms three to five.","exampleKor":"출발하는 기차들은 3번에서 5번 승강장에서 떠납니다."},{"word":"tightly","pos":"adv.","meaning":"단단히, 꽉","example":"Please ensure your hotel room door is locked tightly.","exampleKor":"호텔 객실 문이 단단히 잠겼는지 확인하시기 바랍니다."},{"word":"tour","pos":"n.","meaning":"(공장·시설 등의) 견학, 짧은 여행","example":"The guide gave us a tour of the manufacturing plant.","exampleKor":"가이드는 우리에게 제조 공장을 견학시켜 주었다."},{"word":"carrier","pos":"n.","meaning":"항공사, 수송기, 수송 회사","example":"Flyway Airlines is a popular carrier among travelers because it is inexpensive.","exampleKor":"Flyway Airlines는 저렴하기 때문에 여행객들 사이에서 인기 있는 항공사이다."},{"word":"customarily","pos":"adv.","meaning":"관례상, 습관적으로","example":"Italians customarily greet one another with a kiss on the cheek.","exampleKor":"이탈리아 사람들은 관례상 볼에 입을 맞추며 서로 인사한다."},{"word":"confuse","pos":"v.","meaning":"혼란시키다","example":"The building's lack of signs confused visitors.","exampleKor":"그 건물은 표지판이 부족해서 방문객들을 혼란시켰다."},{"word":"arrive","pos":"v.","meaning":"도착하다","example":"The tour bus will arrive at its destination on time.","exampleKor":"그 관광버스는 정시에 목적지에 도착할 것입니다."},{"word":"brochure","pos":"n.","meaning":"(홍보용) 소책자, 브로셔","example":"Pick up a sightseeing brochure at the information center.","exampleKor":"안내소에서 관광 소책자를 가져가세요."},{"word":"involve","pos":"v.","meaning":"수반하다, 포함하다; 참여시키다","example":"Getting to Kelford by bus involves one transfer.","exampleKor":"버스를 타고 Kelford로 가는 것은 한 번의 환승을 수반한다."},{"word":"ship","pos":"v./n.","meaning":"(배나 다른 운송 수단으로) 운송하다, 수송하다; 선박, 배","example":"The company's fleet ships cargo internationally.","exampleKor":"그 회사가 보유한 모든 선박이 화물을 국제적으로 운송한다."},{"word":"suitcase","pos":"n.","meaning":"여행 가방","example":"Each person is allowed to check in one suitcase.","exampleKor":"일 인당 한 개의 여행 가방을 부치는 것이 허용된다."},{"word":"unavailable","pos":"adj.","meaning":"이용할 수 없는, 구할 수 없는","example":"The luxury suite is currently unavailable.","exampleKor":"고급 스위트룸은 현재 이용할 수 없습니다."},{"word":"fill out/in","pos":"phr.","meaning":"(서류에) 기입하다, 적어 넣다","example":"Please fill out the form prior to landing.","exampleKor":"착륙하기 전에 서식에 기입해 주세요."},{"word":"customs","pos":"n.","meaning":"세관","example":"Hundreds of passengers go through customs every hour.","exampleKor":"매시간 수백 명의 승객들이 세관을 통과한다."},{"word":"away","pos":"adv.","meaning":"떨어져서","example":"The city hall is located about fifteen miles away from the convention center.","exampleKor":"시청은 컨벤션 센터로부터 약 15마일 떨어져 있다."},{"word":"dramatic","pos":"adj.","meaning":"멋진, 극적인; 급격한","example":"This tour includes admiring the country's most dramatic scenery.","exampleKor":"이 여행은 그 나라의 가장 멋진 경치를 즐기는 것을 포함합니다."},{"word":"hospitality","pos":"n.","meaning":"환대, 친절","example":"The guests appreciated the hospitality extended to them during their stay.","exampleKor":"손님들은 숙박하는 동안 받은 환대에 대해 고맙게 생각했다."},{"word":"indulge","pos":"v.","meaning":"빠지다, 탐닉하다","example":"Indulge in a getaway to the jungles and reefs of Belize.","exampleKor":"벨리즈의 정글과 산호초로의 휴가에 빠져 보십시오."},{"word":"proximity","pos":"n.","meaning":"가까움, 근접함","example":"The conference center is in close proximity to the hotel.","exampleKor":"그 회의장은 호텔에 아주 근접해 있다."},{"word":"seating","pos":"n.","meaning":"(집합적) 좌석 설비; 좌석 배열","example":"The seating capacity of this airplane is 250 passengers.","exampleKor":"이 비행기의 좌석 정원은 승객 250명이다."},{"word":"unlimited","pos":"adj.","meaning":"무제한의","example":"Unlimited mileage is included with all our car rental quotes.","exampleKor":"자사의 모든 차량 렌탈 견적에는 무제한 마일리지가 포함되어 있습니다."},{"word":"simply","pos":"adv.","meaning":"그저, 단지, 간단히","example":"To update your delivery address, simply reply to this e-mail.","exampleKor":"당신의 배송 주소를 갱신하려면, 그저 이 이메일에 답장만 하면 됩니다."},{"word":"besides","pos":"adv./prep.","meaning":"게다가, 뿐만 아니라; ~ 외에","example":"This hotel has the best reviews. Besides, it has a swimming pool.","exampleKor":"그 호텔은 평이 가장 좋은 데다가 수영장도 있다."},{"word":"traditionally","pos":"adv.","meaning":"전통적으로","example":"The festival is traditionally held every February on the Italian island of Sardinia.","exampleKor":"그 축제는 전통적으로 매년 2월에 이탈리아의 사르디니아 섬에서 열린다."}]},{"day":15,"title":"협상의 귀재 (계약)","words":[{"word":"proposal","pos":"n.","meaning":"제안, 계획","example":"Ms. Chryssom liked the proposal so much that she decided to invest immediately.","exampleKor":"Ms. Chryssom은 그 제안이 매우 마음에 들어서 즉시 투자하기로 결정했다."},{"word":"alliance","pos":"n.","meaning":"동맹, 제휴","example":"The corporations formed an alliance to protect themselves from competitors.","exampleKor":"그 기업들은 경쟁사로부터 스스로를 보호하기 위해 동맹을 맺었다."},{"word":"stipulation","pos":"n.","meaning":"계약 조건","example":"One of the stipulations was that the goods must be insured.","exampleKor":"계약 조건 중 하나는 상품이 보험에 가입되어 있어야 한다는 것이었다."},{"word":"term","pos":"n.","meaning":"조건; 임기, 기한","example":"We cannot agree to the terms offered.","exampleKor":"우리는 제시된 조건에 동의할 수 없습니다."},{"word":"compromise","pos":"n.","meaning":"타협, 화해","example":"The contractors and management finally reached a compromise following several talks.","exampleKor":"수차례의 협의 끝에 하청업체들과 경영진은 마침내 타협에 이르게 되었다."},{"word":"negotiation","pos":"n.","meaning":"협상, 교섭","example":"Negotiations are now in process.","exampleKor":"협상이 현재 진행 중이다."},{"word":"agreement","pos":"n.","meaning":"계약, 협정; 합의","example":"The agreement has been signed by both parties.","exampleKor":"계약은 양측 모두에 의해 서명되었다."},{"word":"deadlock","pos":"n.","meaning":"교착 상태","example":"Friday's negotiations ended in a deadlock.","exampleKor":"금요일 자 협상은 교착 상태에 빠졌다."},{"word":"review","pos":"v.","meaning":"검토하다, 재조사하다","example":"Please review all of the documents carefully.","exampleKor":"모든 서류를 주의 깊게 검토하시기 바랍니다."},{"word":"contract","pos":"n./v.","meaning":"계약(서); 계약하다, 수축하다","example":"The law requires all participants in the transaction to sign a contract.","exampleKor":"법에 따라 거래의 모든 관계자들이 계약서에 서명해야 한다."},{"word":"signature","pos":"n.","meaning":"서명","example":"The CEO's signature finalized the long-awaited deal.","exampleKor":"최고 경영자의 서명이 오랫동안 기다려 온 거래를 마무리 지었다."},{"word":"originally","pos":"adv.","meaning":"원래, 처음에는","example":"The company wants to change the conditions originally agreed upon.","exampleKor":"그 회사는 원래 합의되었던 조건을 변경하고 싶어 한다."},{"word":"direction","pos":"n.","meaning":"방향, 지시, 감독","example":"Hoping for a settlement, lawyers led the discussion in a different direction.","exampleKor":"합의를 기대하며, 변호사들은 논의를 다른 방향으로 이끌었다."},{"word":"initially","pos":"adv.","meaning":"처음에, 초기에","example":"Managers initially thought the legal issues would be resolved quickly.","exampleKor":"관리자들은 법적 문제들이 빠르게 해결될 것이라고 처음에 생각했다."},{"word":"expire","pos":"v.","meaning":"(계약 등이) 만료되다","example":"The previous lease expired a few weeks ago.","exampleKor":"이전 임대차 계약이 몇 주 전에 만료되었다."},{"word":"collaborate","pos":"v.","meaning":"협력하다, 공동으로 일하다","example":"Moksel Company and Boston University collaborated on the research project.","exampleKor":"Moksel사와 Boston 대학은 그 연구 프로젝트에 대해 협력했다."},{"word":"dedicate","pos":"v.","meaning":"전념하다, 헌신하다, 바치다","example":"Ms. Barton dedicates herself to ensuring clients get good deals.","exampleKor":"Ms. Barton은 고객들이 좋은 거래를 하도록 보장하는 데 전념한다."},{"word":"revised","pos":"adj.","meaning":"수정된, 변경한","example":"The company president accepted the revised project proposal.","exampleKor":"그 회사 회장은 수정된 사업 기획안을 받아들였다."},{"word":"imperative","pos":"adj.","meaning":"반드시 해야 하는, 필수적인","example":"It is imperative that the agreement be fully honored.","exampleKor":"계약은 반드시 철저히 이행되어야 한다."},{"word":"cooperatively","pos":"adv.","meaning":"협력하여, 협조적으로","example":"The company worked cooperatively with Pacific Corporation to build the railway.","exampleKor":"그 회사는 철로를 짓기 위해 Pacific사와 협력하여 일했다."},{"word":"commission","pos":"n./v.","meaning":"수수료, 커미션; 위원회; (일 등을) 의뢰하다, 주문하다","example":"The new recruit consented to work on commission.","exampleKor":"그 신입 사원은 수수료를 받고 일하는 데 동의했다."},{"word":"omit","pos":"v.","meaning":"빠트리다, 생략하다","example":"Grace rewrote the draft to include details omitted from the original.","exampleKor":"Grace는 초안에서 빠트린 세부 사항들을 포함하기 위해 계약서를 다시 작성했다."},{"word":"conflict","pos":"n.","meaning":"대립, 충돌, 갈등","example":"The executives had a conflict over when to expand the business internationally.","exampleKor":"경영진은 언제 해외로 사업을 확장할지를 두고 대립했다."},{"word":"renew","pos":"v.","meaning":"(계약 등을) 갱신하다","example":"The retail company renewed the six-month contract after discussions.","exampleKor":"그 소매업체는 논의 끝에 6개월 계약을 갱신했다."},{"word":"proficient","pos":"adj.","meaning":"능숙한, 능한","example":"David is proficient in several languages, which helps with international negotiations.","exampleKor":"David는 몇 가지 언어에 능숙한데, 이는 국제 협상에 도움이 된다."},{"word":"confidentiality","pos":"n.","meaning":"기밀, 비밀","example":"Study subjects had to sign a confidentiality agreement before participating.","exampleKor":"연구의 피험자들은 참여하기 전 기밀 유지 합의서에 서명해야 했다."},{"word":"dispute","pos":"n.","meaning":"분쟁, 논쟁","example":"The dispute over the copyright prompted court action.","exampleKor":"저작권에 관한 분쟁은 법정 투쟁을 일으켰다."},{"word":"objection","pos":"n.","meaning":"반대, 이의","example":"The deal proceeded despite the board of directors' objections.","exampleKor":"이사회의 반대에도 불구하고 그 거래는 진행되었다."},{"word":"define","pos":"v.","meaning":"규정하다, 정의하다","example":"The contract defined the roles of all parties involved.","exampleKor":"계약서에는 관련된 모든 당사자의 역할이 규정되어 있다."},{"word":"impression","pos":"n.","meaning":"인상","example":"The representative's presentation gave the impression that his company is well-organized.","exampleKor":"그 대표의 발표는 그의 회사가 잘 조직되어 있다는 인상을 주었다."},{"word":"security","pos":"n.","meaning":"보안, 안전, 보호","example":"Security is a priority during next week's sensitive negotiation meetings.","exampleKor":"다음 주 민감한 협상 회담 동안은 보안이 우선이다."},{"word":"option","pos":"n.","meaning":"선택권","example":"The agreement provides Banister with the option to discuss rate adjustments after one year.","exampleKor":"그 계약은 Banister사에 1년 후 요금 조정을 논의할 수 있는 선택권을 준다."},{"word":"proceed","pos":"v.","meaning":"(일을) 진행하다, 진척되다","example":"Talks concerning the companies' merger are proceeding well.","exampleKor":"그 회사들의 합병에 관한 회담이 순조로이 진행되고 있다."},{"word":"modify","pos":"v.","meaning":"수정하다, 일부 변경하다","example":"The parties agreed to modify the wording of some clauses.","exampleKor":"당사자들은 몇몇 조항의 표현을 수정하는 데 동의했다."},{"word":"narrow","pos":"v.","meaning":"(범위 등을) 좁히다","example":"The number of potential building sites has been narrowed down to three.","exampleKor":"잠재적인 건축 부지 수가 세 개로 좁혀졌다."},{"word":"bid","pos":"n.","meaning":"입찰","example":"The construction firm Martin & Sons put in a bid for the contract.","exampleKor":"Martin & Sons 건설 회사는 그 계약에 입찰했다."},{"word":"settle","pos":"v.","meaning":"해결하다, 처리하다","example":"The management made attempts to settle the unfair dismissal case.","exampleKor":"경영진은 불공정한 해고 건을 해결하기 위해 노력했다."},{"word":"terminate","pos":"v.","meaning":"끝내다, 종결시키다","example":"The company terminated the agreement when the project wasn't completed.","exampleKor":"그 회사는 프로젝트가 완료되지 않자 계약을 끝냈다."},{"word":"challenging","pos":"adj.","meaning":"도전적인, 힘든","example":"Renovating the new wing proved to be a challenging project.","exampleKor":"새 별관을 개조하는 것은 어려운 프로젝트로 판명되었다."},{"word":"foundation","pos":"n.","meaning":"토대, 기초","example":"The proposal served as the foundation on which the agreement was concluded.","exampleKor":"그 제안은 계약이 체결되는 토대로 작용했다."},{"word":"pending","pos":"adj.","meaning":"미결인, 미정인; 임박한","example":"The pending order from the factory was delayed again.","exampleKor":"공장의 미결인 주문이 다시 지연되었다."}]},{"day":16,"title":"무역 협정 (상거래)","words":[{"word":"completely","pos":"adv.","meaning":"전적으로, 완전히","example":"Every product in our catalog is completely guaranteed.","exampleKor":"우리 카탈로그상의 모든 제품들은 전적으로 보증됩니다."},{"word":"refuse","pos":"v.","meaning":"거절하다","example":"The shipment was refused by the purchaser due to damage caused in transit.","exampleKor":"그 선적품은 운송 중에 생긴 파손 때문에 구매자로부터 거절당했다."},{"word":"temporarily","pos":"adv.","meaning":"일시적으로","example":"The popular video game is temporarily out of stock in stores, but may be bought online.","exampleKor":"그 인기 있는 비디오 게임은 매장에서 일시적으로 품절이지만, 온라인으로는 구입할 수 있다."},{"word":"dealer","pos":"n.","meaning":"판매업자, 상인","example":"Imported vehicles are sold only by licensed car dealers.","exampleKor":"수입 차량은 허가를 받은 차량 판매업자에 의해서만 판매된다."},{"word":"bulk","pos":"adj.","meaning":"대량의","example":"Many factories offer a modest discount for bulk orders.","exampleKor":"많은 공장들이 대량 주문에 대해 적당한 할인을 제공한다."},{"word":"inventory","pos":"n.","meaning":"재고품, 재고 목록","example":"The inventory in the warehouse is checked at regular intervals.","exampleKor":"창고에 있는 재고품은 정기적으로 점검된다."},{"word":"short","pos":"adj.","meaning":"부족한","example":"The plant is running short on its supply of raw materials.","exampleKor":"그 공장은 원자재의 공급이 부족해지고 있다."},{"word":"cost","pos":"n./v.","meaning":"비용; (비용)이 들다","example":"Singapore is known for its high cost of living.","exampleKor":"싱가포르는 높은 생활비로 알려져 있다."},{"word":"selection","pos":"n.","meaning":"선택된 것, 정선품","example":"Our Web site boasts a wide selection of gift items.","exampleKor":"저희 웹사이트는 다양하게 정선된 선물용 상품들을 자랑합니다."},{"word":"commercial","pos":"adj./n.","meaning":"상업의, 상업적인; 광고","example":"Some commercial products may be subject to import taxes.","exampleKor":"몇몇 상업 제품들은 수입 세금 적용의 대상이 될 수도 있다."},{"word":"order","pos":"v./n.","meaning":"주문하다; 주문, 주문품","example":"The secretary ordered supplies from the main office.","exampleKor":"그 비서는 본사로부터 비품을 주문했다."},{"word":"provide","pos":"v.","meaning":"공급하다, 제공하다","example":"We provide customers with detailed product lists by e-mail.","exampleKor":"저희는 고객들에게 상세한 제품 목록을 이메일로 공급해 드립니다."},{"word":"contact","pos":"v./n.","meaning":"~와 연락하다; (상업적 목적으로) 교섭하고 있는 사람","example":"Contact the supplier to request express delivery.","exampleKor":"특급 배달을 요청하시려면 공급업체와 연락하세요."},{"word":"invoice","pos":"n.","meaning":"송장","example":"The manufacturer sent an invoice for the production costs.","exampleKor":"그 제조업체는 생산비에 대한 송장을 보냈다."},{"word":"move","pos":"v./n.","meaning":"옮기다, 움직이다; 조치, 수단; 이동, 이사","example":"Panther Corporation moved its Asian headquarters to China.","exampleKor":"Panther사는 아시아 본사를 중국으로 옮겼다."},{"word":"supply","pos":"v./n.","meaning":"공급하다; 공급, (-s)비품, 소모품","example":"NovaTech supplies its customers with the latest network equipment.","exampleKor":"NovaTech사는 고객들에게 최신 네트워크 장비를 공급한다."},{"word":"discount","pos":"n.","meaning":"할인","example":"Repeat clients are eligible for a 30 percent discount on all items.","exampleKor":"단골 고객들은 모든 품목에 대해 30퍼센트 할인을 받을 자격이 있다."},{"word":"distribute","pos":"v.","meaning":"배포하다, 배급하다","example":"The goods were distributed to local businesses.","exampleKor":"상품이 현지 사업체들에 배포되었다."},{"word":"acquisition","pos":"n.","meaning":"인수; 구입한 것","example":"Companies can grow quickly through the acquisition of other businesses.","exampleKor":"회사들은 다른 사업체의 인수를 통해 빨리 성장할 수 있다."},{"word":"assure","pos":"v.","meaning":"~에게 보장하다, ~을 안심시키다, 장담하다","example":"RapidFleet assures customers that all purchases are delivered promptly.","exampleKor":"RapidFleet사는 고객들에게 모든 구입품이 신속하게 배송될 것을 보장한다."},{"word":"subject","pos":"adj./v./n.","meaning":"~의 영향을 받기 쉬운; (동의 등을) 조건으로 하는; ~에게 (~을) 받게 하다; 주제, 문제","example":"Prices are subject to change without advance notice.","exampleKor":"가격은 사전 통보 없이 바뀔 수 있습니다."},{"word":"seek","pos":"v.","meaning":"구하다, 찾다","example":"Fenway Bank is seeking a new manager for its Phoenix branch.","exampleKor":"Fenway 은행은 피닉스 지점의 새로운 지점장을 구하고 있다."},{"word":"satisfactory","pos":"adj.","meaning":"만족스러운","example":"Customers expect satisfactory responses to their demands.","exampleKor":"고객들은 자신들의 요구에 대해 만족스러운 반응을 기대한다."},{"word":"confirmation","pos":"n.","meaning":"확인, 확증","example":"Please submit written confirmation of the subscription cancellation.","exampleKor":"구독 취소에 대한 서면 확인서를 제출해 주세요."},{"word":"unable","pos":"adj.","meaning":"~할 수 없는","example":"The hotel is unable to take any more reservations as it is overbooked.","exampleKor":"그 호텔은 초과 예약되어서 더 이상 예약을 받을 수 없다."},{"word":"payment","pos":"n.","meaning":"지불 (금액), 납입 (금액)","example":"Once payment has been received, the books will be delivered.","exampleKor":"일단 지불 금액을 받으면, 책들이 배달될 것입니다."},{"word":"measure","pos":"n./v.","meaning":"대책, 조치, 수단; 측정하다","example":"The safety measures are in place to protect factory workers.","exampleKor":"안전 대책은 공장 직원들을 보호하기 위해서 마련되어 있다."},{"word":"bargain","pos":"n.","meaning":"특가품, 흥정","example":"Stores offer many great bargains at the end of the year.","exampleKor":"상점들은 연말에 좋은 특가품들을 많이 제공한다."},{"word":"stock","pos":"n./v.","meaning":"재고; 주식; 저장하다","example":"This particular model is currently out of stock.","exampleKor":"이 특정 모델은 현재 품절되었다."},{"word":"affordability","pos":"n.","meaning":"감당할 수 있는 비용","example":"Consumers are most concerned about the affordability of groceries.","exampleKor":"소비자들은 식료품이 감당할 수 있는 비용인지에 대해 가장 걱정한다."},{"word":"clientele","pos":"n.","meaning":"(집합적) 고객들, (변호사·건축가 등의) 모든 의뢰인","example":"The wealthiest clientele usually shops in luxury stores.","exampleKor":"가장 부유한 고객들은 보통 명품 매장에서 쇼핑한다."},{"word":"acclaim","pos":"n.","meaning":"호평, 찬사","example":"Ms. Song's novel won critical acclaim, and a studio soon purchased the movie rights.","exampleKor":"Ms. Song의 소설은 비평가들의 호평을 얻었고, 한 영화사에서 곧 영화 판권을 구입했다."},{"word":"represent","pos":"v.","meaning":"~을 대표하다","example":"Rounders Properties is looking for an agent to represent the firm in Europe.","exampleKor":"Rounders Properties사는 유럽에서 회사를 대표할 대리인을 찾고 있다."},{"word":"rating","pos":"n.","meaning":"등급, 평가","example":"The Coolmax air conditioner has the highest energy efficiency rating.","exampleKor":"Coolmax 에어컨은 가장 높은 에너지 효율 등급을 받았다."},{"word":"encompass","pos":"v.","meaning":"포함하다, 둘러싸다","example":"Techtronic's product range encompasses all kinds of electrical goods.","exampleKor":"Techtronic사의 상품은 모든 종류의 전자 제품을 포함한다."},{"word":"finalize","pos":"v.","meaning":"마무리 짓다, 완결하다","example":"Once Bertram Inc. finalizes the contract, they will begin manufacturing the products.","exampleKor":"Bertram사가 계약을 마무리 지으면, 제품 생산을 시작할 것이다."},{"word":"market","pos":"n./v.","meaning":"시장; (상품을) 시장에 내놓다","example":"Joyful-Cleanse is the best dish detergent on the market.","exampleKor":"Joyful-Cleanse는 시장에 나와 있는 가장 좋은 설거지 세제이다."},{"word":"retail","pos":"n.","meaning":"소매","example":"Online shops are more popular than most retail stores nowadays.","exampleKor":"온라인 쇼핑몰들은 요즘 대부분의 소매점들보다 더 인기 있다."},{"word":"commodity","pos":"n.","meaning":"상품, 산물","example":"Export opportunities are opening up in the agricultural commodities sector.","exampleKor":"농산품 부문에서의 수출 기회가 열리고 있다."},{"word":"quote","pos":"n./v.","meaning":"견적(액); 견적을 내다","example":"The customer requested a price quote on the merchandise.","exampleKor":"고객은 그 상품에 대한 가격 견적을 요구했다."},{"word":"consignment","pos":"n.","meaning":"위탁 판매","example":"The dealer only sells on consignment.","exampleKor":"그 판매업자는 위탁 판매만 한다."}]},{"day":17,"title":"특급배송 (무역·배송)","words":[{"word":"fragile","pos":"adj.","meaning":"깨지기 쉬운","example":"Fragile items are wrapped in protective packaging.","exampleKor":"깨지기 쉬운 물품들은 보호용 포장재에 포장되어 있다."},{"word":"perishable","pos":"adj.","meaning":"부패하기 쉬운","example":"Perishable goods are shipped in insulated containers.","exampleKor":"부패하기 쉬운 제품들은 단열 컨테이너에 담겨 수송된다."},{"word":"deliver","pos":"v.","meaning":"배달하다; (연설을) 하다","example":"All packages are delivered by the next morning.","exampleKor":"모든 소포들은 다음 날 아침까지 배달된다."},{"word":"ensure","pos":"v.","meaning":"확실하게 하다, 보장하다","example":"The receptionist called to ensure the message was delivered.","exampleKor":"메시지가 전달되었는지 확실히 하기 위해 접수원이 전화했다."},{"word":"courier","pos":"n.","meaning":"급송 택배","example":"The customer will send the package by courier.","exampleKor":"그 고객은 소포를 급송 택배로 보낼 것이다."},{"word":"carton","pos":"n.","meaning":"(큰) 판지 상자","example":"The carton of goods was shipped by sea.","exampleKor":"물품을 담은 판지 상자가 배편으로 수송되었다."},{"word":"address","pos":"n./v.","meaning":"주소; (어려운 문제 등을) 처리하다, 다루다","example":"The address is stored in our database.","exampleKor":"그 주소는 우리 데이터베이스에 저장되어 있다."},{"word":"shipment","pos":"n.","meaning":"선적, (화물의) 발송; 수송품, 적하물","example":"Freightline specializes in the shipment of food products.","exampleKor":"Freightline사는 식료품 선적을 전문으로 한다."},{"word":"particularly","pos":"adv.","meaning":"특히","example":"The new trade agreement will hurt local business, particularly farmers.","exampleKor":"새 무역 협정은 지역 경제, 특히 농민들에게 타격을 줄 것이다."},{"word":"adequately","pos":"adv.","meaning":"적절히","example":"The workers ensure that glassware is adequately wrapped.","exampleKor":"작업자들은 유리 제품이 적절히 포장되었는지를 확인한다."},{"word":"article","pos":"n.","meaning":"물품, 물건; 기사, 논설","example":"Several articles of clothing are missing from the shipment.","exampleKor":"몇몇 의류 물품들이 선적으로부터 사라지고 있다."},{"word":"efficient","pos":"adj.","meaning":"(기계·방법 등이) 효과적인, 능률적인","example":"Seal-wrap is an efficient means of packaging.","exampleKor":"밀봉 포장은 효과적인 포장 수단이다."},{"word":"agency","pos":"n.","meaning":"대행 회사, 대리점","example":"The government hired an agency to inspect all grain imports.","exampleKor":"정부는 모든 곡물 수입품들을 점검하도록 대행 회사를 고용했다."},{"word":"enclose","pos":"v.","meaning":"~을 동봉하다; ~을 둘러싸다, 에워싸다","example":"Please find a copy of the invoice enclosed.","exampleKor":"동봉된 송장 사본을 확인하세요."},{"word":"careful","pos":"adj.","meaning":"조심스러운, 주의 깊은","example":"Dock workers were extra careful with the crates containing sculptures.","exampleKor":"부두 근로자들은 조각들을 담고 있는 상자들을 특별히 더 조심했다."},{"word":"pick up","pos":"phr.","meaning":"~을 찾다; (사람·물건 등을) 도중에서 태우다","example":"Packages can be picked up from the reception desk.","exampleKor":"소포들은 접수처에서 찾을 수 있습니다."},{"word":"carry","pos":"v.","meaning":"지니다; (물품을) 팔다, 가게에 놓다","example":"All delivery drivers are required to carry at least one piece of identification.","exampleKor":"모든 배달 운전수들은 적어도 한 개의 신분증을 지녀야 한다."},{"word":"attach","pos":"v.","meaning":"붙이다, 접착하다, 첨부하다","example":"Carefully attach the address label to the package.","exampleKor":"주소 라벨을 소포에 조심스럽게 붙이세요."},{"word":"formerly","pos":"adv.","meaning":"이전에","example":"Mr. Lee was formerly in charge of the entire shipping department.","exampleKor":"Mr. Lee는 이전에 배송 부서 전체를 담당했었다."},{"word":"package","pos":"n.","meaning":"소포, 꾸러미","example":"Packages are delivered daily at 4 P.M.","exampleKor":"소포는 매일 오후 4시에 배달된다."},{"word":"react","pos":"v.","meaning":"반응하다, 대응하다","example":"Local businesspeople reacted negatively to news of stricter import regulations.","exampleKor":"지역 사업가들은 보다 엄격한 수입 규제에 대한 소식에 부정적으로 반응했다."},{"word":"content","pos":"n.","meaning":"내용물","example":"Please make sure that the contents of your package are not damaged.","exampleKor":"귀하의 소포 내용물이 파손되지 않았음을 확인해 주십시오."},{"word":"convenience","pos":"n.","meaning":"편의, 편리","example":"For your convenience, a tracking number is provided.","exampleKor":"귀하의 편의를 위해 추적 번호가 발급됩니다."},{"word":"acknowledge","pos":"v.","meaning":"인정하다; (편지 등의) 수령을 알리다","example":"The government acknowledged the need for reduced trade tariffs.","exampleKor":"정부는 무역 관세 인하의 필요성을 인정했다."},{"word":"caution","pos":"n.","meaning":"주의, 조심","example":"Please use caution when unpacking your order.","exampleKor":"귀하의 주문품을 소포에서 꺼내실 때 주의하십시오."},{"word":"correspondence","pos":"n.","meaning":"편지, 통신문","example":"Please send all correspondence to this address.","exampleKor":"모든 편지를 이 주소로 보내주시기 바랍니다."},{"word":"separate","pos":"v./adj.","meaning":"분리하다; 분류하다; 분리된, 따로 떨어진, 독립된","example":"Liquids must be separated from other materials being shipped.","exampleKor":"액체는 배송되는 다른 재료들로부터 분리되어야 한다."},{"word":"remarkable","pos":"adj.","meaning":"현저한, 두드러진","example":"Epic Corporation underwent a remarkable transformation in its export strategy.","exampleKor":"Epic사는 수출 전략에 있어 현저한 변화를 겪었다."},{"word":"handle","pos":"v.","meaning":"취급하다, 다루다","example":"The hazardous substances must be handled with care.","exampleKor":"위험 물질들은 조심스럽게 취급되어야 한다."},{"word":"warehouse","pos":"n.","meaning":"창고, 저장소","example":"Crates go to the warehouse before being delivered to their respective companies.","exampleKor":"나무 상자들은 각각의 회사로 배송되기 전에 창고로 간다."},{"word":"impose","pos":"v.","meaning":"(세금 등을) 부과하다","example":"The government plans to impose taxes on imported steel.","exampleKor":"정부는 수입 철강에 대해 세금을 부과할 계획이다."},{"word":"storage","pos":"n.","meaning":"보관소, 저장소","example":"Unclaimed packages will be placed in storage for six months.","exampleKor":"소유주 불명의 소포들은 6개월 동안 보관소에 놓여질 것이다."},{"word":"detach","pos":"v.","meaning":"분리하다, 떼다","example":"Please detach and send in the completed form.","exampleKor":"작성된 양식을 분리해서 송부해 주십시오."},{"word":"envelope","pos":"n.","meaning":"봉투","example":"A return address must be stamped on each envelope.","exampleKor":"각각의 봉투에 반송 주소가 인쇄되어야 한다."},{"word":"exclusion","pos":"n.","meaning":"제외, 배제","example":"The exclusion of shipping fees is offered for orders exceeding $500.","exampleKor":"배송료 제외는 500달러를 초과하는 주문품에 대해 제공된다."},{"word":"recipient","pos":"n.","meaning":"수신자","example":"Please enter the recipient's shipping address below.","exampleKor":"아래에 수신자의 배송 주소를 기입하세요."},{"word":"affix","pos":"v.","meaning":"(우표 등을) 붙이다","example":"Please affix a 50-cent stamp for postage to New York.","exampleKor":"뉴욕행 우편에는 50센트 우표를 붙여주시기 바랍니다."},{"word":"incorrect","pos":"adj.","meaning":"부정확한","example":"Incorrect mailing information will slow the order process.","exampleKor":"부정확한 우편 정보는 주문 처리를 느리게 할 것이다."},{"word":"oblige","pos":"v.","meaning":"어쩔 수 없이 ~하게 하다, ~에게 강요하다","example":"The importers were obliged to destroy 20,000 boxes of apples.","exampleKor":"수입업자들은 어쩔 수 없이 사과 2만 상자를 폐기해야 했다."},{"word":"step","pos":"n.","meaning":"단계; 조치, 수단","example":"The importer completed the final step of customs formalities.","exampleKor":"그 수입업자는 통관 절차의 마지막 단계를 마쳤다."},{"word":"distinctive","pos":"adj.","meaning":"독특한","example":"Maple syrup is Canada's most distinctive export product.","exampleKor":"메이플 시럽은 캐나다의 가장 독특한 수출품이다."},{"word":"discreet","pos":"adj.","meaning":"신중한, 조심스러운, 분별력 있는","example":"Delivery companies must be discreet with customers' personal information.","exampleKor":"배송 회사들은 고객들의 개인 정보에 대해 신중해야 한다."}]},{"day":18,"title":"특선요리 (숙박·식당)","words":[{"word":"check in","pos":"phr.","meaning":"체크인하다, 숙박 수속을 하다","example":"Please be sure to check in by 7 P.M.","exampleKor":"오후 7시까지 반드시 체크인하십시오."},{"word":"compensate","pos":"v.","meaning":"보상하다","example":"The hotel compensated the guest for the erroneous charge.","exampleKor":"그 호텔은 그 손님에게 잘못된 청구액에 대해 보상했다."},{"word":"complimentary","pos":"adj.","meaning":"무료의, 우대의","example":"Guests are given a complimentary light breakfast.","exampleKor":"손님들은 가벼운 무료 아침 식사를 제공받는다."},{"word":"chef","pos":"n.","meaning":"주방장","example":"The restaurant's head chef is famous across Europe.","exampleKor":"그 식당의 수석 주방장은 유럽 전역에서 유명하다."},{"word":"container","pos":"n.","meaning":"용기, 그릇","example":"Food may be kept for longer periods by storing it in airtight containers.","exampleKor":"음식은 밀폐 용기에 보관함으로써 더 오랜 기간 동안 보존될 수 있다."},{"word":"elegant","pos":"adj.","meaning":"우아한, 고상한","example":"The recently renovated lobby boasts elegant decor.","exampleKor":"최근에 개조된 로비는 우아한 장식을 자랑한다."},{"word":"flavor","pos":"n.","meaning":"맛, 풍미","example":"The shop sells ice cream in a variety of flavors.","exampleKor":"그 가게는 다양한 맛의 아이스크림을 판다."},{"word":"accommodate","pos":"v.","meaning":"(건물 등이) ~을 수용하다, 숙박시키다; (조건·요구 등을) 만족시키다","example":"The hotel can accommodate 350 guests.","exampleKor":"그 호텔은 350명의 손님을 수용할 수 있다."},{"word":"available","pos":"adj.","meaning":"(사물이) 이용 가능한; (사람이) 시간이 있는","example":"The sauna is available to all registered guests.","exampleKor":"사우나는 등록된 모든 손님들이 이용할 수 있습니다."},{"word":"reception","pos":"n.","meaning":"환영회; (호텔·회사·병원 등의) 접수처","example":"The college held a welcome reception for the guest speaker.","exampleKor":"그 대학은 객원 연사를 위한 환영회를 개최했다."},{"word":"in advance","pos":"phr.","meaning":"미리, 사전에","example":"Guests must notify the front desk in advance to reserve an airport shuttle.","exampleKor":"투숙객들은 공항 정기 왕복 버스를 예약하려면 프런트에 미리 알려야 한다."},{"word":"refreshments","pos":"n.","meaning":"다과, 가벼운 음식물","example":"Before leaving the resort, the group was served some refreshments.","exampleKor":"리조트를 떠나기 전에, 그 단체는 약간의 다과를 제공받았다."},{"word":"make","pos":"v.","meaning":"~을 하다, ~을 만들다","example":"To make telephone calls from your room, dial 9 first.","exampleKor":"객실에서 전화를 거시려면, 9번을 먼저 누르세요."},{"word":"cater","pos":"v.","meaning":"(연회 등의) 음식물을 공급하다","example":"The Stovepipe Grill charges reasonable rates to cater large events.","exampleKor":"Stovepipe Grill사는 규모가 큰 행사의 음식을 공급하는 데 합리적인 요금을 청구한다."},{"word":"reservation","pos":"n.","meaning":"예약, 지정; 보호 구역","example":"Once you receive confirmation by e-mail, the reservation has been made.","exampleKor":"확인 이메일을 받으면, 예약이 이루어진 것입니다."},{"word":"beverage","pos":"n.","meaning":"음료","example":"Snacks and beverages are available in the business-class lounge.","exampleKor":"비즈니스 클래스 라운지에서 간식과 음료를 이용할 수 있다."},{"word":"confirm","pos":"v.","meaning":"확인하다","example":"Please confirm your seating reservation prior to arrival.","exampleKor":"도착 전에 귀하의 좌석 예약을 확인하세요."},{"word":"cancel","pos":"v.","meaning":"취소하다","example":"Those wishing to cancel a booking are asked to do so at least a day in advance.","exampleKor":"예약을 취소하고 싶은 사람들은 적어도 하루 전에 취소해야 한다."},{"word":"rate","pos":"n.","meaning":"요금","example":"The inn offers fine rooms at affordable rates.","exampleKor":"그 여관은 좋은 방들을 알맞은 요금에 제공한다."},{"word":"conveniently","pos":"adv.","meaning":"편리하게","example":"Our hotel is conveniently located in downtown Sydney.","exampleKor":"우리 호텔은 시드니 중심가에 편리하게 위치해 있습니다."},{"word":"decorate","pos":"v.","meaning":"장식하다","example":"The restaurant owner decorated its interior with paintings of Italy.","exampleKor":"그 식당 주인은 식당 내부를 이탈리아를 그린 그림들로 장식했다."},{"word":"information","pos":"n.","meaning":"정보, 자료","example":"Further information about the resort can be found on its Web site.","exampleKor":"그 리조트에 대한 자세한 정보는 웹사이트에서 찾을 수 있습니다."},{"word":"retain","pos":"v.","meaning":"유지하다, 보유하다","example":"The cafeteria retains customers by offering inexpensive, flavorful food.","exampleKor":"그 식당은 저렴하면서도 맛있는 음식을 제공함으로써 고객을 유지한다."},{"word":"atmosphere","pos":"n.","meaning":"분위기, 환경","example":"The hotel provides a comfortable atmosphere.","exampleKor":"그 호텔은 편안한 분위기를 제공한다."},{"word":"cuisine","pos":"n.","meaning":"(독특한) 요리","example":"Jacque will prepare an exquisite selection of international cuisine.","exampleKor":"Jacque는 훌륭하고 엄선된 세계 요리를 준비할 것이다."},{"word":"sequence","pos":"n.","meaning":"순서, 차례","example":"The head chef makes sure every dinner order is prepared in the correct sequence.","exampleKor":"수석 주방장은 모든 저녁 식사 주문이 정확한 순서대로 준비되었는지 확인한다."},{"word":"extensive","pos":"adj.","meaning":"광범위한, 넓은","example":"The restaurant offers an extensive range of Chinese dishes.","exampleKor":"그 식당은 광범위한 종류의 중국요리를 제공한다."},{"word":"prior","pos":"adj.","meaning":"전의, 먼저의","example":"Prior to checkout, guests are asked to fill out a survey.","exampleKor":"체크아웃에 앞서, 투숙객들은 설문 조사를 작성해 달라는 요청을 받는다."},{"word":"book","pos":"v.","meaning":"예약하다","example":"The restaurant is busy on weekends, so booking a table is necessary.","exampleKor":"그 식당은 주말에 붐벼서, 테이블을 예약하는 것은 필수다."},{"word":"amenity","pos":"n.","meaning":"편의 시설","example":"The hotel amenities include a health center and a swimming pool.","exampleKor":"그 호텔의 편의 시설은 보건소와 수영장을 포함한다."},{"word":"belongings","pos":"n.","meaning":"소지품, 소유물","example":"Safety boxes are available in every room for the storage of valuable belongings.","exampleKor":"귀중품 보관을 위해 모든 방에서 귀중품 보관함을 이용하실 수 있습니다."},{"word":"entirely","pos":"adv.","meaning":"완전히","example":"The Eatery is known to cook entirely with organic produce.","exampleKor":"Eatery사는 완전히 유기농 농작물로만 조리하는 것으로 알려져 있다."},{"word":"ease","pos":"v./n.","meaning":"완화시키다; 쉬움, 용이함","example":"Jennifer eased the temperature of the oven to avoid burning her dish.","exampleKor":"Jennifer는 요리를 태우지 않기 위해 오븐의 온도를 완화시켰다."},{"word":"ingredient","pos":"n.","meaning":"재료, 성분","example":"The chef shops for fresh ingredients each morning at the local market.","exampleKor":"그 요리사는 매일 아침 현지 시장에서 신선한 재료들을 산다."},{"word":"sip","pos":"v.","meaning":"음미하며 마시다, 홀짝거리다","example":"Sip your beverages at the café's new outdoor area!","exampleKor":"카페의 새로운 야외 공간에서 음료를 음미하세요!"},{"word":"stir","pos":"v.","meaning":"휘젓다, 뒤섞다","example":"Stir the sauce to prevent it from sticking.","exampleKor":"소스가 달라붙는 것을 방지하기 위해 휘저어 주세요."},{"word":"choice","pos":"n.","meaning":"선택물, 선택 사항, 선택","example":"Today's special comes with the choice of soup or a salad.","exampleKor":"오늘의 특선 메뉴는 수프나 샐러드 중 선택하신 것과 함께 제공됩니다."},{"word":"complication","pos":"n.","meaning":"복잡한 문제","example":"We encountered several complications with our reservation.","exampleKor":"우리는 예약과 관련해 몇몇 복잡한 문제에 맞닥뜨렸다."},{"word":"freshness","pos":"n.","meaning":"신선함","example":"Wrapping produce in paper helps prolong its freshness.","exampleKor":"농산물을 종이로 포장해 두면 신선함을 오래 지속시켜 준다."},{"word":"occupancy","pos":"n.","meaning":"(호텔 등의) 이용률","example":"The ski resort's occupancy peaks in January.","exampleKor":"그 스키 리조트의 이용률은 1월에 최고조에 달한다."},{"word":"spot","pos":"v./n.","meaning":"발견하다, 찾다, 알아채다; (특정한) 장소","example":"When preparing to pay for the meal, Marie spotted a mistake on the bill.","exampleKor":"식사비를 지불할 준비를 할 때, Marie는 계산서에서 오류를 발견했다."}]},{"day":19,"title":"보너스는..? (수익)","words":[{"word":"decline","pos":"n./v.","meaning":"감소, 하락; (초대·신청을) 거절하다, 감소하다, 줄다","example":"A sharp decline in the number of buyers has lowered this year's profits.","exampleKor":"구매자 수의 급격한 감소가 금년도 수익을 떨어뜨렸다."},{"word":"markedly","pos":"adv.","meaning":"현저하게, 눈에 띄게","example":"Corporate profits continue to increase markedly.","exampleKor":"기업 이윤이 계속해서 현저하게 증가하고 있다."},{"word":"increase","pos":"n./v.","meaning":"인상, 증가; 증가하다","example":"All employees will receive a five percent pay increase next year.","exampleKor":"모든 직원들은 내년에 5퍼센트의 임금 인상을 받을 것이다."},{"word":"revenue","pos":"n.","meaning":"수입","example":"The company's revenue was boosted by higher album sales.","exampleKor":"회사 수입이 더 늘어난 앨범 판매로 인해 증대되었다."},{"word":"projection","pos":"n.","meaning":"예상(치)","example":"This month's income projections are higher than last month's were.","exampleKor":"이번 달 수입 예상치는 지난달 것보다 높다."},{"word":"substantial","pos":"adj.","meaning":"상당한","example":"The company made substantial investments in several emerging markets.","exampleKor":"그 회사는 몇몇 신흥 시장에 상당한 투자를 했다."},{"word":"anticipate","pos":"v.","meaning":"예상하다, 기대하다","example":"We anticipate a 40 percent increase in sales next year.","exampleKor":"우리는 내년에 40퍼센트의 매출 증대를 예상한다."},{"word":"significantly","pos":"adv.","meaning":"상당히, 두드러지게","example":"The layoffs will reduce expenses significantly.","exampleKor":"직원 감축은 경비를 상당히 감소시켜 줄 것이다."},{"word":"estimate","pos":"v./n.","meaning":"추정하다, 추산하다; 추정(치), 추산","example":"The laptops were estimated to bring in over $50 million.","exampleKor":"그 노트북 컴퓨터는 5천만 달러 이상의 이익을 가져올 것으로 추정되었다."},{"word":"shift","pos":"v./n.","meaning":"옮기다, 이동하다; 변화; 교대 근무","example":"The firm shifted some capital into its newest investment project.","exampleKor":"그 회사는 가장 최근의 투자 프로젝트로 약간의 자금을 옮겼다."},{"word":"fee","pos":"n.","meaning":"요금; 수수료","example":"The merchant may charge a small fee to process credit card payments.","exampleKor":"그 상인은 신용 카드 결제를 처리하기 위해 소액의 요금을 청구할지도 모른다."},{"word":"production","pos":"n.","meaning":"생산량, 생산","example":"Production will rise drastically with the addition of a third shift.","exampleKor":"3교대의 추가로 생산량이 급격하게 늘어날 것이다."},{"word":"sale","pos":"n.","meaning":"(-s) 매출액, 매상고; (할인) 판매","example":"Domestic sales have recently begun to drop.","exampleKor":"국내 매출액이 최근에 하락하기 시작했다."},{"word":"impressive","pos":"adj.","meaning":"굉장한, 인상적인","example":"NeuWear made impressive gains in the sportswear market.","exampleKor":"NeuWear사는 스포츠웨어 시장에서 굉장한 이익을 거두었다."},{"word":"representative","pos":"n./adj.","meaning":"직원, 외판원; 대표자; 대표하는, 대리의","example":"The sales representative developed an impressive client base.","exampleKor":"그 영업 사원은 굉장한 고객 기반을 구축했다."},{"word":"recent","pos":"adj.","meaning":"최근의","example":"Additional costs are reflected in the supplier's most recent price quote.","exampleKor":"추가 비용은 공급자의 가장 최근의 견적서에 반영되어 있다."},{"word":"exceed","pos":"v.","meaning":"~을 초과하다","example":"The new restaurant's profits exceeded initial projections.","exampleKor":"새 레스토랑의 수익은 초기 예상치를 초과했다."},{"word":"improvement","pos":"n.","meaning":"향상","example":"The improvements to the chair designs led to increased sales.","exampleKor":"의자 디자인의 향상은 판매량 증대로 이어졌다."},{"word":"employer","pos":"n.","meaning":"고용주","example":"The largest employer in the city is the automotive factory.","exampleKor":"그 도시의 최대 고용주는 자동차 공장이다."},{"word":"regular","pos":"adj.","meaning":"정기적인; 단골의","example":"Regular assessments of profitability occur throughout the fiscal year.","exampleKor":"정기적인 수익성 평가가 회계 연도 내내 이루어진다."},{"word":"summarize","pos":"v.","meaning":"요약하다","example":"EquityCorp summarized its business operations in the annual report.","exampleKor":"EquityCorp사는 연례 보고서에 자사의 운영 현황을 요약했다."},{"word":"typically","pos":"adv.","meaning":"보통, 일반적으로","example":"Cell phones typically go on sale before new models are released.","exampleKor":"휴대 전화는 보통 새로운 모델이 출시되기 전에 할인 판매된다."},{"word":"whole","pos":"adj.","meaning":"전체의, 온전한","example":"The whole amount of the loan must be paid in 60 days.","exampleKor":"대출금 전액은 60일 내로 상환해야 한다."},{"word":"growth","pos":"n.","meaning":"성장, 발전","example":"The company will be unable to maintain its present rate of growth.","exampleKor":"그 회사는 현재의 성장률을 유지할 수 없을 것이다."},{"word":"figure","pos":"n./v.","meaning":"총액, 합계 수; ~라고 여기다","example":"Last quarter's sales figures need to be sent to the main office.","exampleKor":"지난 분기 매출 총액은 본사로 보내져야 한다."},{"word":"steady","pos":"adj.","meaning":"꾸준한; 안정된","example":"Furniture sales have seen a steady rise since March.","exampleKor":"가구 판매는 3월 이후 꾸준한 증가를 보여 왔다."},{"word":"frequent","pos":"adj.","meaning":"빈번한, 잦은","example":"The company was able to adapt quickly despite frequent market changes.","exampleKor":"그 회사는 빈번한 시장 변화에도 불구하고 재빨리 적응할 수 있었다."},{"word":"achieve","pos":"v.","meaning":"달성하다, 성취하다","example":"The corporation achieved its sales goals for the year.","exampleKor":"그 기업은 금년도 매출 목표를 달성했다."},{"word":"assumption","pos":"n.","meaning":"추정, 산정","example":"DonCo's assumption that consumers value quality over price proved correct.","exampleKor":"소비자들이 가격보다 품질을 중시한다는 DonCo사의 추정은 옳은 것으로 밝혀졌다."},{"word":"share","pos":"v./n.","meaning":"공유하다, 함께 쓰다; (생각·경험·감정을 남과) 함께 나누다; 몫, 지분","example":"The CEO shared some excess profits with employees through bonuses.","exampleKor":"그 최고 경영자는 상여금을 통해 직원들과 초과 수익의 일부를 공유했다."},{"word":"encouraging","pos":"adj.","meaning":"고무적인, 힘을 북돋아 주는","example":"The figures for this quarter were encouraging.","exampleKor":"이번 분기의 수치는 고무적이었다."},{"word":"incur","pos":"v.","meaning":"(손실을) 입다, (빚을) 지다","example":"We have incurred significant operating losses since our inception a decade ago.","exampleKor":"우리는 10년 전 개업한 이래 심각한 운영 손실을 입어 왔다."},{"word":"slightly","pos":"adv.","meaning":"약간","example":"Inquiries regarding purchases are expected to decrease slightly.","exampleKor":"구매에 관한 문의가 약간 감소할 것으로 예상된다."},{"word":"profit","pos":"n.","meaning":"수익, 이익","example":"The profits from the auction will go to charity.","exampleKor":"경매 수익은 자선 단체로 보내질 것이다."},{"word":"reliant","pos":"adj.","meaning":"의존하는, 의지하는","example":"Much of the business is reliant on sales from returning customers.","exampleKor":"사업의 대부분은 재방문 고객들의 매출에 의존한다."},{"word":"illustrate","pos":"v.","meaning":"분명히 보여 주다, 설명하다","example":"The line graph illustrates the rise in expenses.","exampleKor":"선 그래프가 비용의 상승을 분명히 보여 준다."},{"word":"inaccurate","pos":"adj.","meaning":"부정확한","example":"The calculations in the report were inaccurate.","exampleKor":"보고서의 계산은 부정확했다."},{"word":"percentage","pos":"n.","meaning":"비율, 백분율","example":"The percentage of people buying digital music players has decreased somewhat.","exampleKor":"디지털 음악 재생기를 구매하는 사람의 비율이 다소 감소했다."},{"word":"reduce","pos":"v.","meaning":"줄이다, 감소시키다","example":"Management reduced the travel budget in an effort to cut costs.","exampleKor":"경영진은 비용을 절감하고자 출장 예산을 줄였다."},{"word":"tend","pos":"v.","meaning":"~하는 경향이 있다, ~하기 쉽다","example":"Corporate profits tend to rise in line with national income.","exampleKor":"회사 수익은 국민 소득과 함께 증가하는 경향이 있다."},{"word":"beyond","pos":"prep.","meaning":"~을 넘어서, ~이상으로","example":"The monthly sales figures were far beyond the company's expectations.","exampleKor":"월 매출액은 회사의 예상을 훨씬 넘어섰다."}]},{"day":20,"title":"경비 절감 (회계)","words":[{"word":"audit","pos":"n.","meaning":"회계 감사, 심사","example":"An internal audit of financial records will be conducted.","exampleKor":"재무 기록에 대한 내부 감사가 실시될 것이다."},{"word":"accounting","pos":"n.","meaning":"회계","example":"The accounting department reports directly to the CEO.","exampleKor":"회계 부서는 최고 경영자에게 곧장 보고한다."},{"word":"budget","pos":"n.","meaning":"예산","example":"The community center was given an annual operations budget of $120,000.","exampleKor":"지역 문화 회관에 12만 달러의 연간 운영 예산이 주어졌다."},{"word":"financial","pos":"adj.","meaning":"재정의, 금전상의","example":"A consultant's financial advice is helpful for major projects.","exampleKor":"컨설턴트의 재정 상담은 주요 프로젝트에 도움이 된다."},{"word":"curtail","pos":"v.","meaning":"~을 줄이다, 삭감하다","example":"The manager made an effort to curtail office expenses.","exampleKor":"그 관리자는 사무 비용을 줄이기 위해 노력했다."},{"word":"deficit","pos":"n.","meaning":"적자, 부족액","example":"Reserve funds will be used to make up for the deficit.","exampleKor":"예비 자금이 적자를 만회하기 위해 사용될 것이다."},{"word":"recently","pos":"adv.","meaning":"최근에","example":"Bookkeeping costs have recently risen considerably.","exampleKor":"부기 비용이 최근에 상당히 증가했다."},{"word":"substantially","pos":"adv.","meaning":"크게, 상당히","example":"The marketing team was substantially expanded to help boost sales.","exampleKor":"마케팅팀은 판매 증대에 도움이 되도록 크게 확장되었다."},{"word":"committee","pos":"n.","meaning":"위원회","example":"The committee submitted a report on donations.","exampleKor":"위원회가 기부금에 관한 보고서를 제출했다."},{"word":"frequently","pos":"adv.","meaning":"자주, 흔히","example":"Clients who frequently pay on time may receive favorable terms.","exampleKor":"자주 돈을 제때 납부하는 고객들은 유리한 조건을 제공받을 수 있다."},{"word":"capability","pos":"n.","meaning":"능력, 역량","example":"The firm has the capability to advise clients on a range of financial decisions.","exampleKor":"그 회사는 다양한 재정적인 결정에 대해 고객에게 조언할 능력이 있다."},{"word":"proceeds","pos":"n.","meaning":"수익금","example":"All proceeds from the auction will go to local charities.","exampleKor":"경매의 모든 수익금은 지역 자선 단체로 보내질 것이다."},{"word":"reimburse","pos":"v.","meaning":"변제하다, 상환하다","example":"The company will fully reimburse any travel expenses incurred.","exampleKor":"회사가 지출된 모든 여행 경비를 전액 변제할 것이다."},{"word":"considerably","pos":"adv.","meaning":"상당히, 많이","example":"The new software program makes computing taxes considerably easier.","exampleKor":"새 소프트웨어는 세금 산출을 상당히 더 쉽게 해준다."},{"word":"adequate","pos":"adj.","meaning":"충분한, 적절한","example":"Pelton Manufacturing lacks adequate funds for the purchase of new equipment.","exampleKor":"Pelton Manufacturing사는 새로운 장비를 구입할 충분한 자금이 없다."},{"word":"total","pos":"adj./n./v.","meaning":"총계의, 전부의; 합계, 총액; 합산하다, 총계가 ~이 되다","example":"Total revenues for the year have yet to be added up.","exampleKor":"연간 총수입이 아직 합산되지 않았다."},{"word":"allocate","pos":"v.","meaning":"할당하다, 배분하다","example":"Funds were allocated for the charity benefit.","exampleKor":"자선 행사를 위해 자금이 할당되었다."},{"word":"inspector","pos":"n.","meaning":"조사관, 감독관","example":"The inspector reviewed all the receipts submitted last year.","exampleKor":"그 조사관은 작년에 제출된 모든 영수증을 검토했다."},{"word":"preferred","pos":"adj.","meaning":"선호되는, 우선의","example":"Our preferred method of online payment is through Pay Safe.","exampleKor":"우리가 선호하는 온라인 지불 방법은 Pay Safe를 통하는 것이다."},{"word":"quarter","pos":"n.","meaning":"사분기; 4분의 1","example":"Profits this quarter are 20 percent higher than the last one.","exampleKor":"이번 분기의 수익은 지난 분기보다 20퍼센트 더 높다."},{"word":"interrupt","pos":"v.","meaning":"중단시키다, 방해하다","example":"Poor cash management forced the company to interrupt payments to its contractors.","exampleKor":"형편없는 현금 관리로 인해 회사는 하청업체에 지불을 중단할 수밖에 없었다."},{"word":"browse","pos":"v.","meaning":"훑어보다, 둘러보다","example":"Investors may browse through the firm's financial statements before making a decision.","exampleKor":"투자자들은 결정을 내리기 전에 회사의 재무제표를 훑어봐도 된다."},{"word":"prompt","pos":"adj./v.","meaning":"즉각적인; 신속한; 촉발하다, 유도하다","example":"The CEO demanded a prompt response to her questions about the budget.","exampleKor":"그 최고 경영자는 예산에 대한 질문에 즉각적인 답변을 요구했다."},{"word":"deduct","pos":"v.","meaning":"공제하다, 빼다","example":"Michael deducted his business expenses from his gross income.","exampleKor":"Michael은 자신의 총수입에서 업무 경비를 공제했다."},{"word":"measurement","pos":"n.","meaning":"측정, 측량; 치수","example":"Close measurement of the company's operating expenses helped the accountants spot inefficiencies.","exampleKor":"회사 운영비의 철저한 측정은 회계사들이 비능률을 찾는 데 도움이 되었다."},{"word":"shorten","pos":"v.","meaning":"단축하다, 짧게 하다","example":"Tracking expenses online shortens the time needed to calculate expenditures.","exampleKor":"온라인상으로 지출을 추적하는 것은 비용을 계산하는 데 필요한 시간을 단축한다."},{"word":"amend","pos":"v.","meaning":"수정하다","example":"Ms. Ford amended the budget to account for the increased prices of goods.","exampleKor":"Ms. Ford는 인상된 물품 가격을 설명하기 위해 예산안을 수정했다."},{"word":"calculate","pos":"v.","meaning":"계산하다, 산출하다","example":"The contractors calculated the cost of rebuilding to be around $2 million.","exampleKor":"하청업체들은 재건 비용을 약 2백만 달러로 계산했다."},{"word":"exempt","pos":"adj.","meaning":"면제된, ~이 없는","example":"Certain goods are exempt from import taxes.","exampleKor":"특정 물품들은 수입세를 면제받는다."},{"word":"deficient","pos":"adj.","meaning":"부족한, 불충분한","example":"Funding for the office renovations is deficient.","exampleKor":"사무실 개조 자금이 부족하다."},{"word":"compare","pos":"v.","meaning":"비교하다","example":"This software automatically compares profits for each year in a chart.","exampleKor":"이 소프트웨어는 표에 있는 연간 수익금을 자동적으로 비교한다."},{"word":"fortunate","pos":"adj.","meaning":"운 좋은","example":"Some stockholders were fortunate to invest in the company early.","exampleKor":"몇몇 주주들은 운 좋게 그 회사에 일찍 투자할 수 있었다."},{"word":"expenditure","pos":"n.","meaning":"지출, 비용","example":"This month's sales outweigh expenditures.","exampleKor":"이달 매출은 지출보다 훨씬 많다."},{"word":"accurately","pos":"adv.","meaning":"정확하게","example":"To prevent later confusion, record transactions accurately.","exampleKor":"추후의 혼동을 예방하기 위해, 거래를 정확히 기록하세요."},{"word":"worth","pos":"adj./n.","meaning":"~의 가치가 있는; (얼마) 어치, 가치","example":"It is worth the cost to upgrade our machinery.","exampleKor":"기계를 업그레이드하는 것은 비용만큼의 가치가 있다."},{"word":"excess","pos":"n.","meaning":"초과, 초과량","example":"Spending controls led to an excess of funds.","exampleKor":"지출 억제는 자금의 초과로 이어졌다."},{"word":"fiscal","pos":"adj.","meaning":"회계의, 재정상의","example":"Results for the past fiscal year will be announced in August.","exampleKor":"지난 회계 연도의 성과는 8월에 발표될 것이다."},{"word":"incidental","pos":"adj.","meaning":"부수적인","example":"Total all incidental expenses for the journey and submit the form to accounting.","exampleKor":"여행 중에 발생한 모든 부대 비용을 합산해서 해당 서식을 경리과에 제출하세요."},{"word":"inflation","pos":"n.","meaning":"물가 상승, 인플레이션, 통화 팽창","example":"A high inflation rate affected the company's net gains.","exampleKor":"높은 물가 상승률은 회사의 순수익에 영향을 미쳤다."},{"word":"liable","pos":"adj.","meaning":"책임져야 할; ~하기 쉬운","example":"The guarantor is liable for any unpaid debts.","exampleKor":"보증인은 모든 미납된 채무에 대한 책임이 있다."},{"word":"spend","pos":"v.","meaning":"~을 쓰다, 소비하다","example":"The firm spent a lot of money on reinventing its products.","exampleKor":"그 회사는 제품을 처음부터 다시 만드는 데 많은 돈을 썼다."},{"word":"turnover","pos":"n.","meaning":"총 매상고, 거래액; 이직률","example":"The company's turnover exceeded $2.8 million.","exampleKor":"회사의 총 매상고가 280만 달러를 넘어섰다."}]},{"day":21,"title":"사내 공모전 (회사동향)","words":[{"word":"announce","pos":"v.","meaning":"발표하다","example":"The chairperson announced plans to increase overseas production.","exampleKor":"그 의장은 해외 생산을 증가시킬 계획을 발표했다."},{"word":"interested","pos":"adj.","meaning":"관련 있는; 관심이 있는","example":"Interested parties met to discuss the investment proposal.","exampleKor":"관련 당사자들이 투자 제의를 논의하기 위해 만났다."},{"word":"active","pos":"adj.","meaning":"적극적인, 활발한","example":"Mr. Jones decided to take a more active role in the operations of his company.","exampleKor":"Mr. Jones는 회사 운영에 있어 보다 적극적인 역할을 하기로 결정했다."},{"word":"accept","pos":"v.","meaning":"수락하다, 승낙하다","example":"The managers voted to accept the new building proposal.","exampleKor":"그 관리자들은 새로운 건물 건립안을 수락하기로 표결했다."},{"word":"foresee","pos":"v.","meaning":"예견하다, 예감하다","example":"Food companies try to foresee future trends in agriculture.","exampleKor":"식품 회사들은 농업 분야의 미래 동향을 예견하려고 노력한다."},{"word":"expansion","pos":"n.","meaning":"확장, 팽창","example":"The firm is seeking opportunities for expansion into new markets.","exampleKor":"그 회사는 새로운 시장으로의 확장 기회를 찾고 있다."},{"word":"relocate","pos":"v.","meaning":"(공장 등을) 이전하다","example":"The board decided to relocate the plant's main base of operations.","exampleKor":"이사회는 공장의 주요 운영 기지를 이전하기로 결정했다."},{"word":"competitor","pos":"n.","meaning":"경쟁업체, 경쟁자","example":"The company's closest competitor is catching up in sales.","exampleKor":"그 회사의 가장 치열한 경쟁업체가 판매에서 그들을 따라잡고 있다."},{"word":"asset","pos":"n.","meaning":"자산","example":"Wilcox Inc. regards its employees as its most valuable assets.","exampleKor":"Wilcox사는 직원들을 가장 가치 있는 자산으로 여긴다."},{"word":"contribute","pos":"v.","meaning":"기여하다, 공헌하다","example":"Various factors contributed to the company's success.","exampleKor":"다양한 요소들이 회사의 성공에 기여했다."},{"word":"dedicated","pos":"adj.","meaning":"(목표 등에) 전념하는, 헌신적인","example":"The new director is dedicated to improving the firm's public image.","exampleKor":"신임 이사는 회사의 대외 이미지를 개선하는 데 전념한다."},{"word":"misplace","pos":"v.","meaning":"잃어버리다, 위치를 잘못 잡다","example":"Marsha accidentally misplaced several sensitive company documents.","exampleKor":"Marsha는 뜻하지 않게 회사 기밀문서 몇 장을 잃어버렸다."},{"word":"considerable","pos":"adj.","meaning":"(정도나 양이) 상당한","example":"The developer raised the capital after considerable effort.","exampleKor":"그 개발 회사는 상당한 노력 끝에 자금을 마련했다."},{"word":"last","pos":"v.","meaning":"지속되다","example":"The recession lasted longer than most governments had expected.","exampleKor":"경기 침체는 대부분의 국가들이 예상했던 것보다 더 오래 지속되었다."},{"word":"emerge","pos":"v.","meaning":"부상하다, 나타나다","example":"Macrotech Software emerged as the leader in the industry.","exampleKor":"Macrotech Software사는 업계의 선도업체로 두각을 나타냈다."},{"word":"grow","pos":"v.","meaning":"성장하다, 성장시키다, 증가시키다","example":"The market for electric vehicles is growing slowly but steadily.","exampleKor":"전기 자동차 시장은 느리지만 꾸준히 성장하고 있다."},{"word":"select","pos":"v.","meaning":"선발하다, 선택하다","example":"The board of Chambers Corp. selected a new chairperson last week.","exampleKor":"Chambers사의 이사회는 지난주에 새로운 회장을 선발했다."},{"word":"merge","pos":"v.","meaning":"합병하다, 병합하다","example":"The private firm merged with a corporate giant.","exampleKor":"그 사기업은 대기업과 합병했다."},{"word":"imply","pos":"v.","meaning":"암시하다, 넌지시 나타내다, 의미하다","example":"A rise in the company's stock price implies investor confidence in its future performance.","exampleKor":"그 회사의 주가 상승은 회사의 장래 성과에 대한 투자자들의 신뢰를 암시한다."},{"word":"vital","pos":"adj.","meaning":"필수적인","example":"Understanding customers' needs is vital to growing a business.","exampleKor":"고객의 요구를 이해하는 것은 사업을 성장시키는 데 필수적이다."},{"word":"persist","pos":"v.","meaning":"(집요하게) 계속하다, 계속되다, 지속되다","example":"The firm must persist in its attempts to prosecute copyright violators.","exampleKor":"그 회사는 저작권 위반자들을 기소하기 위한 시도를 계속해야 한다."},{"word":"independent","pos":"adj.","meaning":"독립적인, 독자적인","example":"An independent review board was formed to evaluate business proposals.","exampleKor":"사업 제안들을 평가하기 위해 독립적인 평가 위원회가 구성되었다."},{"word":"force","pos":"n.","meaning":"세력","example":"Johnson Homes has become a major force in the real estate sector.","exampleKor":"Johnson Homes사는 부동산 업계의 주요 세력이 되었다."},{"word":"establish","pos":"v.","meaning":"설립하다","example":"The businessman is planning to establish an offshore company.","exampleKor":"그 사업가는 해외에 회사를 설립하려고 계획 중이다."},{"word":"initiate","pos":"v.","meaning":"(사업 등을) 착수하다, 시작하다","example":"The CEO initiated plans for continued business growth.","exampleKor":"그 최고 경영자는 지속적인 사업 성장을 위한 계획에 착수했다."},{"word":"enhance","pos":"v.","meaning":"(질 등을) 향상시키다, 높이다, 강화하다","example":"Support of nonprofit organizations can enhance a company's image.","exampleKor":"비영리 단체를 후원하는 것은 회사 이미지를 향상시킬 수 있다."},{"word":"renowned","pos":"adj.","meaning":"저명한, 유명한, 명성이 있는","example":"Several renowned economists spoke at this year's national business conference.","exampleKor":"몇몇 저명한 경제학자들이 올해 열린 국내 경영 회담에서 연설했다."},{"word":"informed","pos":"adj.","meaning":"정보에 근거한","example":"Seeking legal advice will help you make an informed decision.","exampleKor":"법률 자문을 구하는 것은 현명한 결정을 하는 데 도움이 될 것이다."},{"word":"minutes","pos":"n.","meaning":"회의록","example":"Janine took minutes from the meeting and will send everyone a copy.","exampleKor":"Janine은 그 회의에서 회의록을 작성했고 모두에게 사본을 보낼 것이다."},{"word":"waive","pos":"v.","meaning":"(규칙 등을) 적용하지 않다, (권리·청구 등을) 포기하다","example":"The Revenue Department waives tax requirements in exceptional circumstances.","exampleKor":"국세청은 예외적인 경우에 세금을 면제해 준다."},{"word":"reach","pos":"v.","meaning":"(치수·양 등이) ~에 달하다; ~에 도착하다","example":"Sales figures for Sameco phones have reached 15 million units.","exampleKor":"Sameco사 전화의 판매 실적이 1,500만 대에 달했다."},{"word":"authority","pos":"n.","meaning":"권한; 당국","example":"Ms. Franklin has the authority to revoke the agent's license.","exampleKor":"Ms. Franklin은 중개인 면허를 취소할 수 있는 권한이 있다."},{"word":"acquire","pos":"v.","meaning":"매입하다, 취득하다","example":"The company will acquire property near the financial district.","exampleKor":"그 회사는 금융가 근처의 부동산을 매입할 것이다."},{"word":"surpass","pos":"v.","meaning":"~을 능가하다, 넘어서다","example":"Profits for the last fiscal year surpassed $300 million.","exampleKor":"지난 회계 연도의 수익이 3억 달러를 능가했다."},{"word":"run","pos":"v.","meaning":"~을 운영하다, 경영하다; (공연, 영화 등이) 상영되다, 계속되다","example":"The organization is run by retired executives.","exampleKor":"그 단체는 은퇴한 임원들에 의해 운영된다."},{"word":"improbable","pos":"adj.","meaning":"사실이라고 생각할 수 없는, 일어날 것 같지 않은","example":"Mr. Jenkins is an improbable candidate for the job, as he lacks experience.","exampleKor":"Mr. Jenkins는 경험이 부족하기 때문에 그 자리의 후보로 생각할 수 없다."},{"word":"edge","pos":"n.","meaning":"우위, 유리함; 가장자리, 끝","example":"Mr. Paulson's vast experience gives him an edge on the other job candidates.","exampleKor":"Mr. Paulson의 방대한 경험은 그를 다른 입사 지원자들보다 우위에 둔다."},{"word":"simultaneously","pos":"adv.","meaning":"동시에","example":"The company is attempting to enter both Asia and Europe simultaneously.","exampleKor":"그 회사는 아시아와 유럽으로 동시에 진출하려고 시도하고 있다."},{"word":"reveal","pos":"v.","meaning":"밝히다, 누설하다","example":"The companies revealed their plan to set up a joint venture.","exampleKor":"그 회사들은 합작 사업을 시작하려는 계획을 밝혔다."},{"word":"productivity","pos":"n.","meaning":"생산성","example":"Brewster Manufacturing has raised productivity at its Jakarta plant.","exampleKor":"Brewster Manufacturing사는 자카르타 공장의 생산성을 높였다."},{"word":"uncertain","pos":"adj.","meaning":"확신이 없는, 불확실한","example":"The company is uncertain about the cost of operating a factory in China.","exampleKor":"그 회사는 중국에서 공장을 운영하는 비용에 대해 확신을 갖지 못한다."},{"word":"premier","pos":"adj.","meaning":"으뜸의, 첫째의","example":"Harrison Software quickly became the nation's premier game manufacturer.","exampleKor":"Harrison Software사는 빠르게 국내 으뜸의 게임 제조업체가 되었다."}]},{"day":22,"title":"긴급 회의 (미팅)","words":[{"word":"agenda","pos":"n.","meaning":"의제, 의사일정","example":"Mr. Jones planned the agenda for the stockholders' meeting.","exampleKor":"Mr. Jones는 주주 총회의 의제를 구상했다."},{"word":"convene","pos":"v.","meaning":"(회원 등이) 모이다, (회의가) 개최되다","example":"The CEOs will convene tomorrow to review joint investment initiatives.","exampleKor":"최고 경영자들은 공동 투자 계획을 재검토하기 위해 내일 모일 것이다."},{"word":"refute","pos":"v.","meaning":"부인하다, 반박하다","example":"Mr. Geiger did not refute the allegations made against him.","exampleKor":"Mr. Geiger는 그를 상대로 제기된 혐의를 부인하지 않았다."},{"word":"coordination","pos":"n.","meaning":"조정","example":"Mr. Dane has taken on the coordination of the seminar.","exampleKor":"Mr. Dane이 세미나 조정 업무를 맡았다."},{"word":"unanimous","pos":"adj.","meaning":"만장일치의, 동의하는","example":"The plans gained unanimous support from board members.","exampleKor":"그 계획은 이사진으로부터 만장일치의 지지를 얻었다."},{"word":"convince","pos":"v.","meaning":"납득시키다, 확신시키다","example":"The broker convinced the investors that the scheme was commercially viable.","exampleKor":"중개인은 투자자들에게 그 계획이 상업적으로 성공할 수 있다고 납득시켰다."},{"word":"consensus","pos":"n.","meaning":"여론, 일치된 의견","example":"The general consensus seems to be that selling is the best option.","exampleKor":"매각이 최선의 선택이라는 것이 전반적인 여론인 듯하다."},{"word":"defer","pos":"v.","meaning":"연기하다, 미루다","example":"The registration deadline has been deferred for one week.","exampleKor":"등록 마감일이 일주일 연기되었다."},{"word":"usually","pos":"adv.","meaning":"보통, 일반적으로","example":"Team members usually discuss the schedule each Monday.","exampleKor":"팀원들은 보통 매주 월요일에 일정을 논의한다."},{"word":"reschedule","pos":"v.","meaning":"일정을 바꾸다","example":"The conference may be rescheduled if Mr. Bellman is unavailable.","exampleKor":"Mr. Bellman이 참석할 수 없다면 회의 일정이 바뀔 수 있습니다."},{"word":"meeting","pos":"n.","meaning":"회의","example":"The meeting will begin at 10 A.M., so please be on time.","exampleKor":"회의는 오전 10시에 시작될 예정이오니, 제시간에 와 주십시오."},{"word":"determine","pos":"v.","meaning":"알아내다; 결정하다, 확정하다","example":"The team met to determine the cause of the chemical leak.","exampleKor":"그 팀은 화학 물질 유출의 원인을 알아내기 위해 모였다."},{"word":"report","pos":"v./n.","meaning":"보고하다; 출두하다, (직장·회의 등에 도착을) 알리다; 보고서; 보도, 기록","example":"The head researcher reported his findings to the department leaders.","exampleKor":"수석 연구원은 부서장들에게 그의 연구 결과를 보고했다."},{"word":"comment","pos":"v.","meaning":"논평하다, 언급하다","example":"The spokesperson refused to comment on the budget cuts.","exampleKor":"대변인은 예산 삭감에 대해 말하길 거부했다."},{"word":"phase","pos":"n.","meaning":"단계","example":"Mr. Baker made a detailed plan for the building project's third phase.","exampleKor":"Mr. Baker는 건축 프로젝트의 세 번째 단계에 대한 상세한 계획을 세웠다."},{"word":"approve","pos":"v.","meaning":"승인하다, 찬성하다","example":"The head architect approved the proposal for changing the design process.","exampleKor":"수석 건축가는 설계 과정을 바꾸자는 기획안을 승인했다."},{"word":"enclosed","pos":"adj.","meaning":"동봉된","example":"A program is enclosed in the conference's information packet.","exampleKor":"일정표는 회의 자료 묶음에 동봉되어 있습니다."},{"word":"easy","pos":"adj.","meaning":"쉬운, 용이한","example":"The decision to sell the shopping mall was not easy to make.","exampleKor":"그 쇼핑몰을 매각하겠다는 결정은 내리기 쉽지 않았다."},{"word":"record","pos":"n./v.","meaning":"기록; 경력, 이력; 기록하다","example":"Managers reviewed the accounts record before making a final decision.","exampleKor":"관리자들은 최종 결정을 내리기 전에 회계 기록을 검토했다."},{"word":"suggestion","pos":"n.","meaning":"제안","example":"Mr. Kumar made a useful suggestion to help improve profit margins.","exampleKor":"Mr. Kumar는 수익 개선에 도움이 되는 유용한 제안을 했다."},{"word":"attention","pos":"n.","meaning":"주의, 경청","example":"The officials paid attention to the incoming president's formal address.","exampleKor":"임원들은 후임 회장의 공식 연설에 주의를 기울였다."},{"word":"object","pos":"v.","meaning":"반대하다","example":"No one objected to taking a short coffee break.","exampleKor":"아무도 짧은 휴식 시간을 갖는 것에 반대하지 않았다."},{"word":"coincidentally","pos":"adv.","meaning":"우연히, 일치하게, 동시 발생적으로","example":"The new managers introduced at the meeting were both coincidentally from Taiwan.","exampleKor":"회의에서 소개된 신임 관리자들은 둘 다 우연히도 대만 출신이었다."},{"word":"crowded","pos":"adj.","meaning":"붐비는, 복잡한","example":"Conference attendees have complained about the small venue being too crowded.","exampleKor":"회의 참석자들은 작은 회의장이 너무 붐비는 것에 대해 불평했다."},{"word":"undergo","pos":"v.","meaning":"겪다, 거치다, 경험하다","example":"The meeting room is unavailable because it is undergoing renovation.","exampleKor":"회의실은 보수 중이기 때문에 이용할 수 없다."},{"word":"outcome","pos":"n.","meaning":"결과","example":"The outcome of the study was a topic for debate.","exampleKor":"그 연구 결과는 토론해 볼 만한 주제였다."},{"word":"narrowly","pos":"adv.","meaning":"주의 깊게, 좁게; 가까스로, 간신히, 겨우","example":"The keynote speech was narrowly focused on trends in the industry.","exampleKor":"기조연설은 그 업계의 경향에 주의 깊게 집중했다."},{"word":"differ","pos":"v.","meaning":"의견을 달리하다, 다르다","example":"Executives differ in their opinions on the issue of telecommuting.","exampleKor":"임원들은 재택근무에 대해 의견을 달리한다."},{"word":"discuss","pos":"v.","meaning":"논의하다, 토론하다","example":"Jeremy Stevens discussed the design proposal with his colleagues.","exampleKor":"Jeremy Stevens는 그의 동료들과 함께 디자인 안을 논의했다."},{"word":"give","pos":"v.","meaning":"(연설·수업 등을) 하다","example":"The former president of Gascom will give a speech.","exampleKor":"Gascom사의 전 회장이 연설할 것이다."},{"word":"brief","pos":"v.","meaning":"~에게 간단히 설명하다, 브리핑하다","example":"The manager briefed the staff on the policy change.","exampleKor":"부장은 직원들에게 방침 변화에 대해 간단히 설명했다."},{"word":"distract","pos":"v.","meaning":"(주의를) 산만하게 하다, 빗기게 하다","example":"The meeting's participants were constantly distracted by noise.","exampleKor":"회의 참석자들은 소음 때문에 끊임없이 주의가 산만해졌다."},{"word":"emphasis","pos":"n.","meaning":"강조, 중점","example":"The speaker placed an emphasis on economic development strategies.","exampleKor":"발표자는 경제 개발 전략을 강조했다."},{"word":"press","pos":"n./v.","meaning":"언론(계), 보도기관; 누르다","example":"The press covered the merger talks closely.","exampleKor":"언론은 합병 회담을 심도 있게 다루었다."},{"word":"organize","pos":"v.","meaning":"준비하다, 조직하다, 정리하다","example":"Roy Dell organized a series of marketing seminars.","exampleKor":"Roy Dell이 일련의 마케팅 세미나를 준비했다."},{"word":"mention","pos":"v.","meaning":"언급하다","example":"Karl mentioned his concern about the low attendance levels.","exampleKor":"Karl은 낮은 출석률에 대한 우려를 언급했다."},{"word":"persuasive","pos":"adj.","meaning":"설득력 있는","example":"Julia Accord's offer was refused despite her persuasive arguments.","exampleKor":"Julia Accord의 제안은 그녀의 설득력 있는 주장에도 불구하고 거절되었다."},{"word":"understanding","pos":"adj.","meaning":"이해심 있는","example":"The negotiator assumed an understanding attitude throughout the discussion.","exampleKor":"그 협상자는 논의 내내 이해심 있는 태도를 보였다."},{"word":"adjourn","pos":"v.","meaning":"(회의 등을) 휴회하다","example":"The meeting was adjourned an hour after it began.","exampleKor":"회의는 시작된 지 한 시간 후에 휴회되었다."},{"word":"constructive","pos":"adj.","meaning":"건설적인","example":"Supervisors should give constructive criticism to employees.","exampleKor":"관리자는 직원들에게 건설적인 비판을 해 주어야 한다."},{"word":"preside","pos":"v.","meaning":"(회의의) 사회를 보다, ~의 의장을 맡아보다","example":"The chief of human resources will preside over the annual staff gathering.","exampleKor":"인사부장이 연례 직원 모임의 사회를 볼 것이다."},{"word":"irrelevant","pos":"adj.","meaning":"관계가 없는, 무관한","example":"The argument was irrelevant to the topic.","exampleKor":"그 주장은 논제와 관계가 없었다."},{"word":"constraint","pos":"n.","meaning":"제한","example":"Due to time constraints, the policy change was not discussed.","exampleKor":"시간제한으로 인해, 정책 변경은 논의되지 못했다."},{"word":"condensed","pos":"adj.","meaning":"요약한, 응축한, 압축한","example":"A condensed version of the report was read aloud at the meeting.","exampleKor":"그 보고서의 요약본은 회의에서 낭독되었다."},{"word":"endorse","pos":"v.","meaning":"(공개적으로) 지지하다, 보증하다","example":"The businessman publicly endorsed Ms. Kim for mayor.","exampleKor":"그 사업가는 공개적으로 Ms. Kim을 시장으로 지지했다."},{"word":"punctually","pos":"adv.","meaning":"제시간에, 늦지 않게","example":"Some participants failed to arrive punctually for the workshop.","exampleKor":"몇몇 참가자들은 워크숍에 제시간에 도착하지 못했다."}]},{"day":23,"title":"역지사지 (사원 복지)","words":[{"word":"host","pos":"v./n.","meaning":"(대회 등을) 주최하다; 주최자, 사회자","example":"Wilmar Industries will host this year's convention.","exampleKor":"Wilmar Industries사가 금년도 컨벤션을 주최할 것이다."},{"word":"annual","pos":"adj.","meaning":"매년의","example":"This year's annual conference was held in Atlanta.","exampleKor":"올해의 연례 회의는 애틀랜타에서 열렸다."},{"word":"purpose","pos":"n.","meaning":"목적, 의도","example":"The purpose of the training is to familiarize the staff with the new networking system.","exampleKor":"그 교육의 목적은 직원들이 새 네트워크 시스템에 익숙해지도록 하는 것이다."},{"word":"enroll","pos":"v.","meaning":"등록하다","example":"Employees must enroll in at least one program.","exampleKor":"직원들은 적어도 한 개의 프로그램에 등록해야 한다."},{"word":"lecture","pos":"n.","meaning":"강의, 강연","example":"The course will offer weekly guest lectures.","exampleKor":"그 강좌는 매주 초청 강의를 제공할 것이다."},{"word":"participant","pos":"n.","meaning":"참가자","example":"Many participants in the training program showed some improvement.","exampleKor":"교육 프로그램의 많은 참가자들이 약간의 발전을 보였다."},{"word":"attend","pos":"v.","meaning":"참석하다, 출석하다","example":"Staff were urged to attend weekend software courses.","exampleKor":"직원들은 주말 소프트웨어 강좌에 참석하도록 권고받았다."},{"word":"encourage","pos":"v.","meaning":"장려하다, 북돋아 주다","example":"The CEO encouraged managers to allow flextime for workers.","exampleKor":"그 최고 경영자는 부장들에게 직원들의 탄력 근무 시간제를 허용하도록 장려했다."},{"word":"leave","pos":"n./v.","meaning":"휴가; 떠나다, 남기다","example":"Employees can take up to 10 days annually for emergency leave.","exampleKor":"직원들은 연간 최대 10일의 긴급 휴가를 낼 수 있다."},{"word":"recommendation","pos":"n.","meaning":"추천 사항, 추천","example":"Staff were asked for recommendations on improving the break room.","exampleKor":"직원들은 휴게실 개선에 대한 추천 사항을 요청받았다."},{"word":"conference","pos":"n.","meaning":"회의, 회담","example":"This year's conference focuses on developments in the field of human resources.","exampleKor":"올해 회의는 인적 자원 분야의 개발에 중점을 두고 있다."},{"word":"schedule","pos":"v./n.","meaning":"~을 예정하다; 일정, 스케줄, (가격·요금 등을) 나열한 표","example":"Orientation is scheduled for the morning.","exampleKor":"오리엔테이션은 오전으로 예정되어 있다."},{"word":"include","pos":"v.","meaning":"포함하다","example":"The workshop curriculum includes special digital media classes.","exampleKor":"워크숍 교육 과정은 디지털 미디어 특강을 포함한다."},{"word":"result","pos":"n./v.","meaning":"결과; (~의 결과로) 되다","example":"As a result of increased sales, the marketing team was rewarded with a vacation.","exampleKor":"늘어난 매출의 결과로 마케팅팀은 포상 휴가를 받았다."},{"word":"register","pos":"v.","meaning":"등록하다","example":"Employees must register for unemployment insurance with the state government.","exampleKor":"직원들은 주 정부 주관의 실업 보험에 등록해야 한다."},{"word":"require","pos":"v.","meaning":"요구하다","example":"Staff are required to attend the insurance provider's presentation on benefits.","exampleKor":"직원들은 보험금에 대한 보험 회사의 발표회에 참석하도록 요구된다."},{"word":"grateful","pos":"adj.","meaning":"고마워하는, 감사하는","example":"Ms. Warren was grateful for her recent raise in salary.","exampleKor":"Ms. Warren은 최근의 급여 인상에 대해 고마워했다."},{"word":"overtime","pos":"n./adv.","meaning":"초과 근무, 야근; 규정 시간 외에","example":"Employees are paid $20 for every hour of overtime.","exampleKor":"직원들은 초과 근무에 대해 시간당 20달러를 받는다."},{"word":"responsibility","pos":"n.","meaning":"부담, 책임, 의무","example":"Conference fees will be paid by Direxco, but dining expenses are the participants' responsibility.","exampleKor":"총회 참가비는 Direxco사에서 지불할 것이지만 식비는 참가자 부담입니다."},{"word":"assent","pos":"v./n.","meaning":"찬성하다; 승인, 동의","example":"The managers assented to giving everyone a small raise.","exampleKor":"관리자들은 모두에게 약간의 봉급 인상을 해 주는 것에 찬성했다."},{"word":"regard","pos":"v./n.","meaning":"~을 -으로 간주하다, 여기다; 관심, 배려","example":"Workers regard prompt salary payment as a basic right.","exampleKor":"근로자들은 신속한 임금 지급을 기본 권리로 간주한다."},{"word":"tentative","pos":"adj.","meaning":"임시적인, 잠정적인","example":"The plan to increase paternity leave is still tentative.","exampleKor":"남성 육아 휴직을 늘리겠다는 계획은 여전히 임시적일 뿐이다."},{"word":"welcome","pos":"adj./v.","meaning":"반가운, 기꺼이 받아들여지는; 환영하다, 맞이하다","example":"The extra microwave was a welcome addition to the staff kitchen.","exampleKor":"추가 전자레인지는 직원용 주방에서 환영받는 물건이었다."},{"word":"function","pos":"n./v.","meaning":"행사, 연회; 작동하다","example":"The dining hall seats 100 people for private and business functions.","exampleKor":"그 식당은 개인 및 비즈니스 행사용으로 100명의 인원을 수용할 수 있다."},{"word":"commence","pos":"v.","meaning":"시작되다","example":"The new shifts will commence next week.","exampleKor":"새 교대 근무가 다음 주에 시작될 것이다."},{"word":"objective","pos":"n./adj.","meaning":"목표, 목적; 객관적인","example":"The learning objectives of the program are outlined in the brochure.","exampleKor":"프로그램의 학습 목표가 소책자에 요약되어 있다."},{"word":"excited","pos":"adj.","meaning":"신이 난, 들뜬","example":"Fred was excited about the opportunities his promotion would give him.","exampleKor":"Fred는 자신의 승진으로 제공받을 기회들에 신이 났다."},{"word":"reimbursement","pos":"n.","meaning":"상환, 변제, 배상","example":"Employees will receive reimbursement for accommodations on business trips.","exampleKor":"직원들은 출장 시 숙박 비용에 대해 상환 받을 것이다."},{"word":"treatment","pos":"n.","meaning":"대우, 처우","example":"Every staff member, regardless of position, receives the same level of treatment from Mr. Scanlyn.","exampleKor":"모든 직원들은 직위와 관계없이 Mr. Scanlyn으로부터 동일한 수준의 대우를 받는다."},{"word":"honor","pos":"n./v.","meaning":"존경, 명예; 존경하다, 명예를 주다","example":"A banquet was held in honor of our director's retirement.","exampleKor":"우리 이사님의 은퇴를 기념하는 연회가 개최되었다."},{"word":"emphasize","pos":"v.","meaning":"강조하다","example":"Lindall Inc. emphasizes the importance of employees to its success.","exampleKor":"Lindall사는 자사의 성공에 있어 직원들의 중요성을 강조한다."},{"word":"entry","pos":"n.","meaning":"(경기 등의) 참가자, 출품물","example":"The competition organizers will not accept late entries.","exampleKor":"대회 주최 측은 늦게 신청하는 참가자들을 받지 않을 것이다."},{"word":"bonus","pos":"n.","meaning":"상여금, 보너스","example":"Those who perform well receive a higher bonus at year's end.","exampleKor":"좋은 성과를 내는 사람들은 연말에 보다 높은 상여금을 받는다."},{"word":"salary","pos":"n.","meaning":"급여","example":"The base salary at Serpar is much higher than the industry norm.","exampleKor":"Serpar사의 기본 급여는 업계 표준보다 훨씬 더 높다."},{"word":"earn","pos":"v.","meaning":"(금전 등을) 벌다; (평판을) 받다, 얻다","example":"Jane earns $3,000 a month.","exampleKor":"Jane은 한 달에 3천 달러를 번다."},{"word":"arise","pos":"v.","meaning":"(문제 등이) 발생하다, 일어나다","example":"A number of employee complaints have arisen.","exampleKor":"직원들의 불만이 많이 발생했다."},{"word":"labor","pos":"n./v.","meaning":"노동; 일하다, 노동하다","example":"The new contract sparked a labor dispute.","exampleKor":"새 계약은 노동 쟁의를 일으켰다."},{"word":"union","pos":"n.","meaning":"노동조합","example":"All the employees belong to the labor union.","exampleKor":"모든 직원이 노동조합에 소속되어 있다."},{"word":"existing","pos":"adj.","meaning":"기존의, 현행의","example":"The company is restructuring the existing benefits package.","exampleKor":"회사는 기존의 복지 제도를 개혁하고 있다."},{"word":"exploit","pos":"v.","meaning":"착취하다, 부당하게 이용하다","example":"Workers Forward is dedicated to preventing employees from being exploited.","exampleKor":"Workers Forward사는 직원들이 착취당하는 것을 막는 일에 전념한다."}]},{"day":24,"title":"승진 첫 날 (인사이동)","words":[{"word":"appoint","pos":"v.","meaning":"임명하다, 지명하다","example":"President Davis appointed Roger Lance as head of finance.","exampleKor":"Davis 회장은 Roger Lance를 재무부장으로 임명했다."},{"word":"appraisal","pos":"n.","meaning":"평가","example":"Supervisors carry out performance appraisals every three months.","exampleKor":"관리자들은 석 달마다 실적 평가를 시행한다."},{"word":"promote","pos":"v.","meaning":"승진시키다; 촉진하다","example":"Ms. Wilson was promoted in April to the position of marketing director.","exampleKor":"Ms. Wilson은 4월에 마케팅 부장직으로 승진되었다."},{"word":"skilled","pos":"adj.","meaning":"숙련된, 노련한","example":"Several production plants are short of skilled workers.","exampleKor":"일부 생산 공장들은 숙련된 근로자가 부족하다."},{"word":"radically","pos":"adv.","meaning":"완전히, 철저히","example":"Several divisions will be radically restructured.","exampleKor":"일부 부서들이 완전히 개편될 것이다."},{"word":"exceptional","pos":"adj.","meaning":"뛰어난, 예외적인","example":"Paul Lang showed exceptional talent in computer programming.","exampleKor":"Paul Lang은 컴퓨터 프로그래밍에 뛰어난 재능을 보였다."},{"word":"appreciation","pos":"n.","meaning":"감사","example":"The director gave a short speech to express his appreciation.","exampleKor":"그 이사는 감사를 표하기 위해 짧은 연설을 했다."},{"word":"evaluate","pos":"v.","meaning":"평가하다","example":"Workers' performance should be evaluated annually.","exampleKor":"직원들의 실적은 매년 평가되어야 한다."},{"word":"suggest","pos":"v.","meaning":"제안하다, 추천하다","example":"Charles suggested posting a job advertisement.","exampleKor":"Charles는 채용 광고를 올리는 것을 제안했다."},{"word":"preference","pos":"n.","meaning":"선호","example":"Rita has no preference for working the night shift or the day shift.","exampleKor":"Rita는 야간 근무나 주간 근무 중 선호하는 것이 없다."},{"word":"management","pos":"n.","meaning":"경영진, 경영","example":"Management announced a new hiring plan this month.","exampleKor":"경영진은 이번 달에 새로운 고용 계획을 발표했다."},{"word":"predict","pos":"v.","meaning":"예측하다","example":"Many predict that the CEO will retire soon.","exampleKor":"많은 사람들이 최고 경영자가 곧 은퇴할 것으로 예측한다."},{"word":"transfer","pos":"v./n.","meaning":"보내다; 전근시키다; 전근, 이전","example":"The technology department will transfer the old files to the new server.","exampleKor":"기술 부서는 오래된 파일들을 새 서버로 보낼 것이다."},{"word":"award","pos":"n./v.","meaning":"상; (상 등을) 수여하다","example":"The best-employee award is given every year.","exampleKor":"최고 직원상은 매년 수여된다."},{"word":"mandatory","pos":"adj.","meaning":"의무적인","example":"Attendance to the weekly staff meeting is mandatory.","exampleKor":"주간 직원회의 출석은 의무적이다."},{"word":"competent","pos":"adj.","meaning":"유능한, 능숙한","example":"Eileen is very competent at her job and is well-liked by her staff.","exampleKor":"Eileen은 일에 있어서 매우 유능하고 그녀의 직원들에게 매우 사랑받는다."},{"word":"performance","pos":"n.","meaning":"실적, 성과; 공연, 연주, 연기","example":"The CEO attributed the company's outstanding performance to the staff.","exampleKor":"최고 경영자는 회사의 뛰어난 실적을 직원들 덕분으로 돌렸다."},{"word":"reward","pos":"v./n.","meaning":"~에 보답하다, 보상하다; 포상, 보상","example":"Management plans to reward employees' efforts with wage increases.","exampleKor":"경영진은 임금 인상으로 직원들의 노력에 보답할 계획이다."},{"word":"search","pos":"n./v.","meaning":"찾기, 수색, 조사; 찾다","example":"We have been in search of a new president ever since Mr. Rowles resigned.","exampleKor":"우리는 Mr. Rowles가 사임한 후로 계속해서 새 회장을 찾고 있다."},{"word":"inexperienced","pos":"adj.","meaning":"경험 없는, 미숙한","example":"Robert is too inexperienced to be promoted to manager.","exampleKor":"Robert는 부장으로 승진되기에 너무 경험이 없다."},{"word":"early","pos":"adj./adv.","meaning":"시간상 이른, 조기의; 일찍","example":"Ms. Jones opted for an early retirement.","exampleKor":"Ms. Jones는 조기 퇴직을 선택했다."},{"word":"designate","pos":"v.","meaning":"지명하다, 지정하다","example":"Ms. Carling designated Owen to be the project's team leader.","exampleKor":"Ms. Carling은 Owen을 그 프로젝트의 팀장으로 지명했다."},{"word":"executive","pos":"adj.","meaning":"경영의, 관리의","example":"Mr. Fulton holds an executive position at Greenway Bank.","exampleKor":"Mr. Fulton은 Greenway 은행에서 경영직을 맡고 있다."},{"word":"dedication","pos":"n.","meaning":"헌신","example":"Ms. Hayes was recognized for her dedication to the company.","exampleKor":"Ms. Hayes는 회사에 대한 헌신으로 인정받았다."},{"word":"unanimously","pos":"adv.","meaning":"만장일치로","example":"The board voted unanimously to replace the underperforming CEO.","exampleKor":"이사회는 실적이 저조한 최고 경영자를 교체하는 데 만장일치로 찬성했다."},{"word":"progress","pos":"n./v.","meaning":"진행, 진척, 진전; 진행되다, 진척시키다","example":"Daily reports are good tools for measuring employees' work progress.","exampleKor":"일일 보고서는 직원의 업무 진행 상황을 측정하는 데 좋은 도구이다."},{"word":"congratulate","pos":"v.","meaning":"축하하다","example":"The president personally congratulated the assistant on her promotion.","exampleKor":"그 사장은 보좌관의 승진을 직접 축하해 주었다."},{"word":"dismiss","pos":"v.","meaning":"해임하다, 해고하다","example":"Those staff found in violation of company regulations may be dismissed.","exampleKor":"회사 규정을 위반한 것으로 확인된 직원들은 해임될 수도 있다."},{"word":"independence","pos":"n.","meaning":"독립성","example":"Branch managers are given the independence to make some decisions.","exampleKor":"지점장들은 일부 결정을 내릴 수 있도록 독립성을 부여받았다."},{"word":"participation","pos":"n.","meaning":"참여, 참가, 가입","example":"Workers gained valuable knowledge through participation in the program.","exampleKor":"직원들은 프로그램 참여를 통해 귀중한 지식을 얻었다."},{"word":"praise","pos":"n./v.","meaning":"칭찬; 칭찬하다","example":"Stacey Randall received praise for her outstanding sales record.","exampleKor":"Stacey Randall은 뛰어난 판매 실적으로 칭찬을 받았다."},{"word":"accomplishment","pos":"n.","meaning":"성과, 업적","example":"The team was given a bonus for its accomplishments last quarter.","exampleKor":"그 팀은 지난 분기 성과에 대한 상여금을 받았다."},{"word":"deliberation","pos":"n.","meaning":"토의, 심의","example":"The deliberation about hiring new staff lasted for nearly two hours.","exampleKor":"새로운 직원들을 고용하는 것에 대한 토의는 거의 두 시간 동안 지속되었다."},{"word":"leadership","pos":"n.","meaning":"리더십, 지도력","example":"Ms. Robinson's display of leadership has earned her the respect of her staff.","exampleKor":"Ms. Robinson이 발휘한 리더십은 그녀에게 직원들의 존경심을 가져다주었다."},{"word":"retire","pos":"v.","meaning":"퇴직하다, 은퇴하다","example":"Peter Oswald retires in May after 40 years with the firm.","exampleKor":"Peter Oswald는 그 회사에 40년 근무한 끝에 5월에 퇴직한다."},{"word":"nomination","pos":"n.","meaning":"임명, 지명","example":"Sue Blaine's nomination to the board was a surprise.","exampleKor":"Sue Blaine이 이사회에 임명된 것은 놀라운 일이었다."},{"word":"reorganize","pos":"v.","meaning":"재편성하다, 재조직하다","example":"The marketing team will be reorganized after the merger.","exampleKor":"마케팅팀은 합병 이후에 재편성될 것이다."},{"word":"serve","pos":"v.","meaning":"일하다, 근무하다","example":"The marketing director will serve as the acting director of consumer relations for now.","exampleKor":"마케팅부장이 당분간 고객 서비스 부장 대행으로서 일할 것이다."},{"word":"encouragement","pos":"n.","meaning":"격려","example":"Mr. Vance offers regular encouragement to his employees.","exampleKor":"Mr. Vance는 직원들에게 주기적으로 격려를 해 준다."},{"word":"resignation","pos":"n.","meaning":"사임, 사직, 사직서","example":"The company announced the resignation of its head of development.","exampleKor":"회사는 개발부장의 사임을 발표했다."},{"word":"strictly","pos":"adv.","meaning":"엄격히","example":"International transfer opportunities are strictly limited.","exampleKor":"해외 전근 기회는 엄격히 제한된다."}]},{"day":25,"title":"드라이브 (교통)","words":[{"word":"congestion","pos":"n.","meaning":"(교통의) 체증, 혼잡","example":"Traffic congestion on the highway is heaviest between 5 P.M. and 7 P.M.","exampleKor":"고속도로의 교통 체증은 오후 5시부터 7시 사이에 가장 심하다."},{"word":"alleviate","pos":"v.","meaning":"완화하다","example":"The new freeway lane alleviated traffic congestion.","exampleKor":"새 고속도로 차선은 교통 체증을 완화했다."},{"word":"divert","pos":"v.","meaning":"우회시키다, 다른 곳으로 돌리다","example":"Traffic was diverted during construction.","exampleKor":"공사 기간 동안 차량이 우회되었다."},{"word":"detour","pos":"n.","meaning":"우회","example":"The express bus had to take a detour to avoid heavy traffic.","exampleKor":"그 고속버스는 교통 혼잡을 피하기 위해 우회해야만 했다."},{"word":"fuel","pos":"n.","meaning":"연료","example":"Our car ran out of fuel on the highway.","exampleKor":"우리 차는 고속도로에서 연료가 떨어졌다."},{"word":"malfunction","pos":"n.","meaning":"오작동, 기능 불량","example":"The car's problems stemmed from a brake malfunction.","exampleKor":"그 자동차의 문제들은 브레이크 오작동에서 비롯되었다."},{"word":"permit","pos":"v./n.","meaning":"허락하다; 허가증","example":"The store permits only shoppers to park in the lot.","exampleKor":"그 상점은 오직 쇼핑객들만 주차장에 주차하도록 허락한다."},{"word":"transportation","pos":"n.","meaning":"교통 (수단), 운송 수단","example":"All of the city's major tourist attractions are reachable by public transportation.","exampleKor":"그 도시의 모든 주요 관광지들은 대중교통으로 갈 수 있다."},{"word":"opportunity","pos":"n.","meaning":"기회","example":"The bus tour provides visitors with an opportunity to explore the city in one day.","exampleKor":"버스 투어는 방문객들에게 하루 만에 도시를 둘러볼 기회를 제공한다."},{"word":"clearly","pos":"adv.","meaning":"명확히","example":"The reporter's use of animated graphics clearly showed the flow of traffic during rush hour.","exampleKor":"그 기자의 동영상 그래픽 사용은 출퇴근 시간의 교통 흐름을 명확히 보여주었다."},{"word":"ongoing","pos":"adj.","meaning":"계속 진행 중인","example":"Ongoing roadwork is causing delays through the city center.","exampleKor":"계속 진행 중인 도로 공사가 도심 여기저기에 지체를 일으키고 있다."},{"word":"detailed","pos":"adj.","meaning":"상세한","example":"The tourist information counter provides detailed local maps for visitors.","exampleKor":"관광 안내 창구는 방문객들에게 상세한 지역 지도를 제공한다."},{"word":"alternative","pos":"n./adj.","meaning":"대안, 대체; 다른, 대신의","example":"Consider walking to work as a healthy alternative to driving.","exampleKor":"운전에 대한 건강한 대안으로 도보 출근을 고려해 보세요."},{"word":"obtain","pos":"v.","meaning":"획득하다, 얻다","example":"Driver's licenses can be obtained from the Department of Motor Vehicles.","exampleKor":"운전 면허증은 차량 관리국에서 획득할 수 있습니다."},{"word":"designated","pos":"adj.","meaning":"지정된","example":"Parking is restricted to designated spots.","exampleKor":"주차는 지정된 장소로 제한되어 있다."},{"word":"intersection","pos":"n.","meaning":"교차로, 교차 지점","example":"A traffic light is being installed at the intersection of Fifth Avenue and Main Street.","exampleKor":"신호등이 5번가와 Main가의 교차로에 설치되고 있다."},{"word":"equip","pos":"v.","meaning":"갖추다, 설비하다","example":"Newer cars come equipped with emergency kits.","exampleKor":"최신 자동차들은 비상 도구 세트가 갖추어져 나온다."},{"word":"commute","pos":"v.","meaning":"통근하다","example":"Many workers commute into the city daily by bus.","exampleKor":"많은 근로자들이 버스를 타고 매일 시내로 통근한다."},{"word":"downtown","pos":"adv.","meaning":"시내에서, 도심지로","example":"It is difficult to find free parking downtown.","exampleKor":"시내에서 무료 주차장을 찾는 것은 어렵다."},{"word":"automotive","pos":"adj.","meaning":"자동차의","example":"Automotive repair service is offered for free on new vehicles.","exampleKor":"신차에는 자동차 수리 서비스가 무료로 제공된다."},{"word":"closure","pos":"n.","meaning":"폐쇄","example":"Road closures occur frequently during the winter.","exampleKor":"도로 폐쇄는 겨울에 빈번하게 발생한다."},{"word":"vehicle","pos":"n.","meaning":"차량, 운송 수단","example":"All vehicles must be officially registered upon purchase.","exampleKor":"모든 차량은 구매 직후 정식으로 등록되어야 한다."},{"word":"platform","pos":"n.","meaning":"승강장","example":"All trains to Denver will now be departing from platform two.","exampleKor":"모든 덴버행 열차는 지금 2번 승강장에서 출발할 것입니다."},{"word":"official","pos":"n./adj.","meaning":"공무원, 관리; 공식적인","example":"Transportation officials announced plans to construct a city bypass.","exampleKor":"교통부 공무원은 도시 우회로 건설 계획을 발표했다."},{"word":"transit","pos":"n.","meaning":"교통, 수송","example":"The travel card can be used for all public transit.","exampleKor":"그 교통 카드는 모든 대중교통에 이용할 수 있습니다."},{"word":"fare","pos":"n.","meaning":"교통 요금","example":"Bus fares increased in line with gasoline prices.","exampleKor":"버스 요금이 휘발유 가격에 맞추어 인상되었다."},{"word":"expense","pos":"n.","meaning":"비용, 지출","example":"Residents agreed that the new highway was worth the expense.","exampleKor":"주민들은 새로운 고속도로가 비용을 들인 만큼 가치 있다는 데 동의했다."},{"word":"trust","pos":"n./v.","meaning":"신뢰, 신임; 믿다, 신뢰하다","example":"Car owners who earn the trust of insurers are eligible for discounts.","exampleKor":"보험 회사의 신뢰를 얻은 차주들은 할인 혜택을 받을 자격이 있다."},{"word":"head","pos":"v.","meaning":"(~의 방향으로) 나아가다, 향하게 하다","example":"The motorcyclists headed west toward the mountains.","exampleKor":"오토바이 운전자들은 산을 향해 서쪽으로 나아갔다."},{"word":"drive","pos":"v.","meaning":"(차 등을) 운전하다, 타고 가다, 조종하다","example":"Vehicles with multiple passengers are allowed to drive in the carpool lane.","exampleKor":"다수의 탑승자가 있는 차량은 다인승 전용 차선에서 운전하는 것이 허용된다."},{"word":"fine","pos":"n.","meaning":"벌금","example":"Drivers speeding in a school zone are subject to a substantial fine.","exampleKor":"어린이 보호 구역에서 과속하는 운전자들에게는 상당한 벌금이 부과된다."},{"word":"pass","pos":"v.","meaning":"지나가다, 통과하다","example":"For safety reasons, motorists should not pass other cars on the right.","exampleKor":"안전상의 이유로, 자동차 운전자들은 다른 차량의 오른쪽으로 지나가면 안 된다."},{"word":"securely","pos":"adv.","meaning":"(매듭 등이) 단단하게, 튼튼하게","example":"Passengers are required to fasten seatbelts securely.","exampleKor":"승객들은 안전벨트를 단단히 고정시켜야 한다."},{"word":"prominently","pos":"adv.","meaning":"눈에 잘 띄게, 두드러지게","example":"Traffic control signs are prominently displayed along the highway.","exampleKor":"교통 표지판이 고속도로를 따라 눈에 잘 띄게 설치되어 있다."},{"word":"reserved","pos":"adj.","meaning":"예약된, 예약한; 지정된","example":"The rail service allows passengers to book reserved seats online.","exampleKor":"철도청은 승객들이 온라인으로 좌석을 예약할 수 있게 한다."},{"word":"average","pos":"n.","meaning":"평균치, 평균","example":"Compared to last year's average, road accidents have significantly decreased.","exampleKor":"작년 평균치와 비교해 볼 때, 교통사고가 현저하게 감소했다."},{"word":"collision","pos":"n.","meaning":"충돌","example":"Fortunately, no one was hurt in the four-car collision.","exampleKor":"다행스럽게도, 4중 차량 충돌 사고에서 아무도 다치지 않았다."},{"word":"tow","pos":"v.","meaning":"(차를) 견인하다","example":"All unauthorized vehicles will be towed.","exampleKor":"허가되지 않은 모든 차량은 견인될 것입니다."},{"word":"reverse","pos":"adj.","meaning":"뒤의, 반대의","example":"Jim accidentally put the truck into reverse gear.","exampleKor":"Jim은 실수로 트럭을 후진 기어에 놓았다."},{"word":"obstruct","pos":"v.","meaning":"(전망 등을) 가리다, 차단하다; (도로 등을) 막다","example":"Passengers must not obstruct the driver's view.","exampleKor":"승객들은 운전자의 시야를 가리지 말아야 한다."}]},{"day":26,"title":"잔고와 효도 (은행)","words":[{"word":"delinquent","pos":"adj.","meaning":"(세금 등이) 연체된, 미불의","example":"The delinquent account has been suspended.","exampleKor":"그 연체된 계좌는 정지되었다."},{"word":"overdue","pos":"adj.","meaning":"(지불·반납 등의) 기한이 지난, 지불 기한이 넘은","example":"The bill for October is overdue and must be paid soon.","exampleKor":"10월 청구서는 지불 기한이 지났으므로 곧 납부되어야 한다."},{"word":"regrettably","pos":"adv.","meaning":"유감스럽게도","example":"We are regrettably unable to approve your loan.","exampleKor":"저희는 유감스럽게도 귀하의 대출을 승인할 수 없습니다."},{"word":"balance","pos":"n.","meaning":"잔고, 차감 잔액","example":"Urban Bank's Web site allows customers to check their account balance online.","exampleKor":"Urban 은행의 웹사이트는 고객들이 계좌 잔고를 온라인으로 확인할 수 있게 한다."},{"word":"deposit","pos":"v.","meaning":"입금하다, 예금하다","example":"Steve deposited his paycheck at the bank this morning.","exampleKor":"Steve는 오늘 아침에 자신의 급료를 은행에 입금했다."},{"word":"investigation","pos":"n.","meaning":"조사","example":"The government's investigation into Harp Financial revealed no signs of illegal activity.","exampleKor":"Harp Financial사에 대한 정부의 조사는 불법적인 활동의 흔적을 밝히지 못했다."},{"word":"account","pos":"n./v.","meaning":"계좌; 설명; 고려; (~의 이유를) 밝히다, 설명하다; (~의 비율을) 차지하다","example":"More than $100 must be put in the account to keep it active.","exampleKor":"계좌가 유효하도록 유지하기 위해서는 100달러 이상이 계좌에 있어야 한다."},{"word":"statement","pos":"n.","meaning":"명세서, 성명서","example":"Bank statements are sent out monthly.","exampleKor":"예금 명세서는 매달 발송됩니다."},{"word":"amount","pos":"n.","meaning":"액수, 양","example":"The amount of money needed to open a savings account is $50.","exampleKor":"예금 계좌를 개설하는 데 필요한 액수는 50달러이다."},{"word":"withdrawal","pos":"n.","meaning":"(예금의) 인출","example":"Withdrawals can be made anytime at the cash machine.","exampleKor":"예금 인출은 현금 자동 지급기에서 언제든지 가능합니다."},{"word":"previously","pos":"adv.","meaning":"이전에","example":"The SC card application requires proof of a previously opened credit card account.","exampleKor":"SC 카드 신청에는 이전에 개설했던 신용카드 계좌가 증거로 필요하다."},{"word":"due","pos":"adj.","meaning":"만기가 된, 지불 기일이 된; (금전 등이) ~에게 마땅히 지급되어야 할","example":"Payment must be received by the due date.","exampleKor":"대금은 만기일까지 수납되어야 한다."},{"word":"receive","pos":"v.","meaning":"받다, 수취하다","example":"Carmen received a statement for her credit card in the mail.","exampleKor":"Carmen은 우편으로 그녀의 신용 카드 명세서를 받았다."},{"word":"expect","pos":"v.","meaning":"예상하다, 기대하다","example":"Interest rates are expected to increase by 2 percent.","exampleKor":"금리가 2퍼센트 증가할 것으로 예상된다."},{"word":"certificate","pos":"n.","meaning":"증명서, 증서","example":"The bank requires a certificate of employment to approve the loan.","exampleKor":"그 은행은 대출을 승인하는 데 고용 증명서를 요구한다."},{"word":"document","pos":"n./v.","meaning":"서류, 문서; 기록하다, 문서를 작성하다","example":"Please submit the required tax documents by this Friday.","exampleKor":"이번 금요일까지 필요한 세무 서류들을 제출해 주세요."},{"word":"spending","pos":"n.","meaning":"소비; 지출","example":"The Vantage Checking Account is ideal for your daily spending needs.","exampleKor":"Vantage 당좌 예금 계좌는 여러분의 일상적인 소비 요구에 가장 알맞습니다."},{"word":"successfully","pos":"adv.","meaning":"성공적으로","example":"James successfully transferred $5,000 to his overseas account.","exampleKor":"James는 성공적으로 5천 달러를 그의 해외 계좌로 이체했다."},{"word":"bill","pos":"v./n.","meaning":"~에게 청구서를 보내다; 청구서, 계산서","example":"Residents will be billed separately for gas and electricity charges.","exampleKor":"거주자들은 가스와 전기 요금에 대한 청구서를 따로 받을 것이다."},{"word":"pleasure","pos":"n.","meaning":"즐거움, 기쁨, 영광","example":"Fast and friendly service makes it a pleasure to bank with Township Capital.","exampleKor":"빠르고 친절한 서비스는 Township Capital사와 거래하는 것을 즐겁게 한다."},{"word":"study","pos":"n.","meaning":"연구","example":"This study investigates the feasibility of the proposed tax cuts.","exampleKor":"이 연구는 제시된 세금 감면안의 실현 가능성을 조사한다."},{"word":"summary","pos":"n.","meaning":"요약, 개요","example":"The statement gives a summary of Cantor's financial activities.","exampleKor":"그 보고서는 Cantor사의 재정 활동에 대한 요약을 해준다."},{"word":"temporary","pos":"adj.","meaning":"임시의","example":"A temporary password is given to bank clients until they choose a new one.","exampleKor":"임시 비밀번호는 은행 고객들이 새로운 비밀번호를 선택할 때까지 제공된다."},{"word":"lower","pos":"v.","meaning":"(양·가격을) 줄이다","example":"The new tax break lowers costs for large businesses.","exampleKor":"새로운 세금 우대 조치는 대기업의 지출을 줄인다."},{"word":"transaction","pos":"n.","meaning":"거래, 업무","example":"The first five transactions will not be charged a service fee.","exampleKor":"처음 다섯 번의 거래에는 서비스 비용이 청구되지 않을 것입니다."},{"word":"double","pos":"v.","meaning":"두 배로 만들다","example":"All of the investors who purchased MAGG's stock a month ago doubled their money.","exampleKor":"한 달 전에 MAGG사의 주식을 구입한 모든 투자자는 자신들의 돈을 두 배로 만들었다."},{"word":"identification","pos":"n.","meaning":"신분증, 신분 증명서","example":"Two forms of identification are required to open an account.","exampleKor":"계좌를 개설하려면 두 가지 신분증이 필요하다."},{"word":"dissatisfaction","pos":"n.","meaning":"불만, 불평","example":"Clients registered their dissatisfaction with the bank at the Consumer Protection Office.","exampleKor":"고객들은 은행에 대한 그들의 불만을 고객 보호 사무소에 등록했다."},{"word":"in common","pos":"phr.","meaning":"공통으로, 공동으로","example":"Credit unions and banks have much in common.","exampleKor":"신용 협동조합과 은행은 많은 공통점이 있다."},{"word":"interest","pos":"n.","meaning":"관심; 권리; 이자","example":"Investors have shown great interest in shares of Speedy Motors.","exampleKor":"투자자들은 Speedy Motors사 주식에 큰 관심을 보여 왔다."},{"word":"reject","pos":"v.","meaning":"거절하다, 거부하다","example":"Sarah was rejected for a mortgage application at Singer Bank.","exampleKor":"Sarah는 Singer 은행에서 융자 신청을 거절당했다."},{"word":"relation","pos":"n.","meaning":"관계","example":"Relations between the financial corporation and investors became strained.","exampleKor":"금융 기업과 투자자들 사이의 관계가 불편해졌다."},{"word":"tentatively","pos":"adv.","meaning":"임시로, 시험적으로","example":"Helen tentatively agreed to invest $10,000 in Jim's company.","exampleKor":"Helen은 1만 달러를 Jim의 회사에 투자하는 것에 임시로 동의했다."},{"word":"alternatively","pos":"adv.","meaning":"그렇지 않으면, 그 대신에","example":"The money can go in a savings account; alternatively, it can be placed into an investment fund.","exampleKor":"그 돈은 예금 계좌로 들어갈 수 있으며, 그렇지 않으면 투자 펀드에 투자될 수도 있습니다."},{"word":"attentive","pos":"adj.","meaning":"주의 깊은, 세심한","example":"Martin was very attentive while he discussed investment options with the advisor.","exampleKor":"Martin은 투자 선택권에 대해 고문과 논의하는 동안 매우 주의 깊었다."},{"word":"convert","pos":"v.","meaning":"전환하다, 변환하다","example":"Savings accounts can be converted into mutual funds at no charge.","exampleKor":"보통 예금 계좌는 무료로 뮤추얼 펀드로 전환될 수 있습니다."},{"word":"heavily","pos":"adv.","meaning":"몹시, 심하게","example":"The institution heavily relies on capital gained from lending.","exampleKor":"그 기관은 대출로 얻은 자금에 지나치게 의존하고 있다."},{"word":"loan","pos":"n.","meaning":"대출, 대출금","example":"The couple took out a loan to finance their child's college education.","exampleKor":"그 부부는 자녀의 대학 교육비를 대기 위해 대출을 받았다."},{"word":"unexpected","pos":"adj.","meaning":"예기치 않은","example":"Price drops were an unexpected side effect of the economic reform policy.","exampleKor":"물가 하락은 경제 개혁 정책의 예기치 않은 부작용이었다."},{"word":"cash","pos":"v.","meaning":"현금으로 바꾸다","example":"The bank refuses to cash the check without proper identification.","exampleKor":"은행은 적절한 신분증이 없으면 수표를 현금으로 바꾸어 주기를 거부한다."},{"word":"mortgage","pos":"n.","meaning":"(담보) 대출","example":"Higher mortgage rates will hurt homeowners.","exampleKor":"더 높은 담보 대출 금리는 주택 소유자들에게 손해를 입힐 것이다."},{"word":"payable","pos":"adj.","meaning":"지불해야 하는","example":"Make all checks payable to Everson Ltd.","exampleKor":"모든 수표가 Everson사에 지불되도록 해 주십시오."},{"word":"personal","pos":"adj.","meaning":"개인의","example":"Jane visited the bank to cash a personal check.","exampleKor":"Jane은 개인 수표를 현금으로 바꾸기 위해 은행에 들렀다."},{"word":"practice","pos":"n./v.","meaning":"관행, 관례; 연습하다, 실습하다","example":"The investment bank is known for its responsible business practice.","exampleKor":"그 투자 은행은 책임감 있는 사업 관행으로 알려져 있다."}]},{"day":27,"title":"친구와 주식 (투자)","words":[{"word":"investment","pos":"n.","meaning":"투자, 투자금","example":"Development of a new laptop will require a minimum investment of $250,000.","exampleKor":"새로운 노트북 컴퓨터의 개발은 25만 달러의 최소 투자금을 필요로 한다."},{"word":"lucrative","pos":"adj.","meaning":"수익성 있는, 돈벌이가 되는","example":"The company scanned the market for lucrative investment opportunities.","exampleKor":"그 회사는 수익성 있는 투자 기회를 찾기 위해 시장을 탐색했다."},{"word":"inherently","pos":"adv.","meaning":"본질적으로","example":"Stock market investment is considered inherently risky.","exampleKor":"주식 시장 투자는 본질적으로 위험하다고 여겨진다."},{"word":"secure","pos":"v.","meaning":"확보하다, 얻어 내다; 안전하게 지키다; 고정시키다","example":"The retailer saved some money by securing favorable terms on a loan.","exampleKor":"그 소매상인은 대출에 대해 유리한 조건을 확보함으로써 약간의 돈을 절약했다."},{"word":"foreseeable","pos":"adj.","meaning":"예견할 수 있는","example":"The recent financial losses were not foreseeable.","exampleKor":"최근의 재정 손실은 예견할 수 없었다."},{"word":"innate","pos":"adj.","meaning":"타고난","example":"Mr. Rogers has an innate ability to predict market fluctuations.","exampleKor":"Mr. Rogers는 시장 변동을 예측하는 데 타고난 능력을 갖고 있다."},{"word":"property","pos":"n.","meaning":"재산","example":"All real estate transactions are liable for property tax.","exampleKor":"모든 부동산 거래들은 재산세를 납입할 의무가 있다."},{"word":"on behalf of","pos":"phr.","meaning":"~을 대신해서","example":"The broker received authorization to sell shares on behalf of his client.","exampleKor":"그 중개인은 고객을 대신해 주식을 매각할 수 있는 권한을 받았다."},{"word":"lease","pos":"n.","meaning":"임대차 (계약)","example":"Investors agreed to a 25-year lease on the office building.","exampleKor":"투자자들은 사무실 건물에 대한 25년 임대차 계약에 동의했다."},{"word":"sponsor","pos":"v./n.","meaning":"후원하다; 후원자","example":"Reed Bank sponsored a series of financial seminars.","exampleKor":"Reed 은행은 일련의 재무 세미나를 후원했다."},{"word":"propose","pos":"v.","meaning":"제안하다","example":"Gould Capital proposed to fund Ms. Locke's venture.","exampleKor":"Gould Capital사는 Ms. Locke의 벤처 사업에 자금을 대는 것을 제안했다."},{"word":"support","pos":"n./v.","meaning":"후원, 원조, 지지; 지원하다, 후원하다, 살게 하다, (생명·기력 등을) 유지하다","example":"The small business owner is seeking the support of investors.","exampleKor":"그 소규모 사업주는 투자자의 후원을 구하고 있다."},{"word":"distribution","pos":"n.","meaning":"분배, 배급","example":"The distribution of profits will be announced to shareholders next week.","exampleKor":"수익 분배는 다음 주에 주주들에게 공표될 것이다."},{"word":"consider","pos":"v.","meaning":"고려하다","example":"Before buying a property, it's important to consider the hidden expenses involved.","exampleKor":"부동산을 매입하기 전에 관련된 잠재 비용을 고려하는 것이 중요하다."},{"word":"nearly","pos":"adv.","meaning":"거의, 대략","example":"The firm was operated so well that investors nearly doubled their money.","exampleKor":"회사가 매우 잘 운영되어서 투자자들은 투자금을 거의 두 배로 만들었다."},{"word":"consent","pos":"n.","meaning":"동의, 허락","example":"A sale of the business will require the consent of shareholders.","exampleKor":"사업체의 매각은 주주들의 동의를 필요로 한다."},{"word":"gratitude","pos":"n.","meaning":"고마움, 감사","example":"The CEO showed his gratitude to those who have stayed with the company from the beginning.","exampleKor":"최고 경영자는 초창기부터 회사에 있었던 사람들에게 그의 고마움을 표했다."},{"word":"consult","pos":"v.","meaning":"상의하다, 상담하다","example":"Unsure about whether to invest, Jacob consulted with his financial advisor.","exampleKor":"투자할지 확실하지 않았기 때문에, Jacob은 자신의 재정 고문과 상의했다."},{"word":"advice","pos":"n.","meaning":"조언, 충고","example":"The bank provides its clients with advice on how to save more money.","exampleKor":"그 은행은 고객들에게 더 많은 돈을 저축할 수 있는 방법에 대한 조언을 제공한다."},{"word":"partially","pos":"adv.","meaning":"부분적으로, 일부분은","example":"Indigo Inc. will be partially funded by the sale of bonds.","exampleKor":"Indigo사는 채권의 매각을 통해 부분적으로 자금이 제공될 것이다."},{"word":"evident","pos":"adj.","meaning":"분명한, 명백한","example":"The executives of Panta Ltd. are pleased at the evident interest shown in their public offering.","exampleKor":"Panta사의 임원들은 회사 주식 공모에 보여진 분명한 관심에 기뻐했다."},{"word":"reliability","pos":"n.","meaning":"신뢰도, 믿음직함","example":"KTR's success is dependent on the reliability of its financial research analysis.","exampleKor":"KTR사의 성공은 회사의 재무 연구 분석에 대한 신뢰도에 달려 있다."},{"word":"cautious","pos":"adj.","meaning":"조심하는, 신중한","example":"Analysts are cautious about recommending the troubled company's stocks.","exampleKor":"분석가들은 문제가 많은 회사의 주식을 추천하는 것에 대해 조심한다."},{"word":"insight","pos":"n.","meaning":"식견, 통찰력","example":"The feature article on Dunbar offered valuable insight into the company's operations.","exampleKor":"Dunbar사에 대한 특집 기사는 그 회사 경영에 대한 귀중한 식견을 제공했다."},{"word":"portfolio","pos":"n.","meaning":"포트폴리오, 투자 자산 구성","example":"The advisor suggested that his client diversify her portfolio.","exampleKor":"그 고문은 그의 고객에게 포트폴리오를 다양화해야 한다고 제안했다."},{"word":"possible","pos":"adj.","meaning":"가능한, 있음 직한","example":"Cautious investors take every possible measure to prevent losses.","exampleKor":"신중한 투자자들은 손실을 막기 위해 모든 가능한 조치를 취한다."},{"word":"speculation","pos":"n.","meaning":"추측","example":"Company shares fell amid growing speculation of bankruptcy.","exampleKor":"파산에 대한 추측이 증가하는 가운데 회사 주식이 하락했다."},{"word":"solely","pos":"adv.","meaning":"전적으로","example":"Their interest was solely in foreign investment.","exampleKor":"그들의 관심은 전적으로 해외 투자에만 있었다."},{"word":"entrepreneur","pos":"n.","meaning":"사업가","example":"Rosedale Investments offers venture capital to young entrepreneurs.","exampleKor":"Rosedale Investments사는 젊은 사업가들에게 벤처 자금을 제공한다."},{"word":"eventually","pos":"adv.","meaning":"결국, 마침내","example":"Stocks are expected to stabilize eventually.","exampleKor":"주식이 결국에는 안정될 것으로 예측된다."},{"word":"shareholder","pos":"n.","meaning":"주주","example":"Shareholders can now gain access to updated financial reports on the company's Web site.","exampleKor":"주주들은 이제 회사 웹사이트에서 갱신된 재정 보고서를 볼 수 있다."},{"word":"outlook","pos":"n.","meaning":"전망","example":"The outlook for financial markets is positive.","exampleKor":"금융 시장의 전망은 밝다."},{"word":"stability","pos":"n.","meaning":"안정, 안정성","example":"Sound economic policies are essential for long-term stability.","exampleKor":"견고한 경제 정책들이 장기적인 안정을 위해 꼭 필요하다."},{"word":"bond","pos":"n.","meaning":"채권","example":"The government issued public bonds to raise money for infrastructure projects.","exampleKor":"정부는 기반 시설 사업 자금을 모으기 위해 공모 채권을 발행했다."},{"word":"depreciation","pos":"n.","meaning":"가치 하락, 화폐의 구매력 저하","example":"Due to the currency depreciation, many investors experienced a loss.","exampleKor":"화폐 가치 하락으로 인해 많은 투자자들이 손해를 입었다."},{"word":"increasing","pos":"adj.","meaning":"증가하는","example":"Increasing market pressure led banks to decrease lending rates.","exampleKor":"증가하는 시장 압박은 은행들이 대출 금리를 인하하는 것으로 이어졌다."},{"word":"prevalent","pos":"adj.","meaning":"유행하고 있는, 널리 퍼진","example":"Analysts watch the most prevalent trends in the market.","exampleKor":"분석가들은 시장에서 가장 유행하고 있는 경향을 주시한다."},{"word":"rapid","pos":"adj.","meaning":"빠른, 신속한","example":"Utility companies have been growing at a rapid rate in suburban areas.","exampleKor":"공익 기업들이 교외 지역에서 빠른 속도로 성장하고 있다."},{"word":"unprecedented","pos":"adj.","meaning":"전례 없는","example":"Housing prices in the region rose an unprecedented 50 percent in just six months.","exampleKor":"그 지역의 주택 가격이 6개월 만에 50퍼센트라는 전례 없는 상승을 보였다."},{"word":"yield","pos":"v.","meaning":"(이윤을) 가져오다, 산출하다","example":"Our investments for the past fiscal year yielded returns exceeding 100 percent.","exampleKor":"지난 회계 연도 동안의 우리의 투자는 100퍼센트를 넘는 이윤을 가져왔다."}]},{"day":28,"title":"클래식한 집 (건물·주택)","words":[{"word":"furnished","pos":"adj.","meaning":"가구가 비치된","example":"Furnished apartments often cost more to rent than those that come empty.","exampleKor":"가구가 비치된 아파트는 가구가 없는 곳보다 대개 임대하는 데 비용이 더 든다."},{"word":"residence","pos":"n.","meaning":"거주지, 주택","example":"Students usually attend the school closest to their residence.","exampleKor":"학생들은 보통 자신의 집에서 가장 가까운 학교에 다닌다."},{"word":"spacious","pos":"adj.","meaning":"(공간이) 넓은","example":"The corporate offices are equipped with a spacious kitchen area.","exampleKor":"그 회사 사무실에는 넓은 주방이 갖추어져 있다."},{"word":"drape","pos":"v.","meaning":"(방 등을 커튼 등으로) 장식하다","example":"The decorator draped the living room windows with a silk curtain.","exampleKor":"그 장식가는 거실 창문들을 실크 커튼으로 장식했다."},{"word":"unoccupied","pos":"adj.","meaning":"(집 등이) 비어 있는, 사람이 살지 않는","example":"The top floor has been unoccupied for four months.","exampleKor":"꼭대기 층은 넉 달간 비어 있었다."},{"word":"renovation","pos":"n.","meaning":"수리, 개조","example":"The archives room will be closed for renovation.","exampleKor":"자료 보관실은 수리를 위해 폐쇄될 예정이다."},{"word":"appropriate","pos":"adj.","meaning":"적당한, 적합한","example":"The apartment's size is appropriate for a family of four.","exampleKor":"그 아파트의 규모는 4인 가족에게 적당하다."},{"word":"delay","pos":"v./n.","meaning":"연기하다, ~을 뒤로 미루다; 지연, 연기","example":"The landlord repeatedly delayed repairing the roof.","exampleKor":"집주인은 여러 차례 지붕 수리를 연기했다."},{"word":"community","pos":"n.","meaning":"지역 사회, 공동체","example":"Plans for building a new airport were met with strong community opposition.","exampleKor":"새 공항을 건설하는 계획은 지역 사회의 강한 반대에 부딪혔다."},{"word":"construction","pos":"n.","meaning":"건설, 건축","example":"The construction of the bridge is progressing well.","exampleKor":"교량 건설은 순조롭게 진행되고 있다."},{"word":"repair","pos":"v.","meaning":"수리하다","example":"The plumber repaired the leaking pipe.","exampleKor":"그 배관공이 새는 파이프를 수리했다."},{"word":"currently","pos":"adv.","meaning":"현재","example":"The museum is currently closed due to reconstruction.","exampleKor":"박물관은 재건으로 인해 현재 폐쇄 중이다."},{"word":"regularly","pos":"adv.","meaning":"정기적으로","example":"A gardener regularly does yard work in front of the home.","exampleKor":"정원사는 정기적으로 그 집 앞에서 정원 일을 한다."},{"word":"arrange","pos":"v.","meaning":"배열하다, 정돈하다","example":"Miranda arranged the boardroom furniture in a functional way.","exampleKor":"Miranda는 중역 회의실 가구를 기능적으로 배열했다."},{"word":"location","pos":"n.","meaning":"장소, 위치","example":"The bay area is an ideal location for a house.","exampleKor":"그 만 일대는 주거지로 이상적인 장소이다."},{"word":"restore","pos":"v.","meaning":"복구하다, 회복시키다","example":"The historic sites were restored to their original appearance.","exampleKor":"유적지들은 원래 모습으로 복구되었다."},{"word":"presently","pos":"adv.","meaning":"현재","example":"The entrance is presently under construction.","exampleKor":"입구는 현재 공사 중입니다."},{"word":"numerous","pos":"adj.","meaning":"많은","example":"The condominium has been rented to numerous families in recent years.","exampleKor":"그 아파트는 최근에 많은 가구에 임대되었다."},{"word":"abandon","pos":"v.","meaning":"그만두다; 버리다","example":"The building project was abandoned when funds ran out.","exampleKor":"건설 프로젝트는 자금이 고갈되자 중단되었다."},{"word":"contractor","pos":"n.","meaning":"계약자, 도급업자","example":"The contractor expects to finish all renovations in one month.","exampleKor":"그 계약자는 모든 수리를 한 달 안에 끝낼 것으로 예상한다."},{"word":"develop","pos":"v.","meaning":"개발하다","example":"Asiawide is developing the property into a complex of townhouses.","exampleKor":"Asiawide사는 그 땅을 연립 주택 단지로 개발하고 있다."},{"word":"maintain","pos":"v.","meaning":"유지하다, 관리하다","example":"Tenants must pay fees to maintain the building.","exampleKor":"임차인들은 건물 유지를 위한 비용을 지불해야 한다."},{"word":"densely","pos":"adv.","meaning":"빽빽이, 밀집하여","example":"Hong Kong is densely packed with apartment buildings.","exampleKor":"홍콩은 아파트 건물들로 빽빽이 들어차 있다."},{"word":"prepare","pos":"v.","meaning":"준비하다, 채비를 갖추다","example":"The custodian is preparing the apartment for the new tenants.","exampleKor":"그 관리자는 새로운 세입자를 위해 아파트를 준비하고 있다."},{"word":"finally","pos":"adv.","meaning":"결국, 마침내","example":"The vacant lot was finally sold for $1.2 million.","exampleKor":"그 공터는 결국 120만 달러에 팔렸다."},{"word":"district","pos":"n.","meaning":"지역, 지구","example":"The business district is the most expensive area of city.","exampleKor":"그 상업 지구는 도시에서 가장 비싼 지역이다."},{"word":"renewal","pos":"n.","meaning":"재개발","example":"The city embarked on an urban renewal project.","exampleKor":"그 도시는 도시 재개발 프로젝트에 착수했다."},{"word":"compulsory","pos":"adj.","meaning":"의무적인","example":"Obtaining permission for home renovations is compulsory.","exampleKor":"주택 개조를 위한 허가 취득은 의무적이다."},{"word":"interfere","pos":"v.","meaning":"방해하다, 해치다","example":"Persistent bad weather interfered with construction progress.","exampleKor":"계속되는 악천후가 공사 진행을 방해했다."},{"word":"relocation","pos":"n.","meaning":"이전, 재배치","example":"Relocation of the company's offices can begin as soon as the new building is completed.","exampleKor":"그 회사 사무실의 이전은 새 건물이 준공되는 대로 시작할 수 있다."},{"word":"totally","pos":"adv.","meaning":"완전히, 전적으로","example":"The theater has been totally renovated and will reopen soon.","exampleKor":"그 극장은 완전히 개조되었고 곧 다시 개관할 것이다."},{"word":"actually","pos":"adv.","meaning":"실제로, 사실은","example":"Axiom Tower has fewer floors than the Wade Building, but it is actually taller.","exampleKor":"Axiom Tower는 Wade Building보다 층수가 더 적지만, 실제로는 더 높다."},{"word":"architect","pos":"n.","meaning":"건축가","example":"Architects at the firm of McCall and Associates are busy working on a design for the building.","exampleKor":"McCall and Associates사의 건축가들은 건물을 설계하느라 바쁘다."},{"word":"enlarge","pos":"v.","meaning":"확장하다, 확대하다","example":"The parking area will need to be enlarged to accommodate more cars.","exampleKor":"주차 구역은 더 많은 자동차를 수용하기 위해 확장되어야 할 것이다."},{"word":"install","pos":"v.","meaning":"설치하다, 장치하다","example":"The Internet line will be installed on Monday.","exampleKor":"인터넷 회선은 월요일에 설치될 것이다."},{"word":"suppose","pos":"v.","meaning":"생각하다, 추측하다","example":"The building project could take longer to finish than anyone supposes.","exampleKor":"그 건축 프로젝트는 모두가 생각하는 것보다 완수하는 데 더 오래 걸릴 수도 있다."},{"word":"permanent","pos":"adj.","meaning":"영구적인","example":"Please write your permanent address in the space provided.","exampleKor":"제시된 공란에 본적을 기입해 주세요."},{"word":"adjacent","pos":"adj.","meaning":"인접한","example":"The storage room is adjacent to the administrative offices.","exampleKor":"창고는 행정실에 인접해 있다."},{"word":"consist","pos":"v.","meaning":"구성되다, 이루어지다","example":"The center consists of two conference rooms.","exampleKor":"그 센터는 두 개의 회의실로 구성되어 있다."},{"word":"utility","pos":"n.","meaning":"공공시설; 공공요금","example":"Ohio Water was named the best utility company in America.","exampleKor":"Ohio Water사는 미국 내 최고의 공공 기업으로 지명되었다."}]},{"day":29,"title":"일기예보 (환경)","words":[{"word":"conserve","pos":"v.","meaning":"보존하다, 유지하다","example":"Measures were introduced to conserve forests in the region.","exampleKor":"그 지역의 숲을 보존하기 위한 조치가 도입되었다."},{"word":"chance","pos":"n.","meaning":"가능성, 기회","example":"The morning weather report predicted a 30 percent chance of rain today.","exampleKor":"아침 일기 예보에서는 오늘 비가 올 가능성이 30퍼센트라고 예상했다."},{"word":"forecast","pos":"n.","meaning":"(날씨의) 예보","example":"The news station gives hourly weather forecasts.","exampleKor":"그 뉴스 방송국은 매시간 일기 예보를 제공한다."},{"word":"waste","pos":"n.","meaning":"쓰레기, 폐기물","example":"Recyclable waste must be placed in the designated receptacles.","exampleKor":"재활용 쓰레기는 지정된 용기에 넣어야 한다."},{"word":"dispose","pos":"v.","meaning":"처분하다, 처리하다","example":"Manufacturers must dispose of their waste appropriately.","exampleKor":"제조업체들은 폐기물을 적절하게 처분해야 한다."},{"word":"recycling","pos":"n.","meaning":"재활용","example":"Recycling saves energy and reduces acid rain.","exampleKor":"재활용은 에너지를 절약하고 산성비를 감소시킨다."},{"word":"clear","pos":"adj./adv.","meaning":"맑게 갠; 명백한, 분명한; 또렷하게, 완전히; 떨어져서","example":"The picnic was held at the park on a clear day.","exampleKor":"맑게 갠 날 공원에서 소풍이 열렸다."},{"word":"damage","pos":"n./v.","meaning":"피해, 손해; (물건을) 손상시키다","example":"The thunderstorm caused extensive damage to the region.","exampleKor":"폭풍우가 그 지역에 막대한 피해를 입혔다."},{"word":"significant","pos":"adj.","meaning":"상당한; 중대한, 중요한","example":"Hurricane Aida produced significant winds in excess of 200 kilometers an hour.","exampleKor":"허리케인 Aida는 시속 200킬로미터를 초과하는 상당한 바람을 만들어냈다."},{"word":"solution","pos":"n.","meaning":"해결책","example":"Solar power is one solution to energy problems.","exampleKor":"태양력은 에너지 문제에 대한 하나의 해결책이다."},{"word":"occur","pos":"v.","meaning":"(일이) 발생하다, 생기다","example":"Earthquakes occur frequently in several regions of Japan.","exampleKor":"지진은 일본의 여러 지역에서 자주 발생한다."},{"word":"ideal","pos":"adj.","meaning":"이상적인","example":"The weather this week has been ideal for a camping trip.","exampleKor":"이번 주 날씨는 캠핑 여행을 가기에 이상적이었다."},{"word":"preserve","pos":"v.","meaning":"보존하다, 보호하다","example":"EnviroCore's mandate is to preserve natural habitats in North America.","exampleKor":"EnviroCore의 임무는 북아메리카의 자연 서식지를 보존하는 것이다."},{"word":"aid","pos":"n.","meaning":"원조","example":"The government pledged $15 million in aid to repair flood damage.","exampleKor":"정부는 홍수 피해를 복구하는 데 1,500만 달러의 원조를 약속했다."},{"word":"excessive","pos":"adj.","meaning":"지나친, 과도한","example":"Excessive garbage is a serious problem for many megacities.","exampleKor":"지나친 쓰레기는 많은 대도시의 심각한 문제이다."},{"word":"intensively","pos":"adv.","meaning":"집중적으로","example":"The wind blew intensively for hours during the storm.","exampleKor":"폭풍이 칠 때 바람이 몇 시간 동안 집중적으로 불었다."},{"word":"vary","pos":"v.","meaning":"다르다, 다양하다","example":"The level of water in the lake varies greatly from year to year.","exampleKor":"그 호수의 수위는 해마다 크게 다르다."},{"word":"pleasing","pos":"adj.","meaning":"즐거운, 기분 좋은, 만족스러운","example":"Trees in city parks are not only pleasing to see, but environmentally beneficial.","exampleKor":"시립 공원의 나무들은 보기에 즐거울 뿐만 아니라, 환경적으로도 이롭다."},{"word":"mark","pos":"n./v.","meaning":"점수, 평점, 표시; 기념하다, 축하하다","example":"Allor Corp. received an excellent mark from environment monitoring groups.","exampleKor":"Allor사는 환경 감시 단체들로부터 우수한 점수를 받았다."},{"word":"inaccessible","pos":"adj.","meaning":"접근이 불가능한, 이용이 불가능한","example":"The wildlife park is inaccessible by car, so visitors have to take a ferry.","exampleKor":"그 야생 공원은 자동차로 접근이 불가능해서, 방문객들은 나룻배를 타고 가야 한다."},{"word":"disturb","pos":"v.","meaning":"방해하다","example":"The guests were disturbed by the noise from the construction site.","exampleKor":"손님들은 건설 현장으로부터 나는 소리에 방해받았다."},{"word":"pollutant","pos":"n.","meaning":"오염 물질","example":"Automotive exhaust introduces harmful pollutants into the air.","exampleKor":"자동차 배기가스는 유해한 오염 물질을 대기 중으로 내보낸다."},{"word":"emission","pos":"n.","meaning":"배기가스, 방출","example":"New laws now limit emissions from cars.","exampleKor":"새로운 법률이 이제부터 자동차 배기가스 양을 제한한다."},{"word":"dense","pos":"adj.","meaning":"빽빽한, 밀집한","example":"The Black Forest is so dense that it appears dark even at noon.","exampleKor":"Black 숲은 너무 빽빽해서 한낮에도 어두워 보인다."},{"word":"environmental","pos":"adj.","meaning":"환경적인","example":"Climate change has become a major global environmental issue.","exampleKor":"기후 변화는 전 세계적으로 중요한 환경 문제가 되었다."},{"word":"consistent","pos":"adj.","meaning":"일치하는, 지속적인, 한결같은","example":"Factory construction must be consistent with government environmental regulations.","exampleKor":"공장 건설은 정부 환경 규정에 일치해야 한다."},{"word":"leak","pos":"n./v.","meaning":"누출, 누출량; (물·빛이) 새게 하다","example":"A leak in an oil pipeline caused considerable sickness in wildlife.","exampleKor":"송유관의 누출이 야생 동물들에게 많은 질병을 야기했다."},{"word":"organization","pos":"n.","meaning":"단체","example":"Many organizations have grouped together to protect the African savanna.","exampleKor":"많은 단체가 아프리카 사바나를 보호하기 위해 함께 뭉쳤다."},{"word":"continually","pos":"adv.","meaning":"계속해서","example":"The processing plant continually polluted nearby lakes.","exampleKor":"그 가공 처리 공장은 계속해서 인근 호수들을 오염시켰다."},{"word":"contaminate","pos":"v.","meaning":"오염시키다","example":"The water was contaminated with gasoline.","exampleKor":"물이 휘발유로 오염되었다."},{"word":"disaster","pos":"n.","meaning":"재난","example":"Emergency procedures are implemented in case of a natural disaster.","exampleKor":"자연재해가 발생할 시에는 비상 절차가 시행된다."},{"word":"discharge","pos":"v.","meaning":"방출하다","example":"It is illegal to discharge industrial chemicals into the environment.","exampleKor":"산업용 화학 물질을 자연환경으로 방출하는 것은 불법이다."},{"word":"resource","pos":"n.","meaning":"자원","example":"Designating lands as national parks can help preserve natural resources.","exampleKor":"토지를 국립 공원으로 지정하는 것은 천연자원을 보존하는 데 도움이 된다."},{"word":"prominent","pos":"adj.","meaning":"유명한, 두드러진","example":"Mr. Goldstein is a prominent expert in the energy industry.","exampleKor":"Mr. Goldstein은 에너지 업계에서 유명한 전문가이다."},{"word":"deplete","pos":"v.","meaning":"고갈시키다","example":"The area's water resources have been depleted, causing a drop in produce.","exampleKor":"그 지역의 수자원이 고갈되면서 농산물 감소의 원인이 되었다."},{"word":"purify","pos":"v.","meaning":"정화시키다","example":"The plant purifies the water before it is offered to the local population.","exampleKor":"그 공장은 지역 주민들에게 제공되기 전에 물을 정화시킨다."},{"word":"endangered","pos":"adj.","meaning":"멸종 위기에 처한","example":"WildAid is fighting to protect endangered species.","exampleKor":"WildAid는 멸종 위기에 처한 종들을 보호하기 위해 싸우고 있다."},{"word":"extinction","pos":"n.","meaning":"멸종","example":"Polar bears are now in danger of extinction.","exampleKor":"북극곰은 현재 멸종 위기에 처해 있다."},{"word":"drought","pos":"n.","meaning":"가뭄","example":"The persistent drought affected the water supply.","exampleKor":"계속되는 가뭄이 급수에 영향을 주었다."},{"word":"inflict","pos":"v.","meaning":"(고통·피해를) 입히다, 가하다","example":"The new dam has inflicted considerable damage on the local communities.","exampleKor":"새로운 댐이 지역 사회에 상당한 피해를 입혔다."},{"word":"migration","pos":"n.","meaning":"이동, 이주","example":"The tank was isolated to prevent the migration of contaminants.","exampleKor":"탱크는 오염 물질의 이동을 막기 위해 격리되었다."},{"word":"ecology","pos":"n.","meaning":"생태, 자연환경","example":"Global warming alters the ecology of our planet.","exampleKor":"지구 온난화는 지구의 생태를 변화시킨다."},{"word":"habitat","pos":"n.","meaning":"(동·식물의) 서식지","example":"The plant rarely grows outside its natural habitat.","exampleKor":"그 식물은 자연 서식지 밖에서는 거의 자라지 않는다."}]},{"day":30,"title":"심각한 병 (건강)","words":[{"word":"fatigue","pos":"n.","meaning":"피로","example":"Too much stress can lead to fatigue.","exampleKor":"과도한 스트레스는 피로로 이어질 수 있다."},{"word":"checkup","pos":"n.","meaning":"건강 진단","example":"Yearly medical checkups are required for public school students.","exampleKor":"공립 학교 학생들에게는 매년 건강 진단이 요구된다."},{"word":"symptom","pos":"n.","meaning":"증상","example":"The lawyer exhibited symptoms of a stress disorder.","exampleKor":"그 변호사는 스트레스 장애 증상을 보였다."},{"word":"physician","pos":"n.","meaning":"내과 의사","example":"Mr. Bentley consulted a physician about his high blood pressure.","exampleKor":"Mr. Bentley는 고혈압으로 의사에게 진찰을 받았다."},{"word":"diagnosis","pos":"n.","meaning":"진단","example":"The doctor's diagnosis turned out to be wrong.","exampleKor":"그 의사의 진단은 잘못된 것으로 판명되었다."},{"word":"prescribe","pos":"v.","meaning":"(약을) 처방하다","example":"The doctor prescribed a remedy for Elaine's cold.","exampleKor":"의사가 Elaine의 감기를 위한 치료약을 처방했다."},{"word":"recovery","pos":"n.","meaning":"회복, 쾌유","example":"Time is needed to make a complete recovery.","exampleKor":"완전히 회복하려면 시간이 필요하다."},{"word":"recognize","pos":"v.","meaning":"인정하다, 알아보다","example":"Many alternative medicines are not recognized as valid treatments.","exampleKor":"많은 대체 약품들은 유효한 치료법으로 인정되지 않는다."},{"word":"join","pos":"v.","meaning":"~에 가입하다","example":"Employees are encouraged to join the health club.","exampleKor":"직원들은 헬스클럽에 가입하도록 권장된다."},{"word":"comprehensive","pos":"adj.","meaning":"종합적인, 포괄적인","example":"Executives are required to undergo a comprehensive physical examination once a year.","exampleKor":"경영진은 1년에 한 번 종합 신체검사를 받도록 요구된다."},{"word":"participate","pos":"v.","meaning":"참여하다, 참가하다","example":"Over 100 people participated in the medical study.","exampleKor":"100명이 넘는 사람들이 의학 연구에 참여했다."},{"word":"recommend","pos":"v.","meaning":"권고하다, 추천하다","example":"The doctor recommended that Phillip get enough rest.","exampleKor":"의사는 Phillip에게 충분한 휴식을 취하라고 권고했다."},{"word":"necessary","pos":"adj.","meaning":"필요한","example":"Surgery may be necessary to remove the patient's tumor.","exampleKor":"환자의 종양을 제거하기 위해 수술이 필요할 수도 있다."},{"word":"ability","pos":"n.","meaning":"능력","example":"Some diseases weaken the body's ability to defend itself.","exampleKor":"몇몇 질병은 스스로를 방어하는 신체 능력을 약화시킨다."},{"word":"operation","pos":"n.","meaning":"수술","example":"Mr. Stanley underwent a four-hour operation on his heart.","exampleKor":"Mr. Stanley는 4시간에 걸친 심장 수술을 받았다."},{"word":"cleanliness","pos":"n.","meaning":"청결","example":"Maintaining cleanliness can help prevent the spread of bacteria.","exampleKor":"청결을 유지하는 것은 세균의 확산을 막는 데 도움이 될 수 있다."},{"word":"duration","pos":"n.","meaning":"지속 기간, 지속","example":"The duration of the illness may vary from one person to the next.","exampleKor":"병의 지속 기간은 개인에 따라 다를 수 있다."},{"word":"examination","pos":"n.","meaning":"진찰, 검사","example":"Dr. Knowles began the patient's examination by asking a series of questions.","exampleKor":"Dr. Knowles는 일련의 질문을 함으로써 환자의 진찰을 시작했다."},{"word":"eliminate","pos":"v.","meaning":"제거하다","example":"The kidneys eliminate wastes from the body.","exampleKor":"신장은 신체 노폐물을 제거한다."},{"word":"easily","pos":"adv.","meaning":"쉽게","example":"Doctors easily removed the patient's appendix using advanced equipment.","exampleKor":"의사들은 첨단 장비를 사용해 환자의 맹장을 쉽게 제거했다."},{"word":"dental","pos":"adj.","meaning":"치과의","example":"It is important to receive dental checkups regularly.","exampleKor":"정기적으로 치과 검진을 받는 것은 중요하다."},{"word":"dietary","pos":"adj./n.","meaning":"식이 요법의, 규정식의; 규정식, (식사의) 규정량","example":"The Bureau of Health has issued a set of dietary guidelines for optimal nutrition.","exampleKor":"보건국은 최적의 영양을 위한 식단 지침을 발표했다."},{"word":"related","pos":"adj.","meaning":"관련된","example":"Illnesses with related symptoms can be a challenge to diagnose properly.","exampleKor":"관련 증상을 수반하는 질환들은 제대로 진단하는 것이 어려울 수 있다."},{"word":"transmit","pos":"v.","meaning":"전염시키다","example":"The flu virus is transmitted through the air.","exampleKor":"독감 바이러스는 공기를 통해 전염된다."},{"word":"periodically","pos":"adv.","meaning":"주기적으로","example":"Free health checkups for all staff members are offered periodically.","exampleKor":"모든 직원들을 위한 무료 건강 진단이 주기적으로 제공된다."},{"word":"reaction","pos":"n.","meaning":"반응","example":"Some foods can cause allergic reactions in children.","exampleKor":"일부 음식은 아이들에게 알레르기 반응을 유발할 수 있다."},{"word":"simple","pos":"adj.","meaning":"단순한","example":"A number of simple remedies are available for insomnia.","exampleKor":"불면증에는 많은 단순한 치료법들이 이용 가능하다."},{"word":"coverage","pos":"n.","meaning":"(보험의) 보상 범위; (신문 등의) 보도, 취재 범위","example":"Employees may extend their insurance coverage to spouses.","exampleKor":"직원들은 보험 보상 범위를 배우자로까지 넓힐 수 있다."},{"word":"exposure","pos":"n.","meaning":"노출","example":"Prolonged exposure to sunlight can cause skin cancer.","exampleKor":"햇빛에 대한 장기적인 노출은 피부암을 유발할 수 있다."},{"word":"pharmaceutical","pos":"adj.","meaning":"제약의, 약학의","example":"The pharmaceutical company markets children's dietary supplements.","exampleKor":"그 제약 회사는 아동용 보조 식품을 판매한다."},{"word":"premium","pos":"n.","meaning":"보험료","example":"Monthly medical insurance premiums will rise next year.","exampleKor":"내년에 월 의료 보험료가 상승할 것이다."},{"word":"relieve","pos":"v.","meaning":"완화시키다","example":"AlphaCough effectively relieves the symptoms of winter colds.","exampleKor":"AlphaCough는 겨울철 감기 증상을 효과적으로 완화시켜 준다."},{"word":"combination","pos":"n.","meaning":"결합, 연합","example":"Vitamin supplements are used in combination with other preventative measures.","exampleKor":"비타민 보충제는 다른 예방책들과 결합하여 사용된다."},{"word":"conscious","pos":"adj.","meaning":"알고 있는, 자각하고 있는","example":"People taking medication need to be conscious of the risks.","exampleKor":"약을 복용하는 사람들은 위험성에 대해 알고 있을 필요가 있다."},{"word":"deprivation","pos":"n.","meaning":"박탈, 상실","example":"Sleep deprivation weakens the immune system.","exampleKor":"수면 박탈은 면역 체계를 약화시킨다."},{"word":"health","pos":"n.","meaning":"건강; (사회·기관의) 번영, 안녕","example":"To maintain good health, physicians recommend an active lifestyle.","exampleKor":"건강을 유지하기 위해, 의사들은 활동적인 생활 방식을 추천한다."},{"word":"induce","pos":"v.","meaning":"유발하다","example":"Users were warned that the medication may induce drowsiness.","exampleKor":"소비자들은 약품이 졸림을 유발할 수 있다는 것에 대해 주의를 받았다."},{"word":"insurance","pos":"n.","meaning":"보험","example":"Employees are eligible for dental insurance coverage.","exampleKor":"직원들은 치과 보험 적용을 받을 수 있다."},{"word":"nutrition","pos":"n.","meaning":"영양","example":"Balanced nutrition is essential for growing children.","exampleKor":"균형 잡힌 영양은 성장기의 아이들에게 필수적이다."},{"word":"prevention","pos":"n.","meaning":"예방","example":"Proper diet is necessary for the prevention of illness.","exampleKor":"질병 예방을 위해 제대로 된 식습관이 필요하다."},{"word":"susceptible","pos":"adj.","meaning":"~에 감염되기 쉬운, 영향 받기 쉬운","example":"A weakened immune system makes one susceptible to colds.","exampleKor":"약화된 면역 체계는 감기에 걸리기 쉽게 만든다."},{"word":"uncomfortably","pos":"adv.","meaning":"불쾌하게, 불편하게","example":"After Tom turned on the heater, the room became uncomfortably hot.","exampleKor":"Tom이 난로를 켠 후, 방은 불쾌하게 더워졌다."}]}];
